) as v(name,mg,sm,eq,et,ins,img)
where not exists (select 1 from exercises e where lower(e.name)=lower(v.name));

insert into exercises (name,muscle_group,secondary_muscles,equipment,exercise_type,instructions,image_url,is_custom,user_id)
select v.name,v.mg::muscle_group,v.sm::muscle_group[],v.eq::equipment_type,v.et::exercise_type,v.ins::text[],v.img,false,null
from (values
($x$Catch and Overhead Throw$x$,'back','{core,chest,shoulders}','other','strength',ARRAY[$x$Begin standing while facing a wall or a partner.$x$,$x$Using both hands, position the ball behind your head, stretching as much as possible, and forcefully throw the ball forward.$x$,$x$Ensure that you follow your throw through, being prepared to receive your rebound from your throw. If you are throwing against the wall, make sure that you stand close enough to the wall to receive the rebound, and aim a little higher than you would with a partner.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Catch_and_Overhead_Throw/0.jpg$x$),
($x$Chain Handle Extension$x$,'triceps','{}','other','strength',ARRAY[$x$You will need two cable handle attachments and a flat bench, as well as chains, for this exercise. Clip the middle of the chains to the handles, and position yourself on the flat bench. Your elbows should be pointing straight up.$x$,$x$Begin by extending through the elbow, keeping your upper arm still, with your wrists pronated.$x$,$x$Pause at the lockout, and reverse the motion to return to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Chain_Handle_Extension/0.jpg$x$),
($x$Chain Press$x$,'chest','{shoulders,triceps}','other','strength',ARRAY[$x$Begin by connecting the chains to the cable handle attachments. Position yourself on the flat bench in the same position as for a dumbbell press. Your wrists should be pronated and arms perpendicular to the floor. This will be your starting position.$x$,$x$Lower the chains by flexing the elbows, unloading some of the chain onto the floor.$x$,$x$Continue until your elbow forms a 90 degree angle, and then reverse the motion by extending through the elbow to lockout.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Chain_Press/0.jpg$x$),
($x$Chair Squat$x$,'quadriceps','{calves,glutes,hamstrings}','machine','strength',ARRAY[$x$To begin, first set the bar to a position that best matches your height. Once the bar is loaded, step under it and position it across the back of your shoulders.$x$,$x$Take the bar with your hands facing forward, unlock it and lift it off the rack by extending your legs.$x$,$x$Move your feet forward about 18 inches in front of the bar. Position your legs using a shoulder width stance with the toes slightly pointed out. Look forward at all times and maintain a neutral or slightly arched spine. This will be your starting position.$x$,$x$Slowly lower the bar by bending the knees as you maintain a straight posture with the head up. Continue down until the angle between the upper and lower leg breaks 90 degrees.$x$,$x$Begin to raise the bar as you exhale by pushing the floor with the heels of your feet, extending the knees and returning to the starting position.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Chair_Squat/0.jpg$x$),
($x$Chest Push from 3 point stance$x$,'chest','{core,shoulders,triceps}','other','strength',ARRAY[$x$Begin in a three point stance, squatted down with your back flat and one hand on the ground. Place the medicine ball directly in front of you.$x$,$x$To begin, take your first step as you pull the ball to your chest, positioning both hands to prepare for the throw.$x$,$x$As you execute the second step, explosively release the ball forward as hard as possible.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Chest_Push_from_3_point_stance/0.jpg$x$),
($x$Chest Push with Run Release$x$,'chest','{core,shoulders,triceps}','other','strength',ARRAY[$x$Begin in an athletic stance with the knees bent, hips back, and back flat. Hold the medicine ball near your legs. This will be your starting position.$x$,$x$While taking your first step draw the medicine ball into your chest.$x$,$x$As you take the second step, explosively push the ball forward, immediately sprinting for 10 yards after the release. If you are really fast, you can catch your own pass!$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Chest_Push_with_Run_Release/0.jpg$x$),
($x$Circus Bell$x$,'shoulders','{forearms,glutes,hamstrings,back,triceps}','other','strength',ARRAY[$x$The circus bell is an oversized dumbbell with a thick handle. Begin with the dumbbell between your feet, and grip the handle with both hands.$x$,$x$Clean the dumbbell by extending through your hips and knees to deliver the implement to the desired shoulder, letting go with the extra hand.$x$,$x$Ensure that you get one of the dumbbell heads behind the shoulder to keep from being thrown off balance. To raise it overhead, dip by flexing the knees, and the drive upwards as you extend the dumbbell overhead, leaning slightly away from it as you do so.$x$,$x$Carefully guide the bell back to the floor, keeping it under control as much as possible. It is best to perform this event on a thick rubber mat to prevent damage to the floor.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Circus_Bell/0.jpg$x$),
($x$Clean Deadlift$x$,'hamstrings','{forearms,glutes,back,quadriceps}','barbell','olympic',ARRAY[$x$Begin standing with a barbell close to your shins. Your feet should be directly under your hips with your feet turned out slightly. Grip the bar with a double overhand grip or hook grip, about shoulder width apart. Squat down to the bar. Your spine should be in full extension, with a back angle that places your shoulders in front of the bar and your back as vertical as possible.$x$,$x$Begin by driving through the floor through the front of your heels. As the bar travels upward, maintain a constant back angle. Flare your knees out to the side to help keep them out of the bar's path.$x$,$x$After the bar crosses the knees, complete the lift by driving the hips into the bar until your hips and knees are extended.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Clean_Deadlift/0.jpg$x$),
($x$Clean Shrug$x$,'back','{forearms,shoulders}','barbell','olympic',ARRAY[$x$Begin with a shoulder width, double overhand or hook grip, with the bar hanging at the mid thigh position. Your back should be straight and inclined slightly forward.$x$,$x$Shrug your shoulders towards your ears. While this exercise can usually by loaded with heavier weight than a clean, avoid overloading to the point that the execution slows down.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Clean_Shrug/0.jpg$x$),
($x$Clean and Press$x$,'shoulders','{core,calves,glutes,hamstrings,back,quadriceps,triceps}','barbell','strength',ARRAY[$x$Assume a shoulder-width stance, with knees inside the arms. Now while keeping the back flat, bend at the knees and hips so that you can grab the bar with the arms fully extended and a pronated grip that is slightly wider than shoulder width. Point the elbows out to sides. The bar should be close to the shins. Position the shoulders over or slightly ahead of the bar. Establish a flat back posture. This will be your starting position.$x$,$x$Begin to pull the bar by extending the knees. Move your hips forward and raise the shoulders at the same rate while keeping the angle of the back constant; continue to lift the bar straight up while keeping it close to your body.$x$,$x$As the bar passes the knee, extend at the ankles, knees, and hips forcefully, similar to a jumping motion. As you do so, continue to guide the bar with your hands, shrugging your shoulders and using the momentum from your movement to pull the bar as high as possible. The bar should travel close to your body, and you should keep your elbows out.$x$,$x$At maximum elevation, your feet should clear the floor and you should start to pull yourself under the bar. The mechanics of this could change slightly, depending on the weight used. You should descend into a squatting position as you pull yourself under the bar.$x$,$x$As the bar hits terminal height, rotate your elbows around and under the bar. Rack the bar across the front of the shoulders while keeping the torso erect and flexing the hips and knees to absorb the weight of the bar.$x$,$x$Stand to full height, holding the bar in the clean position.$x$,$x$Without moving your feet, press the bar overhead as you exhale. Lower the bar under control .$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Clean_and_Press/0.jpg$x$),
($x$Clean from Blocks$x$,'quadriceps','{calves,glutes,hamstrings,shoulders,back}','barbell','olympic',ARRAY[$x$With a barbell on boxes or stands of the desired height, take an overhand or hook grip just outside the legs. Lower your hips with the weight focused on the heels, back straight, head facing forward, chest up, with your shoulders just in front of the bar. This will be your starting position.$x$,$x$Begin the first pull by driving through the heels, extending your knees. Your back angle should stay the same, and your arms should remain straight with the elbows pointed out.$x$,$x$As full extension is achieved, transition into the receiving position by aggressively shrugging and flexing the arms with the elbows up and out. Aggressively pull yourself down, rotating your elbows under the bar as you do so. Receive the bar in a front squat position, the depth of which is dependent upon the height of the bar at the end of the third pull. The bar should be racked onto the protracted shoulders, lightly touching the throat with the hands relaxed. Continue to descend to the bottom squat position, which will help in the recovery.$x$,$x$Immediately recover by driving through the heels, keeping the torso upright and elbows up. Continue until you have risen to a standing position. Return the weight to the boxes for the next rep.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Clean_from_Blocks/0.jpg$x$),
($x$Clock Push-Up$x$,'chest','{shoulders,triceps}','bodyweight','bodyweight',ARRAY[$x$Move into a prone position on the floor, supporting your weight on your hands and toes.$x$,$x$Your arms should be fully extended with the hands around shoulder width. Keep your body straight throughout the movement. This will be your starting position.$x$,$x$Descend by flexing at the elbow, lowering your chest toward the ground.$x$,$x$At the bottom, reverse the motion by pushing yourself up through elbow extension as quickly as possible until you are air borne. Aim to "jump" 12-18 inches to one side.$x$,$x$As you accelerate up, move your outside foot away from your direction of travel. Leaving the ground, shift your body about 30 degrees for the next repetition.$x$,$x$Return to the starting position and repeat the exercise, working all the way around until you are back where you started.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Clock_Push-Up/0.jpg$x$),
($x$Close-Grip Push-Up off of a Dumbbell$x$,'triceps','{core,chest,shoulders}','bodyweight','bodyweight',ARRAY[$x$Lie on the floor and place your hands on an upright dumbbell. Supporting your weight on your toes and hands, keep your torso rigid and your elbows in with your arms straight. This will be your starting position.$x$,$x$Lower your body, allowing the elbows to flex while you inhale. Keep your body straight, not allowing your hips to rise or sag.$x$,$x$Press yourself back up to the starting position by extending the elbows. Breathe out as you perform this step.$x$,$x$After a pause at the contracted position, repeat the movement for the prescribed amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Close-Grip_Push-Up_off_of_a_Dumbbell/0.jpg$x$),
($x$Cocoons$x$,'core','{}','bodyweight','bodyweight',ARRAY[$x$Begin by lying on your back on the ground. Your legs should be straight and your arms extended behind your head. This will be your starting position.$x$,$x$To perform the movement, tuck the knees toward your chest, rotating your pelvis to lift your glutes from the floor. As you do so, flex the spine, bringing your arms back over your head to perform a simultaneous crunch motion.$x$,$x$After a brief pause, return to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Cocoons/0.jpg$x$),
($x$Conan's Wheel$x$,'quadriceps','{core,biceps,calves,forearms,back,shoulders}','other','strength',ARRAY[$x$With the weight loaded, take a zurcher hold on the end of the implement. Place the bar in the crook of the elbow and hold onto your wrist. Try to keep the weight off of the forearms.$x$,$x$Begin by lifting the weight from the ground. Keep a tight, upright posture as you being to walk, taking short, fast steps. Look up and away as you turn in a circle. Do not hold your breath during the event. Continue walking until you complete one or more complete turns.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Conans_Wheel/0.jpg$x$),
($x$Cross-Body Crunch$x$,'core','{}','bodyweight','bodyweight',ARRAY[$x$Lie flat on your back and bend your knees about 60 degrees.$x$,$x$Keep your feet flat on the floor and place your hands loosely behind your head. This will be your starting position.$x$,$x$Now curl up and bring your right elbow and shoulder across your body while bring your left knee in toward your left shoulder at the same time. Reach with your elbow and try to touch your knee. Exhale as you perform this movement. Tip: Try to bring your shoulder up towards your knee rather than just your elbow and remember that the key is to contract the abs as you perform the movement; not just to move the elbow.$x$,$x$Now go back down to the starting position as you inhale and repeat with the left elbow and the right knee.$x$,$x$Continue alternating in this manner until all prescribed repetitions are done.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Cross-Body_Crunch/0.jpg$x$),
($x$Crucifix$x$,'shoulders','{forearms}','other','strength',ARRAY[$x$In the crucifix, you statically hold weights out to the side for time. While the event can be practiced using dumbbells, it is best to practice with one of the various implements used, such as axes and hammers, as it feels different.$x$,$x$Begin standing, and raise your arms out to the side holding the implements. Your arms should be parallel to the ground. In competition, judges or sensors are used to let you know when you break parallel. Hold for as long as you can. Typically, the weights should be heavy enough that you fail in 30-60 seconds.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Crucifix/0.jpg$x$),
($x$Crunches$x$,'core','{}','bodyweight','bodyweight',ARRAY[$x$Lie flat on your back with your feet flat on the ground, or resting on a bench with your knees bent at a 90 degree angle. If you are resting your feet on a bench, place them three to four inches apart and point your toes inward so they touch.$x$,$x$Now place your hands lightly on either side of your head keeping your elbows in. Tip: Don't lock your fingers behind your head.$x$,$x$While pushing the small of your back down in the floor to better isolate your abdominal muscles, begin to roll your shoulders off the floor.$x$,$x$Continue to push down as hard as you can with your lower back as you contract your abdominals and exhale. Your shoulders should come up off the floor only about four inches, and your lower back should remain on the floor. At the top of the movement, contract your abdominals hard and keep the contraction for a second. Tip: Focus on slow, controlled movement - don't cheat yourself by using momentum.$x$,$x$After the one second contraction, begin to come down slowly again to the starting position as you inhale.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Crunches/0.jpg$x$),
($x$Cuban Press$x$,'shoulders','{back}','dumbbell','strength',ARRAY[$x$Take a dumbbell in each hand with a pronated grip in a standing position. Raise your upper arms so that they are parallel to the floor, allowing your lower arms to hang in the "scarecrow" position. This will be your starting position.$x$,$x$To initiate the movement, externally rotate the shoulders to move the upper arm 180 degrees. Keep the upper arms in place, rotating the upper arms until the wrists are directly above the elbows, the forearms perpendicular to the floor.$x$,$x$Now press the dumbbells by extending at the elbows, straightening your arms overhead.$x$,$x$Return to the starting position as you breathe in by reversing the steps.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Cuban_Press/0.jpg$x$),
($x$Decline Close-Grip Bench To Skull Crusher$x$,'triceps','{chest,shoulders}','barbell','strength',ARRAY[$x$Secure your legs at the end of the decline bench and slowly lay down on the bench.$x$,$x$Using a close grip (a grip that is slightly less than shoulder width), lift the bar from the rack and hold it straight over you with your arms locked and elbows in. The arms should be perpendicular to the floor. This will be your starting position. Tip: In order to protect your rotator cuff, it is best if you have a spotter help you lift the barbell off the rack.$x$,$x$Now lower the bar down to your lower chest as you breathe in. Keep the elbows in as you perform this movement.$x$,$x$Using the triceps to push the bar back up, press it back to the starting position as you exhale.$x$,$x$As you breathe in and you keep the upper arms stationary, bring the bar down slowly by moving your forearms in a semicircular motion towards you until you feel the bar slightly touch your forehead. Breathe in as you perform this portion of the movement.$x$,$x$Lift the bar back to the starting position by contracting the triceps and exhaling.$x$,$x$Repeat steps 3-6 until the recommended amount of repetitions is performed.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Decline_Close-Grip_Bench_To_Skull_Crusher/0.jpg$x$),
($x$Decline Dumbbell Triceps Extension$x$,'triceps','{}','dumbbell','strength',ARRAY[$x$Secure your legs at the end of the decline bench and lie down with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.$x$,$x$Once you are laying down, move the dumbbells in front of you at shoulder width. The palms of the hands should be facing each other and the arms should be perpendicular to the floor and fully extended. This will be your starting position.$x$,$x$As you breathe in and you keep the upper arms stationary (and elbows in), bring the dumbbells down slowly by moving your forearms in a semicircular motion towards you until your thumbs are next to your ears. Breathe in as you perform this portion of the movement.$x$,$x$Lift the dumbbells back to the starting position by contracting the triceps and exhaling.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Decline_Dumbbell_Triceps_Extension/0.jpg$x$),
($x$Decline Oblique Crunch$x$,'core','{}','bodyweight','bodyweight',ARRAY[$x$Secure your legs at the end of the decline bench and slowly lay down on the bench.$x$,$x$Raise your upper body off the bench until your torso is about 35-45 degrees if measured from the floor.$x$,$x$Put one hand beside your head and the other on your thigh. This will be your starting position.$x$,$x$Raise your upper body slowly from the starting position while turning your torso to the left. Continue crunching up as you exhale until your right elbow touches your left knee. Hold this contracted position for a second. Tip: Focus on keeping your abs tight and keeping the movement slow and controlled.$x$,$x$Lower your body back down slowly to the starting position as you inhale.$x$,$x$After completing one set on the right for the recommended amount of repetitions, switch to your left side. Tip: Focus on really twisting your torso and feeling the contraction when you are in the up position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Decline_Oblique_Crunch/0.jpg$x$),
($x$Decline Smith Press$x$,'chest','{shoulders,triceps}','machine','strength',ARRAY[$x$Place a decline bench underneath the Smith machine. Now place the barbell at a height that you can reach when lying down and your arms are almost fully extended. Using a pronated grip that is wider than shoulder width, unlock the bar from the rack and hold it straight over you with your arms extended. This will be your starting position.$x$,$x$As you inhale, lower the bar under control by allowing the elbows to flex, lightly contacting the torso.$x$,$x$After a brief pause, bring the bar back to the starting position by extending the elbows, exhaling as you do so.$x$,$x$Repeat the movement for the prescribed amount of repetitions.$x$,$x$When the set is complete, lock the bar back in the rack.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Decline_Smith_Press/0.jpg$x$),
($x$Depth Jump Leap$x$,'quadriceps','{glutes,calves,hamstrings}','other','strength',ARRAY[$x$For this drill you will need two boxes or benches, one 12 to 16 inches high and the other 22 to 26 inches high.$x$,$x$Stand on one of the two boxes with arms at the sides; feet should be together and slightly off the edge as in the depth jump. Place the other box approximately two or three feet in front of and facing the performer.$x$,$x$Begin by dropping off the initial box, landing and simultaneously taking off with both feet.$x$,$x$Rebound by driving upward and outward as intensely as possible, using the arms and full extension of the body to jump onto the higher box. Again, allow the legs to absorb the impact.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Depth_Jump_Leap/0.jpg$x$),
($x$Double Kettlebell Alternating Hang Clean$x$,'hamstrings','{biceps,calves,forearms,glutes,back,quadriceps}','kettlebell','strength',ARRAY[$x$Place two kettlebells between your feet. To get in the starting position, push your butt back and look straight ahead.$x$,$x$Clean one kettlebell to your shoulder and hold on to the other kettlebell.$x$,$x$With a fluid motion, lower the top kettlebell while driving the bottom kettlebell up.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Double_Kettlebell_Alternating_Hang_Clean/0.jpg$x$),
($x$Double Kettlebell Jerk$x$,'shoulders','{calves,quadriceps,triceps}','kettlebell','strength',ARRAY[$x$Hold a kettlebell by the handle in each hand.$x$,$x$Clean the kettlebells to your shoulders by extending through the legs and hips as you pull the kettlebells towards your shoulders. Rotate your wrists as you do so, so that the palms face forward. This will be your starting position.$x$,$x$Dip your body by bending the knees, keeping your torso upright.$x$,$x$Immediately reverse direction, driving through the heels, in essence jumping to create momentum.$x$,$x$As you do so, press the kettlebells overhead to lockout by extending the arms, using your body's momentum to move the weights.$x$,$x$Return your feet to the ground in a split fashion, with one foot forward and one foot back.$x$,$x$Keeping the weights overhead, return to a standing position, bringing your feet together. Lower the weights to perform the next repetition.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Double_Kettlebell_Jerk/0.jpg$x$),
($x$Double Kettlebell Push Press$x$,'shoulders','{calves,quadriceps,triceps}','kettlebell','strength',ARRAY[$x$Clean two kettlebells to your shoulders.$x$,$x$Squat down a few inches and reverse the motion rapidly. Use the momentum from the legs to drive the kettlebells overhead.$x$,$x$Once the kettlebells are locked out, lower the kettlebells to your shoulders and repeat.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Double_Kettlebell_Push_Press/0.jpg$x$),
($x$Double Kettlebell Snatch$x$,'shoulders','{glutes,hamstrings,quadriceps}','kettlebell','strength',ARRAY[$x$Place two kettlebells behind your feet. Bend your knees and sit back to pick up the kettlebells.$x$,$x$Swing the kettlebells between your legs forcefully and reverse the direction.$x$,$x$Drive through with your hips and lock the ketttlebells overhead in one uninterrupted motion.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Double_Kettlebell_Snatch/0.jpg$x$),
($x$Double Kettlebell Windmill$x$,'core','{glutes,hamstrings,shoulders,triceps}','kettlebell','strength',ARRAY[$x$Place a kettlebell in front of your front foot and clean and press a kettlebell overhead with your opposite arm. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulders. Rotate your wrist as you do so, so that the palm faces forward.$x$,$x$Keeping the kettlebell locked out at all times, push your butt out in the direction of the locked out kettlebell. Turn your feet out at a forty-five degree angle from the arm with the locked out kettlebell.$x$,$x$Bending at the hip to one side, sticking your butt out, slowly lean until you can retrieve the kettlebell from the floor. Keep your eyes on the kettlebell that you hold over your head at all times.$x$,$x$Pause for a second after retrieving the kettlebell from the ground and reverse the motion back to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Double_Kettlebell_Windmill/0.jpg$x$),
($x$Double Leg Butt Kick$x$,'quadriceps','{glutes,calves,hamstrings}','bodyweight','bodyweight',ARRAY[$x$Begin standing with your knees slightly bent.$x$,$x$Quickly squat a short distance, flexing the hips and knees, and immediately extend to jump for maximum vertical height.$x$,$x$As you go up, tuck your heels by flexing the knees, attempting to touch the buttocks.$x$,$x$Finish the motion by landing with the knees only partially bent, using your legs to absorb the impact.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Double_Leg_Butt_Kick/0.jpg$x$),
($x$Downward Facing Balance$x$,'glutes','{core,hamstrings}','other','strength',ARRAY[$x$Lie facedown on top of an exercise ball.$x$,$x$While resting on your stomach on the ball, walk your hands forward along the floor and lift your legs, extending your elbows and knees.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Downward_Facing_Balance/0.jpg$x$),
($x$Drag Curl$x$,'biceps','{forearms}','barbell','strength',ARRAY[$x$Grab a barbell with a supinated grip (palms facing forward) and get your elbows close to your torso and back. This will be your starting position.$x$,$x$As you exhale, curl the bar up while keeping the elbows to the back as you "Drag" the bar up by keeping it in contact with your torso. Tip: As you can see, you will not be keeping the elbows pinned to your sides, but instead you will be bringing them back. Also, do not lift your shoulders.$x$,$x$Slowly go back to the starting position as you keep the bar in contact with the torso at all times.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Drag_Curl/0.jpg$x$),
($x$Drop Push$x$,'chest','{shoulders,triceps}','other','strength',ARRAY[$x$Position low boxes or other platforms 2-3 feet apart.$x$,$x$Move to a pushup position between them, supporting yourself by placing your hands on the boxes.$x$,$x$With good posture, drop from the platforms by pressing up and moving your hands to shoulder width, cushioning your landing by absorbing the impact through the arm.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Drop_Push/0.jpg$x$),
($x$Dumbbell Alternate Bicep Curl$x$,'biceps','{forearms}','dumbbell','strength',ARRAY[$x$Stand (torso upright) with a dumbbell in each hand held at arms length. The elbows should be close to the torso and the palms of your hand should be facing your thighs.$x$,$x$While holding the upper arm stationary, curl the right weight as you rotate the palm of the hands until they are facing forward. At this point continue contracting the biceps as you breathe out until your biceps is fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps. Tip: Only the forearms should move.$x$,$x$Slowly begin to bring the dumbbell back to the starting position as your breathe in. Tip: Remember to twist the palms back to the starting position (facing your thighs) as you come down.$x$,$x$Repeat the movement with the left hand. This equals one repetition.$x$,$x$Continue alternating in this manner for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Dumbbell_Alternate_Bicep_Curl/0.jpg$x$),
($x$Dumbbell Lying One-Arm Rear Lateral Raise$x$,'shoulders','{back}','dumbbell','strength',ARRAY[$x$While holding a dumbbell in one hand, lay with your chest down on a slightly inclined (around 15 degrees when measured from the floor) adjustable bench. The other hand can be used to hold to the leg of the bench for stability.$x$,$x$Position the palm of the hand that is holding the dumbbell in a neutral manner (palms facing your torso) as you keep the arm extended with the elbow slightly bent. This will be your starting position.$x$,$x$Now raise the arm with the dumbbell to the side until your elbow is at shoulder height and your arm is roughly parallel to the floor as you exhale. Tip: Maintain your arm perpendicular to the torso while keeping your arm extended throughout the movement. Also, keep the contraction at the top for a second.$x$,$x$Slowly lower the dumbbell to the starting position as you inhale.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Dumbbell_Lying_One-Arm_Rear_Lateral_Raise/0.jpg$x$),
($x$Dumbbell Lying Pronation$x$,'forearms','{}','dumbbell','strength',ARRAY[$x$Lie on a flat bench face down with one arm holding a dumbbell and the other hand on top of the bench folded so that you can rest your head on it.$x$,$x$Bend the elbows of the arm holding the dumbbell so that it creates a 90-degree angle between the upper arm and the forearm.$x$,$x$Now raise the upper arm so that the forearm is perpendicular to the floor and the upper arm is perpendicular to your torso. Tip: The upper arm should be parallel to the floor and also creating a 90-degree angle with your torso. This will be your starting position.$x$,$x$As you breathe out, externally rotate your forearm so that the dumbbell is lifted forward as you maintain the 90 degree angle bend between the upper arms and the forearm. You will continue this external rotation until the forearm is parallel to the floor. At this point you will hold the contraction for a second.$x$,$x$As you breathe in, slowly go back to the starting position.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Dumbbell_Lying_Pronation/0.jpg$x$),
($x$Dumbbell Lying Rear Lateral Raise$x$,'shoulders','{}','dumbbell','strength',ARRAY[$x$While holding a dumbbell in each hand, lay with your chest down on a slightly inclined (around 15 degrees when measured from the floor) adjustable bench.$x$,$x$Position the palms of the hands in a neutral manner (palms facing your torso) as you keep the arms extended with the elbows slightly bent. This will be your starting position.$x$,$x$Now raise the arms to the side until your elbows are at shoulder height and your arms are roughly parallel to the floor as you exhale. Tip: Maintain your arms perpendicular to the torso while keeping them extended throughout the movement. Also, keep the contraction at the top for a second.$x$,$x$Slowly lower the dumbbells to the starting position as you inhale.$x$,$x$Repeat for the recommended amount of repetitions and then switch to the other arm.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Dumbbell_Lying_Rear_Lateral_Raise/0.jpg$x$),
($x$Dumbbell Lying Supination$x$,'forearms','{}','dumbbell','strength',ARRAY[$x$Lie sideways on a flat bench with one arm holding a dumbbell and the other hand on top of the bench folded so that you can rest your head on it.$x$,$x$Bend the elbows of the arm holding the dumbbell so that it creates a 90-degree angle between the upper arm and the forearm.$x$,$x$Now raise the upper arm so that the forearm is parallel to the floor and perpendicular to your torso (Tip: So the forearm will be directly in front of you). The upper arm will be stationary by your torso and should be parallel to the floor (aligned with your torso at all times). This will be your starting position.$x$,$x$As you breathe out, externally rotate your forearm so that the dumbbell is lifted up in a semicircle motion as you maintain the 90 degree angle bend between the upper arms and the forearm. You will continue this external rotation until the forearm is perpendicular to the floor and the torso pointing towards the ceiling. At this point you will hold the contraction for a second.$x$,$x$As you breathe in, slowly go back to the starting position.$x$,$x$Repeat for the recommended amount of repetitions and then switch to the other arm.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Dumbbell_Lying_Supination/0.jpg$x$),
($x$Dumbbell One-Arm Shoulder Press$x$,'shoulders','{triceps}','dumbbell','strength',ARRAY[$x$Grab a dumbbell and either sit on a military press bench or a utility bench that has a back support on it as you place the dumbbells upright on top of your thighs or stand up straight.$x$,$x$Clean the dumbbell up to bring it to shoulder height. The other hand can be kept fully extended to the side, by the waist or grabbing a fixed surface.$x$,$x$Rotate the wrist so that the palm of your hand is facing forward. This is your starting position.$x$,$x$As you exhale, push the dumbbell up until your arm is fully extended.$x$,$x$After a second pause, slowly come down back to the starting position as you inhale.$x$,$x$Repeat for the recommended amount of repetitions and then switch arms.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Dumbbell_One-Arm_Shoulder_Press/0.jpg$x$),
($x$Dumbbell Prone Incline Curl$x$,'biceps','{}','dumbbell','strength',ARRAY[$x$Grab a dumbbell on each hand and lie face down on an incline bench with your shoulders near top of the incline. Your knees can rest on the seat or your legs can be straddled to the sides (my preferred way).$x$,$x$Let your arms extend and hang naturally in front of you so that they are perpendicular to the floor.$x$,$x$Now keep your elbows in by your side and face the palms forward. This will be your starting position.$x$,$x$Raise the dumbbells by contracting the biceps until your arms are fully flexed. Exhale as you perform this portion of the movement and ensure that only the forearms move. The upper arms should remain stationary at all times.$x$,$x$Lower the dumbbells until your arms are fully extended.$x$,$x$Repeat for the recommended amount of times.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Dumbbell_Prone_Incline_Curl/0.jpg$x$),
($x$Dumbbell Rear Lunge$x$,'quadriceps','{calves,glutes,hamstrings}','dumbbell','strength',ARRAY[$x$Stand with your torso upright holding two dumbbells in your hands by your sides. This will be your starting position.$x$,$x$Step backward with your right leg around two feet or so from the left foot and lower your upper body down, while keeping the torso upright and maintaining balance. Inhale as you go down. Tip: As in the other exercises, do not allow your knee to go forward beyond your toes as you come down, as this will put undue stress on the knee joint. Make sure that you keep your front shin perpendicular to the ground. Keep the torso upright during the lunge; flexible hip flexors are important. A long lunge emphasizes the Gluteus Maximus; a short lunge emphasizes Quadriceps.$x$,$x$Push up and go back to the starting position as you exhale. Tip: Use the ball of your feet to push in order to accentuate the quadriceps. To focus on the glutes, press with your heels.$x$,$x$Now repeat with the opposite leg.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Dumbbell_Rear_Lunge/0.jpg$x$),
($x$Dumbbell Scaption$x$,'shoulders','{back}','dumbbell','strength',ARRAY[$x$This corrective exercise strengthens the muscles that stabilize your shoulder blade. Hold a light weight in each hand, hanging at your sides. Your thumbs should pointing up.$x$,$x$Begin the movement raising your arms out in front of you, about 30 degrees off center. Your arms should be fully extended as you perform the movement.$x$,$x$Continue until your arms are parallel to the ground, and then return to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Dumbbell_Scaption/0.jpg$x$),
($x$Dumbbell Seated One-Leg Calf Raise$x$,'calves','{}','dumbbell','strength',ARRAY[$x$Place a block on the floor about 12 inches from a flat bench.$x$,$x$Sit on a flat bench and place a dumbbell on your upper left thigh about 3 inches above your knee.$x$,$x$Now place the ball of your left foot on the block. This will be your starting position.$x$,$x$Raise your toes up as high as possible as you exhale and you contract your calf muscle. Hold the contraction for a second.$x$,$x$Slowly return to the starting position, stretching as far down as possible.$x$,$x$Repeat for your prescribed number of repetitions and then repeat with the right leg.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Dumbbell_Seated_One-Leg_Calf_Raise/0.jpg$x$),
($x$Dumbbell Tricep Extension -Pronated Grip$x$,'triceps','{}','dumbbell','strength',ARRAY[$x$Lie down on a flat bench holding two dumbbells directly above your shoulders. Your arms should be fully extended and form a 90 degree angle from your torso and the floor.$x$,$x$The palms of your hands should be facing forward, and your elbows should be tucked in. This will be your starting position.$x$,$x$Now, inhale and slowly lower the dumbbells until they are near your ears. Be sure to keep your upper arms stationary and your elbows tucked in.$x$,$x$Then, exhale and use your triceps to return the weight to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Dumbbell_Tricep_Extension_-Pronated_Grip/0.jpg$x$),
($x$Elbow to Knee$x$,'core','{}','bodyweight','bodyweight',ARRAY[$x$Lie on the floor, crossing your right leg across your bent left knee. Clasp your hands behind your head, beginning with your shoulder blades on the ground. This will be your starting position.$x$,$x$Perform the motion by flexing the spine and rotating your torso to bring the left elbow to the right knee.$x$,$x$Return to the starting position and repeat the movement for the desired number of repetitions before switching sides.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Elbow_to_Knee/0.jpg$x$),
($x$Elevated Back Lunge$x$,'quadriceps','{glutes,hamstrings}','barbell','strength',ARRAY[$x$Position a bar onto a rack at shoulder height loaded to an appropriate weight. Place a short, raised platform behind you.$x$,$x$Rack the bar onto your upper back, keeping your back arched and tight. Step onto your raised platform with both feet. This will be your starting position.$x$,$x$Begin by stepping backwards with one leg. Descend by flexing your hips and knees until your knee touches the floor.$x$,$x$Pause, and extend through the hips and knees to rise up, returning all the way to the starting position before alternating.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Elevated_Back_Lunge/0.jpg$x$),
($x$Elevated Cable Rows$x$,'back','{}','cable','strength',ARRAY[$x$Get a platform of some sort (it can be an aerobics or calf raise platform) that is around 4-6 inches in height.$x$,$x$Place it on the seat of the cable row machine.$x$,$x$Sit down on the machine and place your feet on the front platform or crossbar provided making sure that your knees are slightly bent and not locked.$x$,$x$Lean over as you keep the natural alignment of your back and grab the V-bar handles.$x$,$x$With your arms extended pull back until your torso is at a 90-degree angle from your legs. Your back should be slightly arched and your chest should be sticking out. You should be feeling a nice stretch on your lats as you hold the bar in front of you. This is the starting position of the exercise.$x$,$x$Keeping the torso stationary, pull the handles back towards your torso while keeping the arms close to it until you touch the abdominals. Breathe out as you perform that movement. At that point you should be squeezing your back muscles hard. Hold that contraction for a second and slowly go back to the original position while breathing in.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Elevated_Cable_Rows/0.jpg$x$),
($x$Elliptical Trainer$x$,'quadriceps','{calves,glutes,hamstrings}','machine','cardio',ARRAY[$x$To begin, step onto the elliptical and select the desired option from the menu. Most ellipticals have a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. Elevation can be adjusted to change the intensity of the workout.$x$,$x$The handles can be used to monitor your heart rate to help you stay at an appropriate intensity.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Elliptical_Trainer/0.jpg$x$),
($x$Exercise Ball Crunch$x$,'core','{}','other','strength',ARRAY[$x$Lie on an exercise ball with your lower back curvature pressed against the spherical surface of the ball. Your feet should be bent at the knee and pressed firmly against the floor. The upper torso should be hanging off the top of the ball. The arms should either be kept alongside the body or crossed on top of your chest as these positions avoid neck strains (as opposed to the hands behind the back of the head position).$x$,$x$Lower your torso into a stretch position keeping the neck stationary at all times. This will be your starting position.$x$,$x$With the hips stationary, flex the waist by contracting the abdominals and curl the shoulders and trunk upward until you feel a nice contraction on your abdominals. The arms should simply slide up the side of your legs if you have them at the side or just stay on top of your chest if you have them crossed. The lower back should always stay in contact with the ball. Exhale as you perform this movement and hold the contraction for a second.$x$,$x$As you inhale, go back to the starting position.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Exercise_Ball_Crunch/0.jpg$x$),
($x$Exercise Ball Pull-In$x$,'core','{}','other','strength',ARRAY[$x$Place an exercise ball nearby and lay on the floor in front of it with your hands on the floor shoulder width apart in a push-up position.$x$,$x$Now place your lower shins on top of an exercise ball. Tip: At this point your legs should be fully extended with the shins on top of the ball and the upper body should be in a push-up type of position being supported by your two extended arms in front of you. This will be your starting position.$x$,$x$While keeping your back completely straight and the upper body stationary, pull your knees in towards your chest as you exhale, allowing the ball to roll forward under your ankles. Squeeze your abs and hold that position for a second.$x$,$x$Now slowly straighten your legs, rolling the ball back to the starting position as you inhale.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Exercise_Ball_Pull-In/0.jpg$x$),
($x$Fast Skipping$x$,'quadriceps','{glutes,calves,hamstrings}','bodyweight','bodyweight',ARRAY[$x$Start in a relaxed position with one leg slightly forward. This will be your starting position.$x$,$x$Skip by executing a step-hop pattern of right-right-step to left-left-step, and so on, alternating back and forth.$x$,$x$Perform fast skips by maintaining close contact with the ground and reduce air time, moving as quickly as possible.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Fast_Skipping/0.jpg$x$),
($x$Finger Curls$x$,'forearms','{}','barbell','strength',ARRAY[$x$Hold a barbell with both hands and your palms facing up; hands spaced about shoulder width.$x$,$x$Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart. This will be your starting position.$x$,$x$Lower the bar as far as possible by extending the fingers. Allowing the bar to roll down the hands, catch the bar with the final joint in the fingers.$x$,$x$Now curl bar up as high as possible by closing your hands while exhaling. Hold the contraction at the top.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Finger_Curls/0.jpg$x$),
($x$Flat Bench Cable Flyes$x$,'chest','{}','cable','strength',ARRAY[$x$Position a flat bench between two low pulleys so that when you are laying on it, your chest will be lined up with the cable pulleys.$x$,$x$Lay flat on the bench and keep your feet on the ground.$x$,$x$Have someone hand you the handles on each hand. You will grab each single handle attachment with a palms up grip.$x$,$x$Extend your arms by your side with a slight bend on your elbows. Tip: You will keep this bend constant through the whole movement. Your arms should be parallel to the floor. This is your starting position.$x$,$x$Now start lifting the arms in a semi-circle motion directly in front of you by pulling the cables together until both hands meet at the top of the movement. Squeeze your chest as you perform this motion and breathe out during this movement. Also, hold the contraction for a second at the top. Tip: When performed correctly, at the top position of this movement, your arms should be perpendicular to your torso and the floor touching above your chest.$x$,$x$Slowly come back to the starting position.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Flat_Bench_Cable_Flyes/0.jpg$x$),
($x$Flat Bench Leg Pull-In$x$,'core','{}','bodyweight','bodyweight',ARRAY[$x$Lie on an exercise mat or a flat bench with your legs off the end.$x$,$x$Place your hands either under your glutes with your palms down or by the sides holding on to the bench (or with palms down by the side on an exercise mat). Also extend your legs straight out. This will be your starting position.$x$,$x$Bend your knees and pull your upper thighs into your midsection as you breathe out. Continue this movement until your knees are near your chest. Hold the contracted position for a second.$x$,$x$As you breathe in, slowly return to the starting position.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Flat_Bench_Leg_Pull-In/0.jpg$x$),
($x$Flat Bench Lying Leg Raise$x$,'core','{}','bodyweight','bodyweight',ARRAY[$x$Lie with your back flat on a bench and your legs extended in front of you off the end.$x$,$x$Place your hands either under your glutes with your palms down or by the sides holding on to the bench. This will be your starting position.$x$,$x$As you keep your legs extended, straight as possible with your knees slightly bent but locked raise your legs until they make a 90-degree angle with the floor. Exhale as you perform this portion of the movement and hold the contraction at the top for a second.$x$,$x$Now, as you inhale, slowly lower your legs back down to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Flat_Bench_Lying_Leg_Raise/0.jpg$x$),
($x$Floor Press with Chains$x$,'triceps','{chest,shoulders}','barbell','strength',ARRAY[$x$Adjust the j-hooks so they are at the appropriate height to rack the bar. For this exercise, drape the chains directly over the end of the bar, trying to keep the ends away from the plates.$x$,$x$Begin lying on the floor with your head near the end of a power rack. Keeping your shoulder blades pulled together, pull the bar off of the hooks.$x$,$x$Lower the bar towards the bottom of your chest or upper stomach, squeezing the bar and attempting to pull it apart as you do so. Ensure that you tuck your elbows throughout the movement. Lower the bar until your upper arm contacts the ground and pause, preventing any slamming or bouncing of the weight.$x$,$x$Press the bar back up as fast as you can, keeping the bar, your wrists, and elbows in line as you do so.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Floor_Press_with_Chains/0.jpg$x$),
($x$Forward Drag with Press$x$,'chest','{calves,glutes,hamstrings,quadriceps,shoulders,triceps}','other','strength',ARRAY[$x$Attach a dual handled chain or rope attachment to the sled. You should be facing away from the sled, holding a handle in each hand.$x$,$x$Begin the movement by moving forward for one step. Leaning forward, extend through the legs and hips to move, pausing with each step to extend through the elbows, pressing your hands forward. Step forward until you return to the start position prepared to press.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Forward_Drag_with_Press/0.jpg$x$),
($x$Frankenstein Squat$x$,'quadriceps','{core,calves,glutes,hamstrings}','barbell','olympic',ARRAY[$x$This drill teaches you the proper positioning of both the bar and your body during the clean and front squat.$x$,$x$Place the barbell on the front of the shoulders, releasing your grip and extending your arms out in front of you. The shoulders should be pushed forward to create a shelf, and the bar should be in contact with the throat. Ensure that you only move your shoulder blades forward; don't round the thoracic spine.$x$,$x$Squat by flexing the knees and hips, sitting in between your legs. Keep the torso upright, the arms up, and the shoulders forward, and the bar should stay in place. Go to the bottom of the squat, until your hamstrings contact your calves.$x$,$x$Return to the upright position by driving through the front of the heel and extending the knees and hips.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Frankenstein_Squat/0.jpg$x$),
($x$Freehand Jump Squat$x$,'quadriceps','{calves,glutes,hamstrings}','bodyweight','bodyweight',ARRAY[$x$Cross your arms over your chest.$x$,$x$With your head up and your back straight, position your feet at shoulder width.$x$,$x$Keeping your back straight and chest up, squat down as you inhale until your upper thighs are parallel, or lower, to the floor.$x$,$x$Now pressing mainly with the ball of your feet, jump straight up in the air as high as possible, using the thighs like springs. Exhale during this portion of the movement.$x$,$x$When you touch the floor again, immediately squat down and jump again.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Freehand_Jump_Squat/0.jpg$x$),
($x$Frog Sit-Ups$x$,'core','{}','bodyweight','bodyweight',ARRAY[$x$Lie with your back flat on the floor (or exercise mat) and your legs extended in front of you.$x$,$x$Now bend at the knees and place your outer thighs by the floor (or mat) as you make the soles of your feet touch each other.$x$,$x$Now try pushing both soles and bringing them up as near you as possible while you keep the outer thighs on the floor (or at least almost touching it). Tip: In this position your legs should create a diamond shape.$x$,$x$Now, cross your arms in front of you by touching the opposite shoulders. This will be your starting position.$x$,$x$As you exhale flatten your lower back to the floor while curling the torso upwards. Tip: This will be like performing the first 1/4 movement of a sit up. Hold at the top position for a second.$x$,$x$As you inhale, slowly lower back to the starting position.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Frog_Sit-Ups/0.jpg$x$),
($x$Front Barbell Squat To A Bench$x$,'quadriceps','{calves,glutes,hamstrings}','barbell','strength',ARRAY[$x$This exercise is best performed inside a squat rack for safety purposes. To begin, first set a flat bench behind you and set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, bring your arms up under the bar while keeping the elbows high and the upper arm slightly above parallel to the floor. Rest the bar on top of the deltoids and cross your arms while grasping the bar for total control.$x$,$x$Lift the bar off the rack by first pushing with your legs and at the same time straightening your torso.$x$,$x$Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. This will be your starting position. (Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances described in the foot positioning section).$x$,$x$Begin to slowly lower the bar by bending the knees as you maintain a straight posture with the head up. Continue down until you touch the bench with your glutes. Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.$x$,$x$Begin to raise the bar as you exhale by pushing the floor mainly with the heel of your foot as you straighten the legs again and go back to the starting position.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Front_Barbell_Squat_To_A_Bench/0.jpg$x$),
($x$Front Box Jump$x$,'hamstrings','{glutes,quadriceps,calves}','other','strength',ARRAY[$x$Begin with a box of an appropriate height 1-2 feet in front of you. Stand with your feet should width apart. This will be your starting position.$x$,$x$Perform a short squat in preparation for jumping, swinging your arms behind you.$x$,$x$Rebound out of this position, extending through the hips, knees, and ankles to jump as high as possible. Swing your arms forward and up.$x$,$x$Land on the box with the knees bent, absorbing the impact through the legs. You can jump from the box back to the ground, or preferably step down one leg at a time.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Front_Box_Jump/0.jpg$x$),
($x$Front Incline Dumbbell Raise$x$,'shoulders','{}','dumbbell','strength',ARRAY[$x$Sit down on an incline bench with the incline set anywhere between 30 to 60 degrees while holding a dumbbell on each hand. Tip: You can change the angle to hit the muscle a little differently each time.$x$,$x$Extend your arms straight in front of you and have your palms facing down with the dumbbells raised about 1 inch above your thighs. This will be your starting position.$x$,$x$Slowly raise the dumbbells straight up until they are slightly above your shoulders, while keeping your elbows locked. Squeeze at the top for a second and make sure you breathe out during this portion of the movement. Tip: Keep your head resting down against the bench and your legs on the floor at all times.$x$,$x$Lower the arms back to the starting position as you inhale.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Front_Incline_Dumbbell_Raise/0.jpg$x$),
($x$Front Raise And Pullover$x$,'chest','{back,shoulders,triceps}','barbell','strength',ARRAY[$x$Lie on a flat bench while holding a barbell using a palms down grip that is about 15 inches apart.$x$,$x$Place the bar on your upper thighs, extend your arms and lock them while keeping a slight bend on the elbows. This will be your starting position.$x$,$x$Now raise the weight using a semicircular motion and keeping your arms straight as you inhale. Continue the same movement until the bar is on the other side above your head . (Tip: the bar will travel approximately 180-degrees). At this point your arms should be parallel to the floor with the palms of your hands facing the ceiling.$x$,$x$Now return the barbell to the starting position by reversing the motion as you exhale.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Front_Raise_And_Pullover/0.jpg$x$),
($x$Front Two-Dumbbell Raise$x$,'shoulders','{}','dumbbell','strength',ARRAY[$x$Pick a couple of dumbbells and stand with a straight torso and the dumbbells on front of your thighs at arms length with the palms of the hand facing your thighs. This will be your starting position.$x$,$x$While maintaining the torso stationary (no swinging), lift the dumbbells to the front with a slight bend on the elbow and the palms of the hands always facing down. Continue to go up until you arms are slightly above parallel to the floor. Exhale as you execute this portion of the movement and pause for a second at the top.$x$,$x$As you inhale, lower the dumbbells back down slowly to the starting position.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Front_Two-Dumbbell_Raise/0.jpg$x$),
($x$Gironda Sternum Chins$x$,'back','{biceps}','other','strength',ARRAY[$x$Grasp the pull-up bar with a shoulder width underhand grip.$x$,$x$Now hang with your arms fully extended and stick your chest out and lean back. Tip: You will be leaning back throughout the entire movement. This will be your starting position.$x$,$x$Start pulling yourself towards the bar with your spine arched throughout the movement and your head leaning back as far away from the bar as possible. Exhale as you perform this portion of the movement. Tip: At the upper end of the movement, your hips and legs will be at about a 45-degree angle to the floor.$x$,$x$Keep pulling until your collarbone passes the bar and your lower chest or sternum area touches it. Hold that contraction for a second. Tip: By the time you've completed this portion of the movement; your head will be parallel to the floor.$x$,$x$Slowly start going back to the starting position as you inhale.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Gironda_Sternum_Chins/0.jpg$x$),
($x$Good Morning off Pins$x$,'hamstrings','{core,glutes,back}','barbell','strength',ARRAY[$x$Begin with a bar on a rack at about the same height as your stomach. Bend over underneath the bar and rack the bar across the rear of your shoulders as you would a power squat, not on top of your shoulders. At the proper height, you should be near parallel to the floor when bent over. Keep your back tight, shoulder blades pinched together, and your knees slightly bent. Keep your back arched and your cervical spine in proper alignment.$x$,$x$Begin the motion by extending through the hips with your glutes and hamstrings, and you are standing with the weight. Slowly lower the weight back to the pins returning to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Good_Morning_off_Pins/0.jpg$x$),
($x$Gorilla Chin/Crunch$x$,'core','{biceps,back}','bodyweight','bodyweight',ARRAY[$x$Hang from a chin-up bar using an underhand grip (palms facing you) that is slightly wider than shoulder width.$x$,$x$Now bend your knees at a 90 degree angle so that the calves are parallel to the floor while the thighs remain perpendicular to it. This will be your starting position.$x$,$x$As you exhale, pull yourself up while crunching your knees up at the same time until your knees are at chest level. You will stop going up as soon as your nose is at the same level as the bar. Tip: When you get to this point you should also be finishing the crunch at the same time.$x$,$x$Slowly start to inhale as you return to the starting position.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Gorilla_Chin_Crunch/0.jpg$x$),
($x$Hang Snatch$x$,'hamstrings','{core,calves,forearms,glutes,back,quadriceps,shoulders}','barbell','olympic',ARRAY[$x$Begin with a wide grip on the bar, with an overhand or hook grip. The feet should be directly below the hips with the feet turned out. Your knees should be slightly bent, and the torso inclined forward. The spine should be fully extended and the head facing forward. The bar should be at the hips. This will be your starting position.$x$,$x$Aggressively extend through the legs and hips. At peak extension, shrug the shoulders and allow the elbows to flex to the side.$x$,$x$As you move your feet into the receiving position, forcefully pull yourself below the bar as you elevate the bar overhead. Receive the bar with your body as low as possible and the arms fully extended overhead.$x$,$x$Return to a standing position with the weight overhead. Follow by returning the weight to the ground under control.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Hang_Snatch/0.jpg$x$),
($x$Hanging Bar Good Morning$x$,'hamstrings','{core,glutes,back}','barbell','strength',ARRAY[$x$Begin with a bar on a rack at about the same height as your stomach. Suspend the bar using chains or suspension straps.$x$,$x$Bend over underneath the bar and rack the bar across the rear of your shoulders as you would a power squat, not on top of your traps. At the proper height, you should be near parallel to the floor when bent over. Keep your back tight, shoulder blades pinched together, and your knees slightly bent. Keep your back arched and your cervical spine in proper alignment.$x$,$x$Begin the motion by extending through the hips with your glutes and hamstrings, and you are standing with the weight.$x$,$x$Slowly lower the weight back to the starting position, where it is supported by the chains.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Hanging_Bar_Good_Morning/0.jpg$x$)
) as v(name,mg,sm,eq,et,ins,img)
where not exists (select 1 from exercises e where lower(e.name)=lower(v.name));

insert into exercises (name,muscle_group,secondary_muscles,equipment,exercise_type,instructions,image_url,is_custom,user_id)
select v.name,v.mg::muscle_group,v.sm::muscle_group[],v.eq::equipment_type,v.et::exercise_type,v.ins::text[],v.img,false,null
from (values
($x$Hanging Pike$x$,'core','{}','bodyweight','bodyweight',ARRAY[$x$Hang from a chin-up bar with your legs and feet together using an overhand grip (palms facing away from you) that is slightly wider than shoulder width. Tip: You may use wrist wraps in order to facilitate holding on to the bar.$x$,$x$Now bend your knees at a 90 degree angle and bring the upper legs forward so that the calves are perpendicular to the floor while the thighs remain parallel to it. This will be your starting position.$x$,$x$Pull your legs up as you exhale until you almost touch your shins with the bar above you. Tip: Try to straighten your legs as much as possible while at the top.$x$,$x$Lower your legs as slowly as possible until you reach the starting position. Tip: Avoid swinging and using momentum at all times.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Hanging_Pike/0.jpg$x$),
($x$Heaving Snatch Balance$x$,'quadriceps','{core,forearms,glutes,hamstrings,shoulders,triceps}','barbell','olympic',ARRAY[$x$This drill helps you learn the snatch. Begin by holding a light weight across the back of the shoulders. Your feet should be slightly wider than hip width apart with the feet turned out, the same position that you would perform a squat with.$x$,$x$Begin by dipping with the knees slightly, and popping back up to briefly unload the bar. Drive yourself underneath the bar, elevating it overhead as you descend into a full squat.$x$,$x$Return to a standing position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Heaving_Snatch_Balance/0.jpg$x$),
($x$Heavy Bag Thrust$x$,'chest','{core,shoulders,triceps}','other','strength',ARRAY[$x$Utilize a heavy bag for this exercise. Assume an upright stance next to the bag, with your feet staggered, fairly wide apart. Place your hand on the bag at about chest height. This will be your starting position.$x$,$x$Begin by twisting at the waist, pushing the bag forward as hard as possible. Perform this move quickly, pushing the bag away from your body.$x$,$x$Receive the bag as it swings back by reversing these steps.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Heavy_Bag_Thrust/0.jpg$x$),
($x$Hip Extension with Bands$x$,'glutes','{hamstrings}','bands','strength',ARRAY[$x$Secure one end of the band to the lower portion of a post and attach the other to one ankle.$x$,$x$Facing the attachment point of the band, hold on to the column to stabilize yourself.$x$,$x$Keeping your head and your chest up, move the resisted leg back as far as you can while keeping the knee straight.$x$,$x$Return the leg to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Hip_Extension_with_Bands/0.jpg$x$),
($x$Hip Flexion with Band$x$,'quadriceps','{}','bands','strength',ARRAY[$x$Secure one end of the band to the lower portion of a post and attach the other to one ankle.$x$,$x$Face away from the attachment point of the band.$x$,$x$Keeping your head and your chest up, raise your knee up to 90 degrees and pause.$x$,$x$Return the leg to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Hip_Flexion_with_Band/0.jpg$x$),
($x$Hip Lift with Band$x$,'glutes','{calves,hamstrings}','bands','strength',ARRAY[$x$After choosing a suitable band, lay down in the middle of the rack, after securing the band on either side of you. If your rack doesn't have pegs, the band can be secured using heavy dumbbells or similar objects, just ensure they won't move.$x$,$x$Adjust your position so that the band is directly over your hips. Bend your knees and place your feet flat on the floor. Your hands can be on the floor or holding the band in position.$x$,$x$Keeping your shoulders on the ground, drive through your heels to raise your hips, pushing into the band as high as you can.$x$,$x$Pause at the top of the motion, and return to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Hip_Lift_with_Band/0.jpg$x$),
($x$Hurdle Hops$x$,'hamstrings','{glutes,quadriceps,calves}','other','strength',ARRAY[$x$Set up a row of hurdles or other small barriers, placing them a few feet apart.$x$,$x$Stand in front of the first hurdle with your feet shoulder width apart. This will be your starting position.$x$,$x$Begin by jumping with both feet over the first hurdle, swinging both arms as you jump.$x$,$x$Absorb the impact of landing by bending the knees, rebounding out of the first leap by jumping over the next hurdle. Continue until you have jumped over all of the hurdles.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Hurdle_Hops/0.jpg$x$),
($x$Incline Bench Pull$x$,'back','{shoulders}','barbell','strength',ARRAY[$x$Grab a dumbbell in each hand and lie face down on an incline bench that is set to an incline that is approximately 30 degrees.$x$,$x$Let the arms hang to your sides fully extended as they point to the floor.$x$,$x$Turn the wrists until your hands have a pronated (palms down) grip.$x$,$x$Now flare the elbows out. This will be your starting position.$x$,$x$As you breathe out, start to pull the dumbbells up as if you are doing a reverse bench press. You will do this by bending at the elbows and bringing the upper arms up as you let the forearms hang. Continue this motion until the upper arms are at the same level as your back. Tip: The elbows will come out to the side and your upper arms and torso should make the letter "T" at the top of the movement. Hold the contraction at the top for a second.$x$,$x$Slowly go back down to the starting position as you breathe in.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Incline_Bench_Pull/0.jpg$x$),
($x$Incline Cable Chest Press$x$,'chest','{shoulders,triceps}','cable','strength',ARRAY[$x$Adjust the weight to an appropriate amount and be seated, grasping the handles. Your upper arms should be about 45 degrees to the body, with your head and chest up. The elbows should be bent to about 90 degrees. This will be your starting position.$x$,$x$Begin by extending through the elbow, pressing the handles together straight in front of you. Keep your shoulder blades retracted as you execute the movement.$x$,$x$After pausing at full extension, return to the starting position, keeping tension on the cables.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Incline_Cable_Chest_Press/0.jpg$x$),
($x$Incline Dumbbell Bench With Palms Facing In$x$,'chest','{shoulders,triceps}','dumbbell','strength',ARRAY[$x$Lie back on an incline bench with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.$x$,$x$By using your thighs to help you get the dumbbells up, clean the dumbbells one arm at a time so that you can hold them at shoulder width.$x$,$x$Once at shoulder width, keep the palms of your hands with a neutral grip (palms facing each other). Keep your elbows flared out with the upper arms in line with the shoulders (perpendicular to the torso) and the elbows bent creating a 90-degree angle between the upper arm and the forearm. This will be your starting position.$x$,$x$Now bring down the weights slowly to your side as you breathe in. Keep full control of the dumbbells at all times.$x$,$x$As you breathe out, push the dumbbells up using your pectoral muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly. Tip: It should take at least twice as long to go down than to come up.$x$,$x$Repeat the movement for the prescribed amount of repetitions.$x$,$x$When you are done, place the dumbbells back in your thighs and then on the floor. This is the safest manner to dispose of the dumbbells.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Incline_Dumbbell_Bench_With_Palms_Facing_In/0.jpg$x$),
($x$Incline Inner Biceps Curl$x$,'biceps','{}','dumbbell','strength',ARRAY[$x$Hold a dumbbell in each hand and lie back on an incline bench.$x$,$x$The dumbbells should be at arm's length hanging at your sides and your palms should be facing out. This will be your starting position.$x$,$x$Now as you exhale curl the weight outward and up while keeping your forearms in line with your side deltoids. Continue the curl until the dumbbells are at shoulder height and to the sides of your deltoids. Tip: The end of the movement should look similar to a double biceps pose.$x$,$x$After a second contraction at the top of the movement, start to inhale and slowly lower the weights back to the starting position using the same path used to bring them up.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Incline_Inner_Biceps_Curl/0.jpg$x$),
($x$Isometric Chest Squeezes$x$,'chest','{shoulders,triceps}','bodyweight','bodyweight',ARRAY[$x$While either seating or standing, bend your arms at a 90-degree angle and place the palms of your hands together in front of your chest. Tip: Your hands should be open with the palms together and fingers facing forward (perpendicular to your torso).$x$,$x$Push both hands against each other as you contract your chest. Start with slow tension and increase slowly. Keep breathing normally as you execute this contraction.$x$,$x$Hold for the recommended number of seconds.$x$,$x$Now release the tension slowly.$x$,$x$Rest for the recommended amount of time and repeat.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Isometric_Chest_Squeezes/0.jpg$x$),
($x$Isometric Wipers$x$,'chest','{core,shoulders,triceps}','bodyweight','bodyweight',ARRAY[$x$Assume a push-up position, supporting your weight on your hands and toes while keeping your body straight. Your hands should be just outside of shoulder width. This will be your starting position.$x$,$x$Begin by shifting your body weight as far to one side as possible, allowing the elbow on that side to flex as you lower your body.$x$,$x$Reverse the motion by extending the flexed arm, pushing yourself up and then dropping to the other side.$x$,$x$Repeat for the desired number of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Isometric_Wipers/0.jpg$x$),
($x$Janda Sit-Up$x$,'core','{}','bodyweight','bodyweight',ARRAY[$x$Position your body on the floor in the basic sit-up position; knees to a ninety degree angle with feet flat on the floor and arms either crossed over your chest or to the sides. This will be your starting position.$x$,$x$As you strongly tighten your glutes and hamstrings, fill your lungs with air and in a slow (three to six second count) ascent, slowly exhale. Tip: It is important to tighten the glutes and hamstrings as this will cause the hip flexors to be inactivated in a process called reciprocal inhibition, which basically means that opposite muscles to the contracted ones will relax.$x$,$x$As you inhale, slowly go back in a controlled manner to the starting position.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Janda_Sit-Up/0.jpg$x$),
($x$Jefferson Squats$x$,'quadriceps','{calves,glutes,hamstrings,back}','barbell','strength',ARRAY[$x$Place a barbell on the floor.$x$,$x$Stand in the middle of the bar length wise.$x$,$x$Bend down by bending at the knees and keeping your back straight and grasp the front of the bar with your right hand. Your palm should be in (neutral grip) facing the left side.$x$,$x$Grasp the rear of the bar with your left hand. The palm of your hand should be in neutral grip alignment (palms facing the right side). Tip: Ensure that your grip is even on the bar. Your torso should be positioned right in the middle of the bar and the distance between your torso and your right hand (which should be at the front) should be the same as the distance between your torso and your left hand (which should be to your back).$x$,$x$Now stand straight up with the weight. Tip: Your feet should be shoulder width apart and your toes slightly pointed out.$x$,$x$Squat down by bending at the knees and keeping your back straight until your upper thighs are parallel with the floor. Tip: Keep your back as vertical as possible with the floor and your head up. Also remember to not let your knees go past your toes. Inhale during this portion of the movement.$x$,$x$Now drive yourself back up to the starting position by pushing with the feet . Tip: Keep the bar hanging at arm's length and your elbows locked with a slight bend. The arms only serve as hooks. Avoid doing any lifting with them. Do the lifting with your thighs; not your arms.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Jefferson_Squats/0.jpg$x$),
($x$Jerk Balance$x$,'shoulders','{glutes,hamstrings,quadriceps,triceps}','barbell','olympic',ARRAY[$x$This drill helps you learn to drive yourself low enough during the jerk and corrects those who move backward during the movement. Begin with the bar racked in the jerk position, with the shoulders forward, torso upright, and the feet split slightly apart.$x$,$x$Initiate the movement as you would a normal jerk, dipping at the knees while keeping your torso vertical, and driving back up forcefully, using momentum and not your arms to elevate the weight.$x$,$x$Keep the rear foot in place, using it to drive your body forward into a full split as you jerk the weight. Recover by standing up with the weight overhead.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Jerk_Balance/0.jpg$x$),
($x$Jerk Dip Squat$x$,'quadriceps','{core,calves}','barbell','olympic',ARRAY[$x$This movement strengthens the dip portion of the jerk. Begin with the bar racked in the jerk position, with the shoulders forward to create a shelf and the bar lightly contacting the throat. The feet should be directly under the hips, with the feet turned out as is comfortable.$x$,$x$Keeping the torso vertical, dip by flexing the knees, allowing them to travel forward and without moving the hips to the rear. The dip should not be excessive. Return the weight to the starting position by driving forcefully though the feet.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Jerk_Dip_Squat/0.jpg$x$),
($x$Jogging, Treadmill$x$,'quadriceps','{glutes,hamstrings}','machine','cardio',ARRAY[$x$To begin, step onto the treadmill and select the desired option from the menu. Most treadmills have a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. Elevation can be adjusted to change the intensity of the workout.$x$,$x$Treadmills offer convenience, cardiovascular benefits, and usually have less impact than jogging outside. A 150 lb person will burn almost 250 calories jogging for 30 minutes, compared to more than 450 calories running. Maintain proper posture as you jog, and only hold onto the handles when necessary, such as when dismounting or checking your heart rate.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Jogging_Treadmill/0.jpg$x$),
($x$Keg Load$x$,'back','{core,biceps,calves,forearms,glutes,hamstrings,quadriceps,shoulders}','other','strength',ARRAY[$x$To load kegs, place the desired number a distance from the loading platform, typically 30-50 feet.$x$,$x$Begin by grabbing the close handle of the first keg, tilting it onto its side to grab the opposite edge of the bottom of the keg. Lift the keg up to your chest.$x$,$x$The higher you can place the keg, the faster you should be able to move to the platform. Shouldering is usually not allowed. Be sure to keep a firm hold on the keg. Move as quickly as possible to the platform, and load it, extending through your hips, knees, and ankles to get it as high as possible.$x$,$x$Return to the starting position to retrieve the next keg, and repeat until the event is completed.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Keg_Load/0.jpg$x$),
($x$Kettlebell Dead Clean$x$,'hamstrings','{calves,glutes,back,quadriceps}','kettlebell','strength',ARRAY[$x$Place kettlebell between your feet. To get in the starting position, push your butt back and look straight ahead.$x$,$x$Clean the kettlebell to your shoulder. Clean the kettlebell to your shoulders by extending through the legs and hips as you raise the kettlebell towards your shoulder. The wrist should rotate as you do so.$x$,$x$Lower the kettlebell, keeping the hamstrings loaded by keeping your back straight and your butt out.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Kettlebell_Dead_Clean/0.jpg$x$),
($x$Kettlebell Figure 8$x$,'core','{hamstrings,shoulders}','kettlebell','strength',ARRAY[$x$Place one kettlebell between your legs and take a wider than shoulder width stance. Bend over by pushing your butt out and keeping your back flat.$x$,$x$Pick up a kettlebell and pass it to your other hand between your legs. The receiving hand should reach from behind the legs. Go back and forth for several repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Kettlebell_Figure_8/0.jpg$x$),
($x$Kettlebell One-Legged Deadlift$x$,'hamstrings','{glutes,back}','kettlebell','strength',ARRAY[$x$Hold a kettlebell by the handle in one hand. Stand on one leg, on the same side that you hold the kettlebell.$x$,$x$Keeping that knee slightly bent, perform a stiff legged deadlift by bending at the hip, extending your free leg behind you for balance.$x$,$x$Continue lowering the kettlebell until you are parallel to the ground, and then return to the upright position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Kettlebell_One-Legged_Deadlift/0.jpg$x$),
($x$Kettlebell Pass Between The Legs$x$,'core','{glutes,hamstrings,shoulders}','kettlebell','strength',ARRAY[$x$Place one kettlebell between your legs and take a comfortable stance. Bend over by pushing your butt out and keeping your back flat.$x$,$x$Pick up a kettlebell and pass it to your other hand between your legs, in the fashion of a "W". Go back and forth for several repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Kettlebell_Pass_Between_The_Legs/0.jpg$x$),
($x$Kettlebell Pirate Ships$x$,'shoulders','{core}','kettlebell','strength',ARRAY[$x$With a wide stance, hold a kettlebell with both hands. Allow it to hang at waist level with your arms extended. This will be your starting position.$x$,$x$Initiate the movement by turning to one side, swinging the kettlebell to head height. Briefly pause at the top of the motion.$x$,$x$Allow the bell to drop as you rotate to the opposite side, again raising the kettlebell to head height.$x$,$x$Repeat for the desired amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Kettlebell_Pirate_Ships/0.jpg$x$),
($x$Kettlebell Seesaw Press$x$,'shoulders','{triceps}','kettlebell','strength',ARRAY[$x$Clean two kettlebells two your shoulders.$x$,$x$Press one kettlebell.$x$,$x$Lower the kettlebell and immediately press the other kettlebell. Make sure to do the same amount of reps on both sides.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Kettlebell_Seesaw_Press/0.jpg$x$),
($x$Kettlebell Sumo High Pull$x$,'back','{quadriceps,glutes,hamstrings,shoulders}','kettlebell','strength',ARRAY[$x$Place a kettlebell on the ground between your feet. Position your feet in a wide stance, and grasp the kettlebell with two hands. Set your hips back as far as possible, with your knees bent. Keep your chest and head up. This will be your starting position.$x$,$x$Begin by extending the hips and knees, simultaneously pulling the kettlebell to your shoulders, raising your elbows as you do so. Reverse the motion to return to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Kettlebell_Sumo_High_Pull/0.jpg$x$),
($x$Kipping Muscle Up$x$,'back','{core,biceps,forearms,shoulders,triceps}','other','strength',ARRAY[$x$Grip the rings using a false grip, with the base of your palms on top of the rings.$x$,$x$Begin with a movement swinging your legs backward slightly.$x$,$x$Counter that movement by swinging your legs forward and up, jerking your chin and chest back, pulling yourself up with both arms as you do so. As you reach the top position of the pull-up, pull the rings to your armpits as you roll your shoulders forward, allowing your elbows to move straight back behind you. This puts you into the proper position to continue into the dip portion of the movement.$x$,$x$Maintaining control and stability, extend through the elbow to complete the motion.$x$,$x$Use care when lowering yourself to the ground.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Kipping_Muscle_Up/0.jpg$x$),
($x$Knee/Hip Raise On Parallel Bars$x$,'core','{}','other','strength',ARRAY[$x$Position your body on the vertical leg raise bench so that your forearms are resting on the pads next to the torso and holding on to the handles. Your arms will be bent at a 90 degree angle.$x$,$x$The torso should be straight with the lower back pressed against the pad of the machine and the legs extended pointing towards the floor. This will be your starting position.$x$,$x$Now as you breathe out, lift your legs up as you keep them extended. Continue this movement until your legs are roughly parallel to the floor and then hold the contraction for a second. Tip: Do not use any momentum or swinging as you perform this exercise.$x$,$x$Slowly go back to the starting position as you breathe in.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Knee_Hip_Raise_On_Parallel_Bars/0.jpg$x$),
($x$Knee Tuck Jump$x$,'hamstrings','{glutes,quadriceps,calves}','bodyweight','bodyweight',ARRAY[$x$Begin in a comfortable standing position with your knees slightly bent. Hold your hands in front of you, palms down with your fingertips together at chest height. This will be your starting position.$x$,$x$Rapidly dip down into a quarter squat and immediately explode upward. Drive the knees towards the chest, attempting to touch them to the palms of the hands.$x$,$x$Jump as high as you can, raising your knees up, and then ensure a good land be re-extending your legs, absorbing impact through be allowing the knees to rebend.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Knee_Tuck_Jump/0.jpg$x$),
($x$Kneeling Arm Drill$x$,'shoulders','{core}','other','strength',ARRAY[$x$This drill helps increase arm efficiency during the run. Begin kneeling, left foot in front, right knee down. Apply pressure through the front heel to keep your glutes and hamstrings activated.$x$,$x$Begin by blocking the arms in long, pendulum like swings. Close the arm angle, blocking with the arms as you would when jogging, progressing to a run and finally a sprint.$x$,$x$As soon as your hands pass the hip, accelerate them forward during the sprinting motion to move them as quickly as possible.$x$,$x$Switch knees and repeat.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Kneeling_Arm_Drill/0.jpg$x$),
($x$Kneeling Cable Triceps Extension$x$,'triceps','{}','cable','strength',ARRAY[$x$Place a bench sideways in front of a high pulley machine.$x$,$x$Hold a straight bar attachment above your head with your hands about 6 inches apart with your palms facing down.$x$,$x$Face away from the machine and kneel.$x$,$x$Place your head and the back of your upper arms on the bench. Your elbows should be bent with the forearms pointing towards the high pulley. This will be your starting position.$x$,$x$While keeping your upper arms close to your head at all times with the elbows in, press the bar out in a semicircular motion until the elbows are locked and your arms are parallel to the floor. Contract the triceps hard and keep this position for a second. Exhale as you perform this movement.$x$,$x$Slowly return to the starting position as you breathe in.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Kneeling_Cable_Triceps_Extension/0.jpg$x$),
($x$Kneeling High Pulley Row$x$,'back','{biceps}','cable','strength',ARRAY[$x$Select the appropriate weight using a pulley that is above your head. Attach a rope to the cable and kneel a couple of feet away, holding the rope out in front of you with both arms extended. This will be your starting position.$x$,$x$Initiate the movement by flexing the elbows and fully retracting your shoulders, pulling the rope toward your upper chest with your elbows out.$x$,$x$After pausing briefly, slowly return to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Kneeling_High_Pulley_Row/0.jpg$x$),
($x$Kneeling Jump Squat$x$,'glutes','{calves,hamstrings,quadriceps}','barbell','olympic',ARRAY[$x$Begin kneeling on the floor with a barbell racked across the back of your shoulders, or you can use your body weight for this exercise. This can be done inside of a power rack to make unracking easier.$x$,$x$Sit back with your hips until your glutes touch your feet, keeping your head and chest up.$x$,$x$Explode up with your hips, generating enough power to land with your feet flat on the floor.$x$,$x$Continue with the squat by driving through your heels and extending the knees to come to a standing position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Kneeling_Jump_Squat/0.jpg$x$),
($x$Kneeling Squat$x$,'glutes','{core,hamstrings,back}','barbell','strength',ARRAY[$x$Set the bar to the proper height in a power rack. Kneel behind the bar; it may be beneficial to put a mat down to pad your knees. Slide under the bar, racking it across the back of your shoulders. Your shoulder blades should be retracted and the bar tight across your back. Unrack the weight.$x$,$x$With your head looking forward, sit back with your butt until you touch your calves.$x$,$x$Reverse the motion, returning the torso to an upright position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Kneeling_Squat/0.jpg$x$),
($x$Landmine 180's$x$,'core','{glutes,back,shoulders}','barbell','strength',ARRAY[$x$Position a bar into a landmine or securely anchor it in a corner. Load the bar to an appropriate weight.$x$,$x$Raise the bar from the floor, taking it to shoulder height with both hands with your arms extended in front of you. Adopt a wide stance. This will be your starting position.$x$,$x$Perform the movement by rotating the trunk and hips as you swing the weight all the way down to one side. Keep your arms extended throughout the exercise.$x$,$x$Reverse the motion to swing the weight all the way to the opposite side.$x$,$x$Continue alternating the movement until the set is complete.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Landmine_180s/0.jpg$x$),
($x$Landmine Linear Jammer$x$,'shoulders','{core,calves,chest,hamstrings,quadriceps,triceps}','barbell','strength',ARRAY[$x$Position a bar into landmine or, lacking one, securely anchor it in a corner. Load the bar to an appropriate weight and position the handle attachment on the bar.$x$,$x$Raise the bar from the floor, taking the handles to your shoulders. This will be your starting position.$x$,$x$In an athletic stance, squat by flexing your hips and setting your hips back, keeping your arms flexed.$x$,$x$Reverse the motion by powerfully extending through the hips, knees, and ankles, while also extending the elbows to straighten the arms. This movement should be done explosively, coming out of the squat to full extension as powerfully as possible.$x$,$x$Return to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Landmine_Linear_Jammer/0.jpg$x$),
($x$Lateral Bound$x$,'quadriceps','{glutes,calves,hamstrings}','bodyweight','bodyweight',ARRAY[$x$Assume a half squat position facing 90 degrees from your direction of travel. This will be your starting position.$x$,$x$Allow your lead leg to do a countermovement inward as you shift your weight to the outside leg.$x$,$x$Immediately push off and extend, attempting to bound to the side as far as possible.$x$,$x$Upon landing, immediately push off in the opposite direction, returning to your original start position.$x$,$x$Continue back and forth for several repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Lateral_Bound/0.jpg$x$),
($x$Lateral Box Jump$x$,'quadriceps','{glutes,calves,hamstrings}','other','strength',ARRAY[$x$Assume a comfortable standing position, with a short box positioned next to you. This will be your starting position.$x$,$x$Quickly dip into a quarter squat to initiate the stretch reflex, and immediately reverse direction to jump up and to the side.$x$,$x$Bring your knees high enough to ensure your feet have good clearance over the box.$x$,$x$Land on the center of the box, using your legs to absorb the impact.$x$,$x$Carefully jump down to the other side of the box, and continue going back and forth for several repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Lateral_Box_Jump/0.jpg$x$),
($x$Lateral Cone Hops$x$,'quadriceps','{glutes,calves,hamstrings}','other','strength',ARRAY[$x$Position a number of cones in a row several feet apart.$x$,$x$Stand next to the end of the cones, facing 90 degrees to the direction of travel. This will be your starting position.$x$,$x$Begin the jump by dipping with the knees to initiate a stretch reflex, and immediately reverse direction to push off the ground, jumping up and sideways over the cone.$x$,$x$Use your legs to absorb impact upon landing, and rebound into the next jump, continuing down the row of cones.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Lateral_Cone_Hops/0.jpg$x$),
($x$Leg Lift$x$,'glutes','{hamstrings}','bodyweight','bodyweight',ARRAY[$x$While standing up straight with both feet next to each other at around shoulder width, grab a sturdy surface such as the sides of a squat rack or the top of a chair to brace yourself and keep balance.$x$,$x$With or without an ankle weight, lift one leg behind you as if performing a leg curl but standing up while keeping the other leg straight. Breathe out as you perform this movement.$x$,$x$Slowly bring the raised leg back to the floor as you breathe in.$x$,$x$Repeat for the recommended amount of repetitions.$x$,$x$Repeat the movement with the opposite leg.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Leg_Lift/0.jpg$x$),
($x$Leg Pull-In$x$,'core','{}','bodyweight','bodyweight',ARRAY[$x$Lie on an exercise mat with your legs extended and your hands either palms facing down next to you or under your glutes. Tip: My preference is with the hands next to me. This will be your starting position.$x$,$x$Bend your knees and pull your upper thighs into your midsection as you breathe out. Continue the motion until your knees are around chest level. Contract your abs as you execute this movement and hold for a second at the top. Tip: As you perform the motion, the lower legs (calves) should always remain parallel to the floor.$x$,$x$Return to the starting position as you inhale.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Leg_Pull-In/0.jpg$x$),
($x$Leverage Chest Press$x$,'chest','{shoulders,triceps}','machine','strength',ARRAY[$x$Load an appropriate weight onto the pins and adjust the seat for your height. The handles should be near the bottom or middle of the pectorals at the beginning of the motion.$x$,$x$Your chest and head should be up and your shoulder blades retracted. This will be your starting position.$x$,$x$Press the handles forward by extending through the elbow.$x$,$x$After a brief pause at the top, return the weight just above the start position, keeping tension on the muscles by not returning the weight to the stops until the set is complete.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Leverage_Chest_Press/0.jpg$x$),
($x$Leverage Deadlift$x$,'quadriceps','{glutes,hamstrings}','machine','strength',ARRAY[$x$Load the pins to an appropriate weight. Position yourself directly between the handles. Grasp the bottom handles with a comfortable grip, and then lower your hips as you take a breath. Look forward with your head and keep your chest up. This will be your starting position.$x$,$x$Return the weight to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Leverage_Deadlift/0.jpg$x$),
($x$Leverage Decline Chest Press$x$,'chest','{shoulders,triceps}','machine','strength',ARRAY[$x$Load an appropriate weight onto the pins and adjust the seat for your height. The handles should be near the bottom of the pectorals at the beginning of the motion. Your chest and head should be up and your shoulder blades retracted. This will be your starting position.$x$,$x$Press the handles forward by extending through the elbow.$x$,$x$After a brief pause at the top, return the weight just above the start position, keeping tension on the muscles by not returning the weight to the stops until the set is complete.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Leverage_Decline_Chest_Press/0.jpg$x$),
($x$Leverage High Row$x$,'back','{}','machine','strength',ARRAY[$x$Load an appropriate weight onto the pins and adjust the seat height so that you can just reach the handles above you. Adjust the knee pad to help keep you down. Grasp the handles with a pronated grip. This will be your starting position.$x$,$x$Pull the handles towards your torso, retracting your shoulder blades as you flex the elbow.$x$,$x$Pause at the bottom of the motion, and then slowly return the handles to the starting position.$x$,$x$For multiple repetitions, avoid completely returning the weight to the stops to keep tension on the muscles being worked.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Leverage_High_Row/0.jpg$x$),
($x$Leverage Incline Chest Press$x$,'chest','{shoulders,triceps}','machine','strength',ARRAY[$x$Load an appropriate weight onto the pins and adjust the seat for your height. The handles should be near the top of the pectorals at the beginning of the motion. Your chest and head should be up and your shoulder blades retracted. This will be your starting position.$x$,$x$Press the handles forward by extending through the elbow.$x$,$x$After a brief pause at the top, return the weight just above the start position, keeping tension on the muscles by not returning the weight to the stops until the set is complete.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Leverage_Incline_Chest_Press/0.jpg$x$),
($x$Leverage Iso Row$x$,'back','{biceps}','machine','strength',ARRAY[$x$Load an appropriate weight onto the pins and adjust the seat height so that the handles are at chest level. Grasp the handles with either a neutral or pronated grip. This will be your starting position.$x$,$x$Pull the handles towards your torso, retracting your shoulder blades as you flex the elbow.$x$,$x$Pause at the bottom of the motion, and then slowly return the handles to the starting position. For multiple repetitions, avoid completely returning the weight to the stops to keep tension on the muscles being worked.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Leverage_Iso_Row/0.jpg$x$),
($x$Leverage Shoulder Press$x$,'shoulders','{triceps}','machine','strength',ARRAY[$x$Load an appropriate weight onto the pins and adjust the seat for your height. The handles should be near the top of the shoulders at the beginning of the motion. Your chest and head should be up and handles held with a pronated grip. This will be your starting position.$x$,$x$Press the handles upward by extending through the elbow.$x$,$x$After a brief pause at the top, return the weight to just above the start position, keeping tension on the muscles by not returning the weight to the stops until the set is complete.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Leverage_Shoulder_Press/0.jpg$x$),
($x$Leverage Shrug$x$,'back','{forearms}','machine','strength',ARRAY[$x$Load the pins to an appropriate weight. Position yourself directly between the handles.$x$,$x$Grasp the top handles with a comfortable grip, and then lower your hips as you take a breath. Look forward with your head and keep your chest up.$x$,$x$Drive through the floor with your heels, extending your hips and knees as you rise to a standing position. Keep your arms straight throughout the movement, finishing with your shoulders back. This will be your starting position.$x$,$x$Raise the weight by shrugging the shoulders towards your ears, moving straight up and down.$x$,$x$Pause at the top of the motion, and then return the weight to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Leverage_Shrug/0.jpg$x$),
($x$Linear 3-Part Start Technique$x$,'hamstrings','{calves,quadriceps}','other','strength',ARRAY[$x$This drill helps you accelerate as quickly as possible into a sprint from a dead stop. It helps to use a line to start from. Begin with two feet on the line. Place your left foot with the toe next to your right ankle. Place your right foot 4-6 inches behind the left.$x$,$x$Place your right hand onto the line, and thing bring your nose close to your left knee.$x$,$x$Squat down as you lean foward, your head being lower than your hips and your weight loaded onto the left leg. This will be your starting position.$x$,$x$Take your left hand up so that it is parallel to the ground, pointing behind you, and explode out when ready.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Linear_3-Part_Start_Technique/0.jpg$x$),
($x$Linear Acceleration Wall Drill$x$,'hamstrings','{calves,glutes,quadriceps}','other','strength',ARRAY[$x$Lean at around 45 degrees against a wall. Your feet should be together, glutes contracted.$x$,$x$Begin by lifting your right knee quickly, pausing, and then driving it straight down into the ground.$x$,$x$Switch legs, raising the opposite knee, and then attacking the ground straight down.$x$,$x$Repeat once more with your right leg, and as soon as the right foot strikes the ground hammer them out rapidly, alternating left and right as fast as you can.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Linear_Acceleration_Wall_Drill/0.jpg$x$),
($x$Linear Depth Jump$x$,'quadriceps','{calves,glutes,hamstrings}','other','strength',ARRAY[$x$You will need two boxes or benches spaced a few feet away from each other. Begin by standing on one box facing towards the other platform.$x$,$x$To initiate the movement, gently drop down to the ground between your platforms, allowing the knees and hips to flex.$x$,$x$Reverse the motion by exploding, extending through the hips, knees, and ankles to jump onto the other platform.$x$,$x$Land softly, asborbing the impact through the legs.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Linear_Depth_Jump/0.jpg$x$),
($x$Log Lift$x$,'shoulders','{core,chest,glutes,hamstrings,back,quadriceps,triceps}','other','strength',ARRAY[$x$Begin standing with the log in front of you. Grasp the handles, and begin to clean the log. As you are bent over to start the clean, attempt to get the log as high as possible, pulling it into your chest. Extend through the hips and knees to bring it up to complete the clean.$x$,$x$Push your head back and look up, creating a shelf on your chest to rest the log. Begin the press by dipping, flexing slightly through the knees and reversing the motion. This push press will generate momentum to start the log moving vertically. Continue by extending through the elbows to press the log above your head. There are no strict rules on form, so use whatever techniques you are most efficient with. As the log is pressed, ensure that you push your head through on each repetition, looking forward.$x$,$x$Repeat as many times as possible. Attempt to control the descent of the log as it is returned to the ground.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Log_Lift/0.jpg$x$),
($x$London Bridges$x$,'back','{biceps,forearms}','other','strength',ARRAY[$x$Attach a climbing rope to a high beam or cross member. Below it, ensure that the smith machine bar is locked in place with the safeties and cannot move. Alternatively, a secure box could also be utilized.$x$,$x$Stand on the bar, using the rope to balance yourself. This will be your starting position.$x$,$x$Keeping your body straight, lean back and lower your body by slowly going hand over hand with the rope. Continue until you are perpendicular to the ground.$x$,$x$Keeping your body straight, reverse the motion, going hand over hand back to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/London_Bridges/0.jpg$x$),
($x$Low Cable Triceps Extension$x$,'triceps','{}','cable','strength',ARRAY[$x$Select the desired weight and lay down face up on the bench of a seated row machine that has a rope attached to it. Your head should be pointing towards the attachment.$x$,$x$Grab the outside of the rope ends with your palms facing each other (neutral grip).$x$,$x$Position your elbows so that they are bent at a 90 degree angle and your upper arms are perpendicular (90 degree angle) to your torso. Tip: Keep the elbows in and make sure that the upper arms point to the ceiling while your forearms point towards the pulley above your head. This will be your starting position.$x$,$x$As you breathe out, extend your lower arms until they are straight and vertical. The upper arms and elbows remain stationary throughout the movement. Only the forearms should move. Contract the triceps hard for a second.$x$,$x$As you breathe in slowly return to the starting position.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Low_Cable_Triceps_Extension/0.jpg$x$),
($x$Low Pulley Row To Neck$x$,'shoulders','{biceps,back}','cable','strength',ARRAY[$x$Sit on a low pulley row machine with a rope attachment.$x$,$x$Grab the ends of the rope using a palms-down grip and sit with your back straight and your knees slightly bent. Tip: Keep your back almost completely vertical and your arms fully extended in front of you. This will be your starting position.$x$,$x$While keeping your torso stationary, lift your elbows and start bending them as you pull the rope towards your neck while exhaling. Throughout the movement your upper arms should remain parallel to the floor. Tip: Continue this motion until your hands are almost next to your ears (the forearms will not be parallel to the floor at the end of the movement as they will be angled a bit upwards) and your elbows are out away from your sides.$x$,$x$After holding for a second or so at the contracted position, come back slowly to the starting position as you inhale. Tip: Again, during no part of the movement should the torso move.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Low_Pulley_Row_To_Neck/0.jpg$x$),
($x$Lunge Pass Through$x$,'hamstrings','{calves,glutes,quadriceps}','kettlebell','strength',ARRAY[$x$Stand with your torso upright holding a kettlebell in your right hand. This will be your starting position.$x$,$x$Step forward with your left foot and lower your upper body down by flexing the hip and the knee, keeping the torso upright. Lower your back knee until it nearly touches the ground.$x$,$x$As you lunge, pass the kettlebell under your front leg to your opposite hand.$x$,$x$Pressing through the heel of your foot, return to the starting position.$x$,$x$Repeat the movement for the recommended amount of repetitions, alternating legs.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Lunge_Pass_Through/0.jpg$x$),
($x$Lunge Sprint$x$,'quadriceps','{calves,glutes,hamstrings}','machine','strength',ARRAY[$x$Adjust a bar in a Smith machine to an appropriate height. Position yourself under the bar, racking it across the back of your shoulders. Unrack the bar, and then split your feet, moving one foot forward and one foot back. This will be your starting position.$x$,$x$Lower your back knee nearly to the ground, flexing the knees and lowering your hips as you do so.$x$,$x$At the bottom of the descent, immediately reverse direction. Explosively drive through the heel of your front foot with light pressure from your back foot. Jump up and reverse the position of your legs.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Lunge_Sprint/0.jpg$x$),
($x$Lying Close-Grip Bar Curl On High Pulley$x$,'biceps','{}','cable','strength',ARRAY[$x$Place a flat bench in front of a high pulley or lat pulldown machine.$x$,$x$Hold the straight bar attachment using an underhand grip (palms up) that is about shoulder width.$x$,$x$Lie on your back with your head over the end of the bench.$x$,$x$Now extend your arms straight above your shoulders. Your torso and your arms should make a 90-degree angle and the elbows should be in. This will be your starting position.$x$,$x$As you breathe out, curl the bar down in a semicircular motion until it touches your chin. Squeeze the biceps for a second at the top contracted position. Tip: As you execute this motion only the forearms should move. At no time should the upper arms be moving at all. They are to remain perpendicular throughout the movement.$x$,$x$Return to starting position slowly.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Lying_Close-Grip_Bar_Curl_On_High_Pulley/0.jpg$x$),
($x$Lying Close-Grip Barbell Triceps Extension Behind The Head$x$,'triceps','{}','barbell','strength',ARRAY[$x$While holding a barbell or EZ Curl bar with a pronated grip (palms facing forward), lie on your back on a flat bench with your head close to the end of the bench. Tip: If you are holding a barbell grab it using a shoulder-width grip and if you are using an E-Z Bar grab it on the inner handles.$x$,$x$Extend your arms in front of you and slowly bring the bar back in a semi circular motion (while keeping the arms extended) to a position over your head. At the end of this step your arms should be overhead and parallel to the floor. This will be your starting position. Tip: Keep your elbows in at all times.$x$,$x$As you inhale, lower the bar by bending at the elbows and while keeping the upper arm stationary. Keep lowering the bar until your forearms are perpendicular to the floor.$x$,$x$As you exhale bring the bar back up to the starting position by pushing the bar up in a semi-circular motion until the lower arms are also parallel to the floor. Contract the triceps hard at the top of the movement for a second. Tip: Again, only the forearms should move. The upper arms should remain stationary at all times.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Lying_Close-Grip_Barbell_Triceps_Extension_Behind_The_Head/0.jpg$x$),
($x$Lying Close-Grip Barbell Triceps Press To Chin$x$,'triceps','{}','barbell','strength',ARRAY[$x$While holding a barbell or EZ Curl bar with a pronated grip (palms facing forward), lie on your back on a flat bench with your head off the end of the bench. Tip: If you are holding a barbell grab it using a shoulder-width grip and if you are using an E-Z Bar grab it on the inner handles.$x$,$x$Extend your arms in front of you as you hold the barbell over your chest. The arms should be perpendicular to your torso (90-degree angle). This will be your starting position.$x$,$x$As you inhale, lower the bar in a semi-circular motion by bending at the elbows and while keeping the upper arm stationary and elbows in. Keep lowering the bar until it lightly touches your chin.$x$,$x$As you exhale bring the bar back up to the starting position by pushing the bar up in a semi-circular motion. Contract the triceps hard at the top of the movement for a second. Tip: Again, only the forearms should move. The upper arms should remain stationary at all times.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Lying_Close-Grip_Barbell_Triceps_Press_To_Chin/0.jpg$x$),
($x$Lying Face Down Plate Neck Resistance$x$,'shoulders','{}','other','strength',ARRAY[$x$Lie face down with your whole body straight on a flat bench while holding a weight plate behind your head. Tip: You will need to position yourself so that your shoulders are slightly above the end of a flat bench in order for the upper chest, neck and face to be off the bench. This will be your starting position.$x$,$x$While keeping the plate secure on the back of your head slowly lower your head (as in saying "yes") as you breathe in.$x$,$x$Raise your head back up to the starting position in a semi-circular motion as you breathe out. Hold the contraction for a second.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Lying_Face_Down_Plate_Neck_Resistance/0.jpg$x$),
($x$Lying Face Up Plate Neck Resistance$x$,'shoulders','{}','other','strength',ARRAY[$x$Lie face up with your whole body straight on a flat bench while holding a weight plate on top of your forehead. Tip: You will need to position yourself so that your shoulders are slightly above the end of a flat bench in order for the traps, neck and head to be off the bench. This will be your starting position.$x$,$x$While keeping the plate secure on your forehead slowly lower your head back in a semi-circular motion as you breathe in.$x$,$x$Raise your head back up to the starting position in a semi-circular motion as you breathe out. Hold the contraction for a second.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Lying_Face_Up_Plate_Neck_Resistance/0.jpg$x$),
($x$Lying One-Arm Lateral Raise$x$,'shoulders','{}','dumbbell','strength',ARRAY[$x$While holding a dumbbell in one hand, lay with your chest down on a flat bench. The other hand can be used to hold to the leg of the bench for stability.$x$,$x$Position the palm of the hand that is holding the dumbbell in a neutral manner (palms facing your torso) as you keep the arm extended with the elbow slightly bent. This will be your starting position.$x$,$x$Now raise the arm with the dumbbell to the side until your elbow is at shoulder height and your arm is roughly parallel to the floor as you exhale. Tip: Maintain your arm perpendicular to the torso while keeping your arm extended throughout the movement. Also, keep the contraction at the top for a second.$x$,$x$Slowly lower the dumbbell to the starting position as you inhale.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Lying_One-Arm_Lateral_Raise/0.jpg$x$),
($x$Lying Rear Delt Raise$x$,'shoulders','{}','dumbbell','strength',ARRAY[$x$While holding a dumbbell in each hand, lay with your chest down on a flat bench.$x$,$x$Position the palms of the hands in a neutral manner (palms facing your torso) as you keep the arms extended with the elbows slightly bent. This will be your starting position.$x$,$x$Now raise the arms to the side until your elbows are at shoulder height and your arms are roughly parallel to the floor as you exhale. Tip: Maintain your arms perpendicular to the torso while keeping them extended throughout the movement. Also, keep the contraction at the top for a second.$x$,$x$Slowly lower the dumbbells to the starting position as you inhale.$x$,$x$Repeat for the recommended amount of repetitions and then switch to the other arm.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Lying_Rear_Delt_Raise/0.jpg$x$),
($x$Medicine Ball Chest Pass$x$,'chest','{shoulders,triceps}','other','strength',ARRAY[$x$You will need a partner for this exercise. Lacking one, this movement can be performed against a wall.$x$,$x$Begin facing your partner holding the medicine ball at your torso with both hands.$x$,$x$Pull the ball to your chest, and reverse the motion by extending through the elbows. For sports applications, you can take a step as you throw.$x$,$x$Your partner should catch the ball, and throw it back to you.$x$,$x$Receive the throw with both hands at chest height.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Medicine_Ball_Chest_Pass/0.jpg$x$),
($x$Medicine Ball Full Twist$x$,'core','{shoulders}','other','strength',ARRAY[$x$For this exercise you will need a medicine ball and a partner. Stand back to back with your partner, spaced 2-3 feet apart. This will be your starting position.$x$,$x$Hold the ball in front of the trunk. Open the hips and turn the shoulders at the same time as your partner.$x$,$x$For full rotation, you and your partner should twist in the same direction, i.e. counter-clockwise.$x$,$x$Pass the ball to your partner, and both of you can now twist in the opposite direction to repeat the procedure.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Medicine_Ball_Full_Twist/0.jpg$x$),
($x$Medicine Ball Scoop Throw$x$,'shoulders','{core,hamstrings,quadriceps}','other','strength',ARRAY[$x$Assume a semisquat stance with a medicine ball in your hands. Your arms should hang so the ball is near your feet.$x$,$x$Begin by thrusting the hips forward as you extend through the legs, jumping up.$x$,$x$As you do, swing your arms up and over your head, keeping them extended, releasing the ball at the peak of your movement. The goal is to throw the ball the greatest distance behind you.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Medicine_Ball_Scoop_Throw/0.jpg$x$),
($x$Middle Back Shrug$x$,'back','{}','dumbbell','strength',ARRAY[$x$Lie facedown on an incline bench while holding a dumbbell in each hand. Your arms should be fully extended hanging down and pointing towards the floor. The palms of your hands should be facing each other. This will be your starting position.$x$,$x$As you exhale, squeeze your shoulder blades together and hold the contraction for a full second. Tip: This movement is just like the reverse action of a hug, or trying to perform rear laterals as if you had no arms.$x$,$x$As you inhale go back to the starting position.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Middle_Back_Shrug/0.jpg$x$),
($x$Mixed Grip Chin$x$,'back','{biceps}','other','strength',ARRAY[$x$Using a spacing that is just about 1 inch wider than shoulder width, grab a pull-up bar with the palms of one hand facing forward and the palms of the other hand facing towards you. This will be your starting position.$x$,$x$Now start to pull yourself up as you exhale. Tip: With the arm that has the palms facing up concentrate on using the back muscles in order to perform the movement. The elbow of that arm should remain close to the torso. With the other arm that has the palms facing forward, the elbows will be away but in line with the torso. You will concentrate on using the lats to pull your body up.$x$,$x$After a second contraction at the top, start to slowly come down as you inhale.$x$,$x$Repeat for the recommended amount of repetitions.$x$,$x$On the following set, switch grips; so if you had the right hand with the palms facing you and the left one with the palms facing forward, on the next set you will have the palms facing forward for the right hand and facing you for the left.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Mixed_Grip_Chin/0.jpg$x$)
) as v(name,mg,sm,eq,et,ins,img)
where not exists (select 1 from exercises e where lower(e.name)=lower(v.name));

insert into exercises (name,muscle_group,secondary_muscles,equipment,exercise_type,instructions,image_url,is_custom,user_id)
select v.name,v.mg::muscle_group,v.sm::muscle_group[],v.eq::equipment_type,v.et::exercise_type,v.ins::text[],v.img,false,null
from (values
($x$Monster Walk$x$,'glutes','{}','bands','strength',ARRAY[$x$Place a band around both ankles and another around both knees. There should be enough tension that they are tight when your feet are shoulder width apart.$x$,$x$To begin, take short steps forward alternating your left and right foot.$x$,$x$After several steps, do just the opposite and walk backward to where you started.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Monster_Walk/0.jpg$x$),
($x$Moving Claw Series$x$,'hamstrings','{calves,quadriceps}','other','strength',ARRAY[$x$This move helps prepare your running form to help you excel at sprinting. As you run, be sure to flex the knee, aiming to kick your glutes as the hip extends.$x$,$x$Reload the quad as the leg moves back forward, attacking the ground on the next step.$x$,$x$Ensure that as you run, you block with the arms, punching through in a rapid 1-2 motion.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Moving_Claw_Series/0.jpg$x$),
($x$Muscle Snatch$x$,'hamstrings','{glutes,back,quadriceps,shoulders,triceps}','barbell','olympic',ARRAY[$x$Begin with a loaded barbell held at the mid thigh position with a wide grip. The feet should be directly below the hips, with the feet turned out as needed. Lower the hips, with the chest up and the head looking forward. The shoulders should be just in front of the bar. This will be the starting position.$x$,$x$Begin the pull by driving through the front of the heels, raising the bar. Transition into the second pull by extending through the hips knees and ankles, driving the bar up as quickly as possible. The bar should be close to the body.$x$,$x$Continue raising the bar to the overhead position, without rebending the knees.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Muscle_Snatch/0.jpg$x$),
($x$Muscle Up$x$,'back','{core,biceps,forearms,shoulders,triceps}','other','strength',ARRAY[$x$Grip the rings using a false grip, with the base of your palms on top of the rings. Initiate a pull up by pulling the elbows down to your side, flexing the elbows.$x$,$x$As you reach the top position of the pull-up, pull the rings to your armpits as you roll your shoulders forward, allowing your elbows to move straight back behind you. This puts you into the proper position to continue into the dip portion of the movement.$x$,$x$Maintaining control and stability, extend through the elbow to complete the motion.$x$,$x$Use care when lowering yourself to the ground.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Muscle_Up/0.jpg$x$),
($x$Narrow Stance Squats$x$,'quadriceps','{calves,glutes,hamstrings,back}','barbell','strength',ARRAY[$x$This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.$x$,$x$Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.$x$,$x$Step away from the rack and position your legs using a less-than-shoulder-width narrow stance with the toes slightly pointed out. Feet should be around 3-6 inches apart. Keep your head up at all times (looking down will get you off balance) and maintain a straight back. This will be your starting position. (Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances discussed in the foot stances section).$x$,$x$Begin to slowly lower the bar by bending the knees as you maintain a straight posture with the head up. Continue down until the angle between the upper leg and the calves becomes slightly less than 90-degrees (which is the point in which the upper legs are below parallel to the floor). Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.$x$,$x$Begin to raise the bar as you exhale by pushing the floor with the heel of your foot mainly as you straighten the legs again and go back to the starting position.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Narrow_Stance_Squats/0.jpg$x$),
($x$Neck Press$x$,'chest','{shoulders,triceps}','barbell','strength',ARRAY[$x$Lie back on a flat bench. Using a medium-width grip (a grip that creates a 90-degree angle in the middle of the movement between the forearms and the upper arms), lift the bar from the rack and hold it straight over your neck with your arms locked. This will be your starting position.$x$,$x$As you breathe in, come down slowly until you feel the bar on your neck.$x$,$x$After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your chest muscles. Lock your arms and squeeze your chest in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up).$x$,$x$Repeat the movement for the prescribed amount of repetitions.$x$,$x$When you are done, place the bar back in the rack.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Neck_Press/0.jpg$x$),
($x$Oblique Crunches$x$,'core','{}','bodyweight','bodyweight',ARRAY[$x$Lie flat on the floor with your lower back pressed to the ground. For this exercise, you will need to put one hand beside your head and the other to the side against the floor.$x$,$x$Make sure your feet are elevated and resting on a flat surface.$x$,$x$Now lift the shoulder in which your hand is touching your head.$x$,$x$Simply elevate your shoulder and body upward until you touch your knee. For example, if you have your right hand besides your head, then you want to elevate your body upwards until your right elbow touches your left knee. The same variation can be applied doing the inverse and using your left elbow to touch your right knee.$x$,$x$After your knee touches your elbow, lower your body until you have reached the starting position.$x$,$x$Remember to breathe in during the eccentric (lowering) part of the exercise and to breathe out during the concentric (upward) part of the exercise.$x$,$x$Continue alternating in this manner until all of the recommended repetitions for each side have been completed.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Oblique_Crunches/0.jpg$x$),
($x$Olympic Squat$x$,'quadriceps','{calves,glutes,hamstrings}','barbell','olympic',ARRAY[$x$Begin with a barbell supported on top of the traps. The chest should be up, and the head facing forward. Adopt a hip width stance with the feet turned out as needed.$x$,$x$Descend by flexing the knees, refraining from moving the hips back as much as possible. This requires that the knees travel forward; ensure that they stay aligned with the feet. The goal is to keep the torso as upright as possible. Continue all the way down, keeping the weight on the front of the heel.$x$,$x$At the moment the upper legs contact the lower, reverse the motion, driving the weight upward.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Olympic_Squat/0.jpg$x$),
($x$One-Arm Flat Bench Dumbbell Flye$x$,'chest','{}','dumbbell','strength',ARRAY[$x$Lie down on a flat bench with a dumbbell in one hand resting on top of your thigh. The palm of your hand with the dumbbell in it should be at a neutral grip.$x$,$x$By using your thighs to help you get the dumbbell up, clean the dumbbell so that you can hold it in front of you with your lifting arm being fully extended. Remember to maintain a neutral grip with this exercise. Your non lifting hand should be to the side holding the flat bench for better support. This will be your starting position.$x$,$x$Your arm with the weight should have a slight bend on your elbow in order to prevent stress at the biceps tendon. Begin by lowering your arm with the weight in it out in a wide arc until you feel a stretch on your chest. Breathe in as you perform this portion of the movement. Tip: Keep in mind that throughout the movement, your lifting arm should remain stationary; the movement should only occur at the shoulder joint.$x$,$x$Return your lifting arm back to the starting position as you squeeze your chest muscles and breathe out. Tip: Make sure to use the same arc of motion used to lower the weights.$x$,$x$Hold for a second at the contracted position and repeat the movement for the prescribed amount of repetitions.$x$,$x$Switch arms and repeat the exercise.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/One-Arm_Flat_Bench_Dumbbell_Flye/0.jpg$x$),
($x$One-Arm High-Pulley Cable Side Bends$x$,'core','{}','cable','strength',ARRAY[$x$Connect a standard handle to a tower. Move cable to highest pulley position.$x$,$x$Stand with side to cable. With one hand, reach up and grab handle with underhand grip.$x$,$x$Pull down cable until elbow touches your side and the handle is by your shoulder.$x$,$x$Position feet hip-width apart. Place free hand on hip to help gauge pivot point.$x$,$x$Keep arm in static position. Contract oblique to bring the weight down in a side crunch.$x$,$x$Once you reach maximum contraction, slowly release the weight to the starting position. The weight stack should never be unloaded in a resting position. The aim is constant tension during the set.$x$,$x$Repeat to failure.$x$,$x$Then, reposition and repeat the same series of movements on the opposite side.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/One-Arm_High-Pulley_Cable_Side_Bends/0.jpg$x$),
($x$One-Arm Incline Lateral Raise$x$,'shoulders','{}','dumbbell','strength',ARRAY[$x$Lie down sideways on an incline bench press with a dumbbell in the hand. Make sure the shoulder is pressing against the incline bench and the arm is lying across your body with the palm around your navel.$x$,$x$Hold a dumbbell in your uppermost arm while keeping it extended in front of you parallel to the floor. This is your starting position.$x$,$x$While keeping the dumbbell parallel to the floor at all times, perform a lateral raise. Your arm should travel straight up until it is pointing at the ceiling. Tip: Exhale as you perform this movement. Hold the dumbbell in the position and feel the contraction in the shoulders for a second.$x$,$x$While inhaling lower the weight across your body back into the starting position.$x$,$x$Repeat the movement for the prescribed amount of repetitions.$x$,$x$Switch arms and repeat the movement.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/One-Arm_Incline_Lateral_Raise/0.jpg$x$),
($x$One-Arm Kettlebell Clean$x$,'hamstrings','{glutes,back,shoulders}','kettlebell','strength',ARRAY[$x$Place a kettlebell between your feet. As you bend down to grab the kettlebell, push your butt back and keep your eyes looking forward.$x$,$x$Clean the kettlebell to your shoulders by extending through the legs and hips as you raise the kettlebell towards your shoulder. The wrist should rotate as you do so.$x$,$x$Return the weight to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/One-Arm_Kettlebell_Clean/0.jpg$x$),
($x$One-Arm Kettlebell Clean and Jerk$x$,'shoulders','{}','kettlebell','strength',ARRAY[$x$Hold a kettlebell by the handle.$x$,$x$Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward.$x$,$x$Dip your body by bending the knees, keeping your torso upright.$x$,$x$Immediately reverse direction, driving through the heels, in essence jumping to create momentum. As you do so, press the kettlebell overhead to lockout by extending the arms, using your body's momentum to move the weight.$x$,$x$Receive the weight overhead by returning to a squat position underneath the weight.$x$,$x$Keeping the weight overhead, return to a standing position. Lower the weight to the floor to perform the next repetition.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/One-Arm_Kettlebell_Clean_and_Jerk/0.jpg$x$),
($x$One-Arm Kettlebell Jerk$x$,'shoulders','{calves,quadriceps,triceps}','kettlebell','strength',ARRAY[$x$Hold a kettlebell by the handle. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward. This will be your starting position.$x$,$x$Dip your body by bending the knees, keeping your torso upright.$x$,$x$Immediately reverse direction, driving through the heels, in essence jumping to create momentum. As you do so, press the kettlebell overhead to lockout by extending the arms, using your body's momentum to move the weight. Receive the weight overhead by returning to a squat position underneath the weight. Keeping the weight overhead, return to a standing position.$x$,$x$Lower the weight to perform the next repetition.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/One-Arm_Kettlebell_Jerk/0.jpg$x$),
($x$One-Arm Kettlebell Para Press$x$,'shoulders','{triceps}','kettlebell','strength',ARRAY[$x$Clean a kettlebell to your shoulder. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward. This will be your starting position.$x$,$x$Hold the kettlebell with the elbow out to the side, and press it up and out until it is locked out overhead.$x$,$x$Lower the kettlebell back to your shoulder under control and repeat. Make sure to contract your lat, butt, and stomach forcefully for added stability and strength.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/One-Arm_Kettlebell_Para_Press/0.jpg$x$),
($x$One-Arm Kettlebell Push Press$x$,'shoulders','{calves,quadriceps,triceps}','kettlebell','strength',ARRAY[$x$Hold a kettlebell by the handle. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward. This will be your starting position.$x$,$x$Dip your body by bending the knees, keeping your torso upright.$x$,$x$Immediately reverse direction, driving through the heels, in essence jumping to create momentum. As you do so, press the kettlebell overhead to lockout by extending the arms, using your body's momentum to move the weight. Lower the weight to perform the next repetition.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/One-Arm_Kettlebell_Push_Press/0.jpg$x$),
($x$One-Arm Kettlebell Row$x$,'back','{biceps}','kettlebell','strength',ARRAY[$x$Place a kettlebell in front of your feet. Bend your knees slightly and then push your butt out as much as possible as you bend over to get in the starting position. Grab the kettlebell and pull it to your stomach, retracting your shoulder blade and flexing the elbow. Keep your back straight. Lower and repeat.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/One-Arm_Kettlebell_Row/0.jpg$x$),
($x$One-Arm Kettlebell Snatch$x$,'shoulders','{calves,glutes,hamstrings,back,triceps}','kettlebell','strength',ARRAY[$x$Place a kettlebell between your feet. Bend your knees and push your butt back to get in the proper starting position.$x$,$x$Look straight ahead and swing the kettlebell back between your legs.$x$,$x$Immediately reverse the direction and drive through with your hips and knees, accelerating the kettlebell upward. As the kettlebell rises to your shoulder rotate your hand and punch straight up, using momentum to receive the weight locked out overhead.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/One-Arm_Kettlebell_Snatch/0.jpg$x$),
($x$One-Arm Kettlebell Split Jerk$x$,'shoulders','{glutes,hamstrings,quadriceps,triceps}','kettlebell','strength',ARRAY[$x$Hold a kettlebell by the handle. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward. This will be your starting position.$x$,$x$Dip your body by bending the knees, keeping your torso upright.$x$,$x$Immediately reverse direction, driving through the heels, in essence jumping to create momentum. As you do so, press the kettlebell overhead to lockout by extending the arms, using your body's momentum to move the weight.$x$,$x$Receive the weight overhead by returning to a squat position underneath the weight, positioning one leg in front of you and one leg behind you.$x$,$x$Keeping the weight overhead, return to a standing position and bring your feet together. Lower the weight to perform the next repetition.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/One-Arm_Kettlebell_Split_Jerk/0.jpg$x$),
($x$One-Arm Kettlebell Split Snatch$x$,'shoulders','{hamstrings,quadriceps}','kettlebell','strength',ARRAY[$x$Hold a kettlebell in one hand by the handle.$x$,$x$Squat towards the floor, and then reverse the motion, extending the hips, knees, and finally the ankles, to raise the kettlebell overhead.$x$,$x$After fully extending the body, descend into a lunge position to receive the weights overhead, one leg forward and one leg back. Ensure you drive through with your hips and lock the ketttlebells overhead in one uninterrupted motion.$x$,$x$Return to a standing position, holding the weight overhead, and bring the feet together. Lower the weight to return to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/One-Arm_Kettlebell_Split_Snatch/0.jpg$x$),
($x$One-Arm Kettlebell Swings$x$,'hamstrings','{calves,glutes,back,shoulders}','kettlebell','strength',ARRAY[]::text[],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/One-Arm_Kettlebell_Swings/0.jpg$x$),
($x$One-Arm Long Bar Row$x$,'back','{biceps}','barbell','strength',ARRAY[$x$Position a bar into a landmine or in a corner to keep it from moving. Load an appropriate weight onto your end.$x$,$x$Stand next to the bar, and take a grip with one hand close to the collar. Using your hips and legs, rise to a standing position.$x$,$x$Assume a bent-knee stance with your hips back and your chest up. Your arm should be extended. This will be your starting position.$x$,$x$Pull the weight to your side by retracting the shoulder and flexing the elbow. Do not jerk the weight or cheat during the movement.$x$,$x$After a brief pause, return to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/One-Arm_Long_Bar_Row/0.jpg$x$),
($x$One-Arm Open Palm Kettlebell Clean$x$,'hamstrings','{forearms,glutes,back,quadriceps,shoulders}','kettlebell','strength',ARRAY[$x$Place one kettlebell between your feet.$x$,$x$Grab the handle with one hand and raise the kettlebell rapidly, let it flip so that the ball of the kettlebell lands in the palm of your hand.$x$,$x$Throw the kettlebell out in front of you and catch the handle with one hand.$x$,$x$Take the kettlebell to the floor and repeat. Make sure to work both arms.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/One-Arm_Open_Palm_Kettlebell_Clean/0.jpg$x$),
($x$One-Arm Overhead Kettlebell Squats$x$,'quadriceps','{calves,glutes,hamstrings,shoulders}','kettlebell','strength',ARRAY[$x$Clean and press a kettlebell with one arm. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so. Press the weight overhead by extending through the elbow.This will be your starting position.$x$,$x$Looking straight ahead and keeping a kettlebell locked out above you, flex the knees and hips and lower your torso between your legs, keeping your head and chest up.$x$,$x$Pause at the bottom position for a second before rising back to the top, driving through the heels of your feet.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/One-Arm_Overhead_Kettlebell_Squats/0.jpg$x$),
($x$One-Arm Side Deadlift$x$,'quadriceps','{core,calves,glutes,hamstrings,back}','barbell','strength',ARRAY[$x$Stand to the side of a barbell next to its center. Bend your knees and lower your body until you are able to reach the barbell.$x$,$x$Grasp the bar as if you were grabbing a briefcase (palms facing you since the bar is sideways). You may need a wrist wrap if you are using a significant amount of weight. This is your starting position.$x$,$x$Use your legs to help lift the barbell up while exhaling. Your arms should extend fully as bring the barbell up until you are in a standing position.$x$,$x$Slowly bring the barbell back down while inhaling. Tip: Make sure to bend your knees while lowering the weight to avoid any injury from occurring.$x$,$x$Repeat for the recommended amount of repetitions.$x$,$x$Switch arms and repeat the movement.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/One-Arm_Side_Deadlift/0.jpg$x$),
($x$One-Arm Side Laterals$x$,'shoulders','{}','dumbbell','strength',ARRAY[$x$Pick a dumbbell and place it in one of your hands. Your non lifting hand should be used to grab something steady such as an incline bench press. Lean towards your lifting arm and away from the hand that is gripping the incline bench as this will allow you to keep your balance.$x$,$x$Stand with a straight torso and have the dumbbell by your side at arm's length with the palm of the hand facing you. This will be your starting position.$x$,$x$While maintaining the torso stationary (no swinging), lift the dumbbell to your side with a slight bend on the elbow and your hand slightly tilted forward as if pouring water in a glass. Continue to go up until you arm is parallel to the floor. Exhale as you execute this movement and pause for a second at the top.$x$,$x$Lower the dumbbell back down slowly to the starting position as you inhale.$x$,$x$Repeat for the recommended amount of repetitions.$x$,$x$Switch arms and repeat the exercise.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/One-Arm_Side_Laterals/0.jpg$x$),
($x$One Arm Chin-Up$x$,'back','{biceps,forearms}','other','strength',ARRAY[$x$For this exercise, start out by placing a towel around a chin up bar.$x$,$x$Grab the chin-up bar with your palm facing you. One hand will be grabbing the chin-up bar and the other will be grabbing the towel.$x$,$x$Bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.v$x$,$x$Pull your torso up until the bar touches your upper chest by drawing the shoulders and the upper arms down and back. Exhale as you perform this portion of the movement. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.$x$,$x$After a second on the contracted position, start to inhale and slowly lower your torso back to the starting position when your arms are fully extended and the lats are fully stretched.$x$,$x$Repeat this motion for the prescribed amount of repetitions.$x$,$x$Switch arms and repeat the movement.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/One_Arm_Chin-Up/0.jpg$x$),
($x$One Arm Floor Press$x$,'triceps','{chest,shoulders}','barbell','strength',ARRAY[$x$Lie down on a flat surface with your back pressing against the floor or an exercise mat. Make sure your knees are bent.$x$,$x$Have a partner hand you the bar on one hand. When starting, your arm should be just about fully extended, similar to the starting position of a barbell bench press. However, this time your grip will be neutral (palms facing your torso).$x$,$x$Make sure the hand you are not using to lift the weight is placed by your side.$x$,$x$Begin the exercise by lowering the barbell until your elbow touches the ground. Make sure to breathe in as this is the eccentric (lowering part of the exercise).$x$,$x$Then start lifting the barbell back up to the original starting position. Remember to breathe out during the concentric (lifting part of the exercise).$x$,$x$Repeat until you have performed your recommended repetitions.$x$,$x$Switch arms and repeat the movement.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/One_Arm_Floor_Press/0.jpg$x$),
($x$One Arm Pronated Dumbbell Triceps Extension$x$,'triceps','{}','dumbbell','strength',ARRAY[$x$Lie flat on a bench while holding a dumbbell at arms length. Your arm should be perpendicular to your body. The palm of your hand should be facing towards your feet as a pronated grip is required to perform this exercise.$x$,$x$Place your non lifting hand on your bicep for support.$x$,$x$Slowly begin to lower the dumbbell down as you breathe in.$x$,$x$Then, begin lifting the dumbbell upward as you contract the triceps. Remember to breathe out during the concentric (lifting part of the exercise).$x$,$x$Repeat until you have performed your set repetitions.$x$,$x$Switch arms and repeat the movement.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/One_Arm_Pronated_Dumbbell_Triceps_Extension/0.jpg$x$),
($x$One Arm Supinated Dumbbell Triceps Extension$x$,'triceps','{}','dumbbell','strength',ARRAY[$x$Lie flat on a bench while holding a dumbbell at arms length. Your arm should be perpendicular to your body. The palm of your hand should be facing towards your face as a supinated grip is required to perform this exercise.$x$,$x$Place your non lifting hand on your bicep for support.$x$,$x$Slowly begin to lower the dumbbell down as you breathe in.$x$,$x$Then, begin lifting the dumbbell upward as you contract the triceps. Remember to breathe out during the concentric (lifting part of the exercise).$x$,$x$Repeat until you have performed your set repetitions.$x$,$x$Switch arms and repeat the movement.$x$,$x$Switch arms again and repeat the movement.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/One_Arm_Supinated_Dumbbell_Triceps_Extension/0.jpg$x$),
($x$One Leg Barbell Squat$x$,'quadriceps','{calves,glutes,hamstrings}','barbell','strength',ARRAY[$x$Start by standing about 2 to 3 feet in front of a flat bench with your back facing the bench. Have a barbell in front of you on the floor. Tip: Your feet should be shoulder width apart from each other.$x$,$x$Bend the knees and use a pronated grip with your hands being wider than shoulder width apart from each other to lift the barbell up until you can rest it on your chest.$x$,$x$Then lift the barbell over your head and rest it on the base of your neck. Move one foot back so that your toe is resting on the flat bench. Your other foot should be stationary in front of you. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. Tip: Make sure your back is straight and chest is out while performing this exercise.$x$,$x$As you inhale, slowly lower your leg until your thigh is parallel to the floor. At this point, your knee should be over your toes. Your chest should be directly above the middle of your thigh.$x$,$x$Leading with the chest and hips and contracting the quadriceps, elevate your leg back to the starting position as you exhale.$x$,$x$Repeat for the recommended amount of repetitions.$x$,$x$Switch legs and repeat the movement.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/One_Leg_Barbell_Squat/0.jpg$x$),
($x$Open Palm Kettlebell Clean$x$,'hamstrings','{glutes,back,quadriceps,shoulders}','kettlebell','strength',ARRAY[$x$Place one kettlebell between your feet. Clean the kettlebell by extending through the legs and hips as you raise the kettlebell towards your shoulders.$x$,$x$Release the kettlebell as it comes up, and let it flip so that the ball of the kettlebell lands in the palms of your hands.$x$,$x$Release the kettlebell out in front of you and catch the handle with both hands. Lower the kettlebell to the starting position and repeat.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Open_Palm_Kettlebell_Clean/0.jpg$x$),
($x$Otis-Up$x$,'core','{chest,shoulders,triceps}','other','strength',ARRAY[$x$Secure your feet and lay back on the floor. Your knees should be bent. Hold a weight with both hands to your chest. This will be your starting position.$x$,$x$Initiate the movement by flexing the hips and spine to raise your torso up from the ground.$x$,$x$As you move up, press the weight up so that it is above your head at the top of the movement.$x$,$x$Return the weight to your chest as you reverse the sit-up motion, ensuring not to go all the way down to the floor.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Otis-Up/0.jpg$x$),
($x$Overhead Slam$x$,'back','{}','other','strength',ARRAY[$x$Hold a medine ball with both hands and stand with your feet at shoulder width. This will be your starting position.$x$,$x$Initiate the countermovement by raising the ball above your head and fully extending your body.$x$,$x$Reverse the motion, slamming the ball into the ground directly in front of you as hard as you can.$x$,$x$Receive the ball with both hands on the bounce and repeat the movement.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Overhead_Slam/0.jpg$x$),
($x$Overhead Squat$x$,'quadriceps','{core,calves,glutes,hamstrings,back,shoulders,triceps}','barbell','olympic',ARRAY[$x$Start out by having a barbell in front of you on the floor. Your feet should be wider than shoulder width apart from each other.$x$,$x$Bend the knees and use a pronated grip (palms facing you) to grab the barbell. Your hands should be at a wider than shoulder width apart from each other before lifting. Once you are positioned, lift the barbell up until you can rest it on your chest.$x$,$x$Move the barbell over and slightly behind your head and make sure your arms are fully extended. Keep your head up at all times and also maintain a straight back. Retract your shoulder blades. This is your starting position.$x$,$x$Slowly lower the weight by bending your knees until your thighs are parallel to the ground while inhaling. Tip: Keep your back straight while performing this exercise to avoid any injuries and your arms should remain extended and over your head at all times.$x$,$x$Now use your feet and legs to help bring the weight back up to the starting position while exhaling.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Overhead_Squat/0.jpg$x$),
($x$Parallel Bar Dip$x$,'triceps','{chest,shoulders}','other','strength',ARRAY[$x$Stand between a set of parallel bars. Place a hand on each bar, and then take a small jump to help you get into the starting position with your arms locked out.$x$,$x$Begin by flexing the elbow, lowering your body until your arms break 90 degrees. Avoid swinging, and maintain good posture throughout the descent.$x$,$x$Reverse the motion by extending the elbow, pushing yourself back up into the starting position.$x$,$x$Repeat for the desired number of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Parallel_Bar_Dip/0.jpg$x$),
($x$Physioball Hip Bridge$x$,'glutes','{hamstrings}','other','strength',ARRAY[$x$Lay on a ball so that your upper back is on the ball with your hips unsupported. Both feet should be flat on the floor, hip width apart or wider. This will be your starting position.$x$,$x$Begin by extending the hips using your glutes and hamstrings, raising your hips upward as you bridge.$x$,$x$Pause at the top of the motion and return to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Physioball_Hip_Bridge/0.jpg$x$),
($x$Pin Presses$x$,'triceps','{chest,forearms,back,shoulders}','barbell','strength',ARRAY[$x$Pin presses remove the eccentric phase of the bench press, developing starting strength. They also allow you to train a desired range of motion.$x$,$x$The bench should be set up in a power rack. Set the pins to the desired point in your range of motion, whether it just be lockout or an inch off of your chest. The bar should be moved to the pins and prepared for lifting.$x$,$x$Begin by lying on the bench, with the bar directly above the contact point during your regular bench. Tuck your feet underneath you and arch your back. Using the bar to help support your weight, lift your shoulder off the bench and retract them, squeezing the shoulder blades together. Use your feet to drive your traps into the bench. Maintain this tight body position throughout the movement.$x$,$x$You can take a standard bench grip, or shoulder width to focus on the triceps. The bar, wrist, and elbow should stay in line at all times. Focus on squeezing the bar and trying to pull it apart.$x$,$x$Drive the bar up with as much force as possible. The elbows should be tucked in until lockout.$x$,$x$Return the bar to the pins, pausing before beginning the next repetition.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Pin_Presses/0.jpg$x$),
($x$Plate Twist$x$,'core','{}','other','strength',ARRAY[$x$Lie down on the floor or an exercise mat with your legs fully extended and your upper body upright. Grab the plate by its sides with both hands out in front of your abdominals with your arms slightly bent.$x$,$x$Slowly cross your legs near your ankles and lift them up off the ground. Your knees should also be bent slightly. Note: Move your upper body back slightly to help keep you balanced turning this exercise. This is the starting position.$x$,$x$Move the plate to the left side and touch the floor with it. Breathe out as you perform that movement.$x$,$x$Come back to the starting position as you breathe in and then repeat the movement but this time to the right side of the body. Tip: Use a slow controlled movement at all times. Jerking motions can injure the back.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Plate_Twist/0.jpg$x$),
($x$Platform Hamstring Slides$x$,'hamstrings','{glutes}','other','strength',ARRAY[$x$For this movement a wooden floor or similar is needed. Lay on your back with your legs extended. Place a gym towel or a light weight underneath your heel. This will be your starting position.$x$,$x$Begin the movement by flexing the knee, keeping your other leg straight.$x$,$x$Continue bringing the heel closer to you, sliding it on the floor.$x$,$x$At full knee flexion, reverse the movement to return to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Platform_Hamstring_Slides/0.jpg$x$),
($x$Plie Dumbbell Squat$x$,'quadriceps','{core,calves,glutes,hamstrings}','dumbbell','strength',ARRAY[$x$Hold a dumbbell at the base with both hands and stand straight up. Move your legs so that they are wider than shoulder width apart from each other with your knees slightly bent.$x$,$x$Your toes should be facing out. Note: Your arms should be stationary while performing the exercise. This is the starting position.$x$,$x$Slowly bend the knees and lower your legs until your thighs are parallel to the floor. Make sure to inhale as this is the eccentric part of the exercise.$x$,$x$Press mainly with the heel of the foot to bring the body back to the starting position while exhaling.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Plie_Dumbbell_Squat/0.jpg$x$),
($x$Plyo Push-up$x$,'chest','{shoulders,triceps}','bodyweight','bodyweight',ARRAY[$x$Move into a prone position on the floor, supporting your weight on your hands and toes.$x$,$x$Your arms should be fully extended with the hands around shoulder width. Keep your body straight throughout the movement. This will be your starting position.$x$,$x$Descend by flexing at the elbow, lowering your chest towards the ground.$x$,$x$At the bottom, reverse the motion by pushing yourself up through elbow extension as quickly as possible. Attempt to push your upper body up until your hands leave the ground.$x$,$x$Return to the starting position and repeat the exercise.$x$,$x$For added difficulty, add claps into the movement while you are air borne.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Plyo_Push-up/0.jpg$x$),
($x$Power Clean from Blocks$x$,'hamstrings','{quadriceps}','barbell','olympic',ARRAY[$x$With a barbell on boxes of the desired height, take a grip just outside the legs. Lower your hips with the weight focused on the heels, back straight, head facing forward, chest up, with your shoulders just in front of the bar. This will be your starting position.$x$,$x$Begin the first pull by driving through the heels, extending your knees. Your back angle should stay the same, and your arms should remain straight. As the bar approaches the mid-thigh position, begin extending through the hips.$x$,$x$In a jumping motion, accelerate by extending the hips, knees, and ankles, using speed to move the bar upward. There should be no need to actively pull through the arms to accelerate the weight. At the end of the second pull, the body should be fully extended, leaning slightly back, with the arms still extended.$x$,$x$As full extension is achieved, transition into the third pull by aggressively shrugging and flexing the arms with the elbows up and out. At peak extension, pull yourself under the bar far enough that it can be racked onto the shoulders, rotating your elbows under the bar as you do so. The bar should be racked onto the protracted shoulders, lightly touching the throat with the hands relaxed.$x$,$x$Immediately recover by driving through the heels, keeping the torso upright and elbows up. Continue until you have risen to a standing position, and complete the repetition by returning the weight to the boxes.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Power_Clean_from_Blocks/0.jpg$x$),
($x$Power Jerk$x$,'quadriceps','{core,calves,glutes,hamstrings,shoulders,triceps}','barbell','olympic',ARRAY[$x$Standing with the weight racked on the front of the shoulders, begin with the dip. With your feet directly under your hips, flex the knees without moving the hips backward. Go down only slightly, and reverse direction as powerfully as possible.$x$,$x$Drive through the heels create as much speed and force as possible, and be sure to move your head out of the way as the bar leaves the shoulders.$x$,$x$At this moment as the feet leave the floor, the feet must be placed into the receiving position as quickly as possible. In the brief moment the feet are not actively driving against the platform, the athletes effort to push the bar up will drive them down. The feet should be moved to a slightly wider stance, with the knees partially bent.$x$,$x$Receive the bar with the arms locked out overhead.$x$,$x$Return to a standing position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Power_Jerk/0.jpg$x$),
($x$Power Partials$x$,'shoulders','{}','dumbbell','strength',ARRAY[$x$Stand up with your torso upright and a dumbbell on each hand being held at arms length. The elbows should be close to the torso.$x$,$x$The palms of the hands should be facing your torso. Your feet should be about shoulder width apart. This will be your starting position.$x$,$x$Keeping your arms straight and the torso stationary, lift the weights out to your sides until they are about shoulder level height while exhaling.$x$,$x$Feel the contraction for a second and begin to lower the weights back down to the starting position while inhaling. Tip: Keep the palms facing down with the little finger slightly higher while lifting and lowering the weights as it will concentrate the stress on your shoulders mainly.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Power_Partials/0.jpg$x$),
($x$Power Snatch from Blocks$x$,'quadriceps','{calves,forearms,glutes,hamstrings,back,shoulders,triceps}','barbell','olympic',ARRAY[$x$Begin with a loaded barbell on boxes or stands of the desired height. A wide grip should be taken on the bar. The feet should be directly below the hips, with the feet turned out as needed. Lower the hips, with the chest up and the head looking forward. The shoulders should be just in front of the bar, with the elbows pointed out. This will be the starting position.$x$,$x$Begin the first pull by driving through the front of the heels, raising the bar from the boxes.$x$,$x$Transition into the second pull by extending through the hips knees and ankles, driving the bar up as quickly as possible. The bar should be close to the body. At peak extension, shrug the shoulders and allow the elbows to flex to the side.$x$,$x$As you move your feet into the receiving position, forcefully pull yourself below the bar as you elevate the bar overhead. The feet should move to just outside the hips, turned out as necessary. Receive the bar above a full squat and with the arms fully extended overhead.$x$,$x$Keeping the bar aligned over the front of the heels, your head and chest up, drive through heels of the feet to move to a standing position. Carefully return the weight to the boxes.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Power_Snatch_from_Blocks/0.jpg$x$),
($x$Power Stairs$x$,'hamstrings','{quadriceps,calves,glutes,back,shoulders}','other','strength',ARRAY[$x$In the power stairs, implements are moved up a staircase. For training purposes, these can be performed with a tire or box.$x$,$x$Begin by taking the implement with both hands. Set your feet wide, with your head and chest up. Drive through the ground with your heels, extending your knees and hips to raise the weight from the ground.$x$,$x$As you lean back, attempt to swing the weight onto the stairs, which are usually around 16-18" high. You can use your legs to help push the weight onto the stair.$x$,$x$Repeat for 3-5 repetitions, and continue with a heavier weight, moving as fast as possible.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Power_Stairs/0.jpg$x$),
($x$Press Sit-Up$x$,'core','{chest,shoulders,triceps}','barbell','strength',ARRAY[$x$To begin, lie down on a bench with a barbell resting on your chest. Position your legs so they are secure on the extension of the abdominal bench. This is the starting position.$x$,$x$While inhaling, tighten your abdominals and glutes. Simultaneously curl your torso as you do when performing a sit-up and press the barbell to an overhead position while exhaling. Tip: Use your arms to push the barbell out as you perform this exercise while still focusing on the abdominal muscles.$x$,$x$Lower your upper body back down to the starting position while bringing the barbell back down to your torso. Remember to breathe in while lowering the body.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Press_Sit-Up/0.jpg$x$),
($x$Prone Manual Hamstring$x$,'hamstrings','{}','other','strength',ARRAY[$x$You will need a partner for this exercise. Lay face down with your legs straight. Your assistant will place their hand on your heel.$x$,$x$To begin, flex the knee to curl your leg up. Your partner should provide resistance, starting light and increasing the pressure as the movement is completed. Communicate with your partner to monitor appropriate resistance levels.$x$,$x$Pause at the top, returning the leg to the starting position as your partner provides resistance going the other direction.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Prone_Manual_Hamstring/0.jpg$x$),
($x$Prowler Sprint$x$,'hamstrings','{calves,chest,glutes,quadriceps,shoulders}','other','cardio',ARRAY[$x$Place your sled on an appropriate surface, loaded to a suitable weight. The sled should provide enough resistance to require effort, but not so heavy that you are significantly slowed down.$x$,$x$You may use the upright or the low handles for this exercise. Place your hands on the handles with your arms extended, leaning into the implement.$x$,$x$With good posture, drive through the ground with alternating, short steps. Move as fast as you can for a short distance.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Prowler_Sprint/0.jpg$x$),
($x$Push-Up Wide$x$,'chest','{core,shoulders,triceps}','bodyweight','bodyweight',ARRAY[$x$With your hands wide apart, support your body on your toes and hands in a plank position. Your elbows should be extended and your body straight. Do not allow your hips to sag. This will be your starting position.$x$,$x$To begin, allow the elbows to flex, lowering your chest to the floor as you inhale.$x$,$x$Using your pectoral muscles, press your upper body back up to the starting position by extending the elbows. Exhale as you perform this step.$x$,$x$After pausing at the contracted position, repeat the movement for the prescribed amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Push-Up_Wide/0.jpg$x$),
($x$Push Up to Side Plank$x$,'chest','{core,shoulders,triceps}','bodyweight','bodyweight',ARRAY[$x$Get into pushup position on the toes with your hands just outside of shoulder width.$x$,$x$Perform a pushup by allowing the elbows to flex. As you descend, keep your body straight.$x$,$x$Do one pushup and as you come up, shift your weight on the left side of the body, twist to the side while bringing the right arm up towards the ceiling in a side plank.$x$,$x$Lower the arm back to the floor for another pushup and then twist to the other side.$x$,$x$Repeat the series, alternating each side, for 10 or more reps.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Push_Up_to_Side_Plank/0.jpg$x$),
($x$Quick Leap$x$,'quadriceps','{calves,hamstrings}','other','strength',ARRAY[$x$You will need a box for this exerise.$x$,$x$Begin facing the box standing 1-2 feet from its edge.$x$,$x$By utilizing your hips, hop onto the box, landing on both legs. Ensure that you land with your legs bent and your feet flat.$x$,$x$Immediately upon landing, fully extend through the entire body and swing your arms overhead to explode off of the box. Use your legs to absorb the impact of landing.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Quick_Leap/0.jpg$x$),
($x$Rack Delivery$x$,'shoulders','{forearms,back}','barbell','olympic',ARRAY[$x$This drill teaches the delivery of the barbell to the rack position on the shoulders. Begin holding a bar in the scarecrow position, with the upper arms parallel to the floor, and the forearms hanging down. Use a hook grip, with your fingers wrapped over your thumbs.$x$,$x$Begin by rotating the elbows around the bar, delivering the bar to the shoulders. As your elbows come forward, relax your grip. The shoulders should be protracted, providing a shelf for the bar, which should lightly contact the throat.$x$,$x$It is important that the bar stay close to the body at all times, as with a heavier load any distance will result in an unwanted collision. As the movement becomes smoother, speed and load can be increased before progressing further.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Rack_Delivery/0.jpg$x$),
($x$Recumbent Bike$x$,'quadriceps','{calves,glutes,hamstrings}','machine','cardio',ARRAY[$x$To begin, seat yourself on the bike and adjust the seat to your height.$x$,$x$Select the desired option from the menu. You may have to start pedaling to turn it on. You can use the manual setting, or you can select a program to use. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. The level of resistance can be changed throughout the workout. The handles can be used to monitor your heart rate to help you stay at an appropriate intensity.$x$,$x$Recumbent bikes offer convenience, cardiovascular benefits, and have less impact than other activities. A 150 lb person will burn about 230 calories cycling at a moderate rate for 30 minutes, compared to 450 calories or more running.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Recumbent_Bike/0.jpg$x$),
($x$Return Push from Stance$x$,'shoulders','{chest,triceps}','other','strength',ARRAY[$x$You will need a partner for this drill.$x$,$x$Begin in an athletic 2 or 3 point stance.$x$,$x$At the signal, move into a position to receive the pass from your partner.$x$,$x$Catch the medicine ball with both hands and immediately throw it back to your partner.$x$,$x$You can modify this drill by running different routes.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Return_Push_from_Stance/0.jpg$x$),
($x$Reverse Band Bench Press$x$,'triceps','{chest,forearms,back,shoulders}','barbell','strength',ARRAY[$x$Position a bench inside a power rack, with the bar set to the correct height. Begin by anchoring bands either to band pegs or to the top of the rack. Ensure that you will be position properly under the bands. Attach the other end to the barbell.$x$,$x$Lie on the bench, tuck your feet underneath you and arch your back. Using the bar to help support your weight, lift your shoulder off the bench and retract them, squeezing the shoulder blades together. Use your feet to drive your traps into the bench. Maintain this tight body position throughout the movement. However wide your grip, it should cover the ring on the bar.$x$,$x$Pull the bar out of the rack without protracting your shoulders. Focus on squeezing the bar and trying to pull it apart. Lower the bar to your lower chest or upper stomach. The bar, wrist, and elbow should stay in line at all times.$x$,$x$Pause when the barbell touches your torso, and then drive the bar up with as much force as possible. The elbows should be tucked in until lockout.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Reverse_Band_Bench_Press/0.jpg$x$),
($x$Reverse Band Power Squat$x$,'quadriceps','{calves,glutes,hamstrings,back}','barbell','strength',ARRAY[$x$Begin in a power rack with the pins and bar set at the appropriate height. After loading the bar, attach bands to the top of the rack, using either pegs or the frame itself. Attach the other end of the bands to the bar.$x$,$x$Begin by stepping under the bar and placing it across the back of the shoulders. Squeeze your shoulder blades together and rotate your elbows forward, attempting to bend the bar across your shoulders. Remove the bar from the rack, creating a tight arch in your lower back, and step back into position. Place your feet wide for more emphasis on the back, glutes, adductors, and hamstrings.$x$,$x$Keep your head facing forward. With your back, shoulders, and core tight, push your knees and butt out and you begin your descent. Sit back with your hips as much as possible. Ideally, your shins should be perpendicular to the ground. Lower bar position necessitates a greater torso lean to keep the bar over the heels. Continue until you break parallel, which is defined as the crease of the hip being in line with the top of the knee.$x$,$x$Keeping the weight on your heels and pushing your feet and knees out, drive upward as you lead the movement with your head. Continue upward, maintaining tightness head to toe, until you have returned to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Reverse_Band_Power_Squat/0.jpg$x$),
($x$Reverse Band Sumo Deadlift$x$,'hamstrings','{glutes,quadriceps,calves,forearms,back}','barbell','strength',ARRAY[$x$Begin with a bar loaded on the floor inside of a power rack. Attach bands to the top of the rack, using either pegs or the frame itself. Attach the other end to the barbell.$x$,$x$Approach the bar so that the bar intersects the middle of the feet. The feet should be set very wide, near the collars. Bend at the hips to grip the bar. The arms should be directly below the shoulders, inside the legs, and you can use a pronated grip, a mixed grip, or hook grip. Relax the shoulders, which in effect lengthens your arms.$x$,$x$Take a breath, and then lower your hips, looking forward with your head with your chest up. Drive through the floor, spreading your feet apart, with your weight on the back half of your feet. Extend through the hips and knees.$x$,$x$As the bar passes through the knees, lean back and drive the hips into the bar, pulling your shoulder blades together.$x$,$x$Return the weight to the ground by bending at the hips and controlling the weight on the way down.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Reverse_Band_Sumo_Deadlift/0.jpg$x$),
($x$Reverse Flyes$x$,'shoulders','{}','dumbbell','strength',ARRAY[$x$To begin, lie down on an incline bench with the chest and stomach pressing against the incline. Have the dumbbells in each hand with the palms facing each other (neutral grip).$x$,$x$Extend the arms in front of you so that they are perpendicular to the angle of the bench. The legs should be stationary while applying pressure with the ball of your toes. This is the starting position.$x$,$x$Maintaining the slight bend of the elbows, move the weights out and away from each other (to the side) in an arc motion while exhaling. Tip: Try to squeeze your shoulder blades together to get the best results from this exercise.$x$,$x$The arms should be elevated until they are parallel to the floor.$x$,$x$Feel the contraction and slowly lower the weights back down to the starting position while inhaling.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Reverse_Flyes/0.jpg$x$),
($x$Reverse Flyes With External Rotation$x$,'shoulders','{}','dumbbell','strength',ARRAY[$x$To begin, lie down on an incline bench set at a 30-degree angle with the chest and stomach pressing against the incline.$x$,$x$Have the dumbbells in each hand with the palms facing down to the floor. Your arms should be in front of you so that they are perpendicular to the angle of the bench. Tip: Your elbows should have a slight bend. The legs should be stationary while applying pressure with the ball of your toes (your heels should not be touching the floor). This is the starting position.$x$,$x$Maintaining the slight bend of the elbows, move the weights out and away from each other in an arc motion while exhaling.$x$,$x$As you lift the weight, your wrist should externally rotate by 90-degrees so that you go from a palms down (pronated) grip to a palms facing each other (neutral) grip. Tip: Try to squeeze your shoulder blades together to get the best results from this exercise.$x$,$x$The arms should be elevated until they are level with the head.$x$,$x$Feel the contraction and slowly lower the weights back down to the starting position while inhaling.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Reverse_Flyes_With_External_Rotation/0.jpg$x$),
($x$Reverse Grip Bent-Over Rows$x$,'back','{biceps,shoulders}','barbell','strength',ARRAY[$x$Stand erect while holding a barbell with a supinated grip (palms facing up).$x$,$x$Bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up. The barbell should hang directly in front of you as your arms hang perpendicular to the floor and your torso. This is your starting position.$x$,$x$While keeping the torso stationary, lift the barbell as you breathe out, keeping the elbows close to the body and not doing any force with the forearm other than holding the weights. On the top contracted position, squeeze the back muscles and hold for a second.$x$,$x$Slowly lower the weight again to the starting position as you inhale.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Reverse_Grip_Bent-Over_Rows/0.jpg$x$),
($x$Reverse Grip Triceps Pushdown$x$,'triceps','{}','cable','strength',ARRAY[$x$Start by setting a bar attachment (straight or e-z) on a high pulley machine.$x$,$x$Facing the bar attachment, grab it with the palms facing up (supinated grip) at shoulder width. Lower the bar by using your lats until your arms are fully extended by your sides. Tip: Elbows should be in by your sides and your feet should be shoulder width apart from each other. This is the starting position.$x$,$x$Slowly elevate the bar attachment up as you inhale so it is aligned with your chest. Only the forearms should move and the elbows/upper arms should be stationary by your side at all times.$x$,$x$Then begin to lower the cable bar back down to the original staring position while exhaling and contracting the triceps hard.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Reverse_Grip_Triceps_Pushdown/0.jpg$x$),
($x$Reverse Hyperextension$x$,'hamstrings','{calves,glutes}','machine','strength',ARRAY[$x$Place your feet between the pads after loading an appropriate weight. Lay on the top pad, allowing your hips to hang off the back, while grasping the handles to hold your position.$x$,$x$To begin the movement, flex the hips, pulling the legs forward.$x$,$x$Reverse the motion by extending the hips, kicking the leg back. It is very important not to over-extend the hip on this movement, stopping short of your full range of motion.$x$,$x$Return by again flexing the hip, pulling the carriage forward as far as you can.$x$,$x$Repeat for the desired number of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Reverse_Hyperextension/0.jpg$x$),
($x$Reverse Plate Curls$x$,'biceps','{forearms}','other','strength',ARRAY[$x$Start by standing straight with a weighted plate held by both hands and arms fully extended. Use a pronated grip (palms facing down) and make sure your fingers grab the rough side of the plate while your thumb grabs the smooth side. Note: For the best results, grab the weighted plate at an 11:00 and 1:00 o'clock position.$x$,$x$Your feet should be shoulder width apart from each other and the weighted plate should be near the groin area. This is the starting position.$x$,$x$Slowly lift the plate up while keeping the elbows in and the upper arms stationary until your biceps and forearms touch while exhaling. The plate should be evenly aligned with your torso at this point.$x$,$x$Feel the contraction for a second and begin to lower the weight back down to the starting position while inhaling$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Reverse_Plate_Curls/0.jpg$x$),
($x$Reverse Triceps Bench Press$x$,'triceps','{chest,shoulders}','barbell','strength',ARRAY[$x$Lie back on a flat bench. Using a close, supinated grip (around shoulder width), lift the bar from the rack and hold it straight over you with your arms locked extended in front of you and perpendicular to the floor. This will be your starting position.$x$,$x$As you breathe in, come down slowly until you feel the bar on your middle chest. Tip: Make sure that as opposed to a regular bench press, you keep the elbows close to the torso at all times in order to maximize triceps involvement.$x$,$x$After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your triceps muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up.$x$,$x$Repeat the movement for the prescribed amount of repetitions.$x$,$x$When you are done, place the bar back in the rack.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Reverse_Triceps_Bench_Press/0.jpg$x$),
($x$Rickshaw Carry$x$,'forearms','{core,calves,glutes,hamstrings,back,quadriceps}','other','strength',ARRAY[$x$Position the frame at the starting point, and load with the appropriate weight. Standing in the center of the frame, begin by gripping the handles and driving through your heels to lift the frame. Ensure your chest and head are up and your back is straight.$x$,$x$Immediately begin walking briskly with quick, controlled steps. Keep your chest up and head forward, and make sure you continue breathing. Bring the frame to the ground after you have reached the end point.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Rickshaw_Carry/0.jpg$x$),
($x$Rickshaw Deadlift$x$,'quadriceps','{forearms,glutes,hamstrings,back}','other','strength',ARRAY[$x$Load the frame with the desired weight. Center yourself between the handles. You feet should be about hip width apart. Bend at the hips to grip the handles, allowing your shoulder blades to protract.$x$,$x$With your feet and your grip set, take a big breath and then lower your hips and flex the knees. Look forward with your head, keep your chest up and your back arched, and begin driving through the heels to move the weight upward. As the weight comes up, pull your shoulder blades together as you drive your hips forward.$x$,$x$Lower the weight by bending at the hips and guiding it to the ground.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Rickshaw_Deadlift/0.jpg$x$),
($x$Ring Dips$x$,'triceps','{chest,shoulders}','other','strength',ARRAY[$x$Grip a ring in each hand, and then take a small jump to help you get into the starting position with your arms locked out.$x$,$x$Begin by flexing the elbow, lowering your body until your arms break 90 degrees. Avoid swinging, and maintain good posture throughout the descent.$x$,$x$Reverse the motion by extending the elbow, pushing yourself back up into the starting position.$x$,$x$Repeat for the desired number of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Ring_Dips/0.jpg$x$),
($x$Rocket Jump$x$,'quadriceps','{calves,hamstrings}','bodyweight','bodyweight',ARRAY[$x$Begin in a relaxed stance with your feet shoulder width apart and hold your arms close to the body.$x$,$x$To initiate the move, squat down halfway and explode back up as high as possible.$x$,$x$Fully extend your entire body, reaching overhead as far as possible. As you land, absorb your impact through the legs.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Rocket_Jump/0.jpg$x$)
) as v(name,mg,sm,eq,et,ins,img)
where not exists (select 1 from exercises e where lower(e.name)=lower(v.name));

insert into exercises (name,muscle_group,secondary_muscles,equipment,exercise_type,instructions,image_url,is_custom,user_id)
select v.name,v.mg::muscle_group,v.sm::muscle_group[],v.eq::equipment_type,v.et::exercise_type,v.ins::text[],v.img,false,null
from (values
($x$Romanian Deadlift from Deficit$x$,'hamstrings','{forearms,glutes,back}','barbell','olympic',ARRAY[$x$Begin standing while holding a bar at arm's length in front of you. You can stand on a raised platform to increase the range of motion.$x$,$x$Begin by flexing the knees slightly, and then flex at the hip, moving your butt back as far as possible, lowering the torso as far as flexibility allows. The back should remain in absolute extension at all times, and the bar should remain in contact with the legs. If done properly, there should be heavy tension felt in the hamstrings.$x$,$x$Reverse the motion to return to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Romanian_Deadlift_from_Deficit/0.jpg$x$),
($x$Rope Climb$x$,'back','{biceps,forearms,shoulders}','other','strength',ARRAY[$x$Grab the rope with both hands above your head. Pull down on the rope as you take a small jump.$x$,$x$Wrap the rope around one leg, using your feet to pinch the rope. Reach up as high as possible with your arms, gripping the rope tightly.$x$,$x$Release the rope from your feet as you pull yourself up with your arms, bringing your knees towards your chest.$x$,$x$Resecure your feet on the rope, and then stand up to take another high hold on the rope. Continue until you reach the top of the rope.$x$,$x$To lower yourself, loosen the grip of your feet on the rope as you slide down using a hand over hand motion.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Rope_Climb/0.jpg$x$),
($x$Rope Crunch$x$,'core','{}','cable','strength',ARRAY[$x$Kneel 1-2 feet in front of a cable system with a rope attached.$x$,$x$After selecting an appropriate weight, grasp the rope with both hands reaching overhead. Your torso should be upright in the starting position.$x$,$x$To begin, flex at the spine, attempting to bring your rib cage to your legs as you pull the cable down.$x$,$x$Pause at the bottom of the motion, and then slowly return to the starting position.$x$,$x$These can be done with twists or to the side to hit the obliques.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Rope_Crunch/0.jpg$x$),
($x$Rope Jumping$x$,'quadriceps','{calves,hamstrings}','other','cardio',ARRAY[$x$Hold an end of the rope in each hand. Position the rope behind you on the ground. Raise your arms up and turn the rope over your head bringing it down in front of you. When it reaches the ground, jump over it. Find a good turning pace that can be maintained. Different speeds and techniques can be used to introduce variation.$x$,$x$Rope jumping is exciting, challenges your coordination, and requires a lot of energy. A 150 lb person will burn about 350 calories jumping rope for 30 minutes, compared to over 450 calories running.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Rope_Jumping/0.jpg$x$),
($x$Rowing, Stationary$x$,'quadriceps','{biceps,calves,glutes,hamstrings,back}','machine','cardio',ARRAY[$x$To begin, seat yourself on the rower. Make sure that your heels are resting comfortably against the base of the foot pedals and that the straps are secured. Select the program that you wish to use, if applicable. Sit up straight and bend forward at the hips.$x$,$x$There are three phases of movement when using a rower. The first phase is when you come forward on the rower. Your knees are bent and against your chest. Your upper body is leaning slightly forward while still maintaining good posture. Next, push against the foot pedals and extend your legs while bringing your hands to your upper abdominal area, squeezing your shoulders back as you do so. To avoid straining your back, use primarily your leg and hip muscles.$x$,$x$The recovery phase simply involves straightening your arms, bending the knees, and bringing your body forward again as you transition back into the first phase.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Rowing_Stationary/0.jpg$x$),
($x$Running, Treadmill$x$,'quadriceps','{calves,glutes,hamstrings}','machine','cardio',ARRAY[$x$To begin, step onto the treadmill and select the desired option from the menu. Most treadmills have a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. Elevation can be adjusted to change the intensity of the workout.$x$,$x$Treadmills offer convenience, cardiovascular benefits, and usually have less impact than running outside. A 150 lb person will burn over 450 calories running 8 miles per hour for 30 minutes. Maintain proper posture as you run, and only hold onto the handles when necessary, such as when dismounting or checking your heart rate.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Running_Treadmill/0.jpg$x$),
($x$Sandbag Load$x$,'quadriceps','{core,biceps,calves,forearms,glutes,hamstrings,back,shoulders}','other','strength',ARRAY[$x$To load sandbags or other objects, begin with the implements placed a distance from the loading platform, typically 50 feet.$x$,$x$Begin by lifting the sandbag. Sandbags are extremely awkward, and the manner of lifting them can vary depending on the particular sandbag used. Reach as far around it as possible, extending through the hips and knees to pull it up high. Shouldering is usually not allowed.$x$,$x$Move as quickly as possible to the platform, and load it, extending through your hips, knees, and ankles to get it as high as possible. Place it onto the platform, ensuring it doesn't fall off.$x$,$x$Return to the starting position to retrieve the next sandbag, and repeat until the event is completed.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Sandbag_Load/0.jpg$x$),
($x$Scapular Pull-Up$x$,'back','{}','other','strength',ARRAY[$x$Take a pronated grip on a pull-up bar.$x$,$x$From a hanging position, raise yourself a few inches without using your arms. Do this by depressing your shoulder girdle in a reverse shrugging motion.$x$,$x$Pause at the completion of the movement, and then slowly return to the starting position before performing more repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Scapular_Pull-Up/0.jpg$x$),
($x$Scissors Jump$x$,'quadriceps','{glutes,hamstrings}','bodyweight','bodyweight',ARRAY[$x$Assume a lunge stance position with one foot forward with the knee bent, and the rear knee nearly touching the ground.$x$,$x$Ensure that the front knee is over the midline of the foot. Extending through both legs, jump as high as possible, swinging your arms to gain lift.$x$,$x$As you jump as high as you can, switch the position of your legs, moving your front leg to the back and the rear leg to the front.$x$,$x$As you land, absorb the impact through the legs by adopting the lunge position, and repeat.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Scissors_Jump/0.jpg$x$),
($x$Seated Barbell Twist$x$,'core','{}','barbell','strength',ARRAY[$x$Start out by sitting at the end of a flat bench with a barbell placed on top of your thighs. Your feet should be shoulder width apart from each other.$x$,$x$Grip the bar with your palms facing down and make sure your hands are wider than shoulder width apart from each other. Begin to lift the barbell up over your head until your arms are fully extended.$x$,$x$Now lower the barbell behind your head until it is resting along the base of your neck. This is the starting position.$x$,$x$While keeping your feet and head stationary, move your waist from side to side so that your oblique muscles feel the contraction. Only move from side to side as far as your waist will allow you to go. Stretching or moving too far can cause an injury to occur. Tip: Use a slow and controlled motion.$x$,$x$Remember to breathe out while twisting your body to the side and in when moving back to the starting position.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Seated_Barbell_Twist/0.jpg$x$),
($x$Seated Bent-Over One-Arm Dumbbell Triceps Extension$x$,'triceps','{}','dumbbell','strength',ARRAY[$x$Sit down at the end of a flat bench with a dumbbell in one arm using a neutral grip (palms of the hand facing you).$x$,$x$Bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Make sure that you keep the head up.$x$,$x$The upper arm with the dumbbell should be close to the torso and aligned with it (lifted up until it is parallel to the floor while the forearms are pointing towards the floor as the hands hold the weights). Tip: There should be a 90-degree angle between the forearms and the upper arm. This is your starting position.$x$,$x$Keeping the upper arm stationary, use the triceps to lift the weight as you exhale until the forearm is parallel to the floor and the whole arm is extended. Like many other arm exercises, only the forearm moves.$x$,$x$After a second contraction at the top, slowly lower the dumbbell back to the starting position as you inhale.$x$,$x$Repeat the movement for the prescribed amount of repetitions.$x$,$x$Switch arms and repeat the exercise.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Seated_Bent-Over_One-Arm_Dumbbell_Triceps_Extension/0.jpg$x$),
($x$Seated Bent-Over Rear Delt Raise$x$,'shoulders','{}','dumbbell','strength',ARRAY[$x$Place a couple of dumbbells looking forward in front of a flat bench.$x$,$x$Sit on the end of the bench with your legs together and the dumbbells behind your calves.$x$,$x$Bend at the waist while keeping the back straight in order to pick up the dumbbells. The palms of your hands should be facing each other as you pick them. This will be your starting position.$x$,$x$Keeping your torso forward and stationary, and the arms slightly bent at the elbows, lift the dumbbells straight to the side until both arms are parallel to the floor. Exhale as you lift the weights. (Note: avoid swinging the torso or bringing the arms back as opposed to the side.)$x$,$x$After a one second contraction at the top, slowly lower the dumbbells back to the starting position.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Seated_Bent-Over_Rear_Delt_Raise/0.jpg$x$),
($x$Seated Bent-Over Two-Arm Dumbbell Triceps Extension$x$,'triceps','{}','dumbbell','strength',ARRAY[$x$Sit down at the end of a flat bench with a dumbbell in both arms using a neutral grip (palms of the hand facing you).$x$,$x$Bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Make sure that you keep the head up.$x$,$x$The upper arms with the dumbbells should be close to the torso and aligned with it (lifted up until they are parallel to the floor while the forearms are pointing towards the floor as the hands hold the weights). Tip: There should be a 90-degree angle between the forearms and the upper arm. This is your starting position.$x$,$x$Keeping the upper arms stationary, use the triceps to lift the weight as you exhale until the forearms are parallel to the floor and the whole arm is extended. Like many other arm exercises, only the forearm moves.$x$,$x$After a second contraction at the top, slowly lower the dumbbells back to the starting position as you inhale.$x$,$x$Repeat the movement for the prescribed amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Seated_Bent-Over_Two-Arm_Dumbbell_Triceps_Extension/0.jpg$x$),
($x$Seated Dumbbell Inner Biceps Curl$x$,'biceps','{}','dumbbell','strength',ARRAY[$x$Sit on the end of a flat bench with a dumbbell in each hand being held at arms length. The elbows should be close to the torso.$x$,$x$Rotate the palms of the hands so that they are facing inward in a neutral position. This will be your starting position.$x$,$x$While holding the upper arms stationary, curl the dumbbells out and up, turning the palms out as you lift and keeping your forearms in line with your outer deltoids. Tips:$x$,$x$Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps.$x$,$x$Slowly begin to bring the dumbbells back to the starting position as your breathe in. Remember to rotate your arms as you lower the dumbbells so that you can switch back to a neutral grip.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Seated_Dumbbell_Inner_Biceps_Curl/0.jpg$x$),
($x$Seated Head Harness Neck Resistance$x$,'shoulders','{}','other','strength',ARRAY[$x$Place a neck strap on the floor at the end of a flat bench. Once you have selected the weights, sit at the end of the flat bench with your feet wider than shoulder width apart from each other. Your toes should be pointed out.$x$,$x$Slowly move your torso forward until it is almost parallel with the floor. Using both hands, securely position the neck strap around your head. Tip: Make sure the weights are still lying on the floor to prevent any strain on the neck. Now grab the weight with both hands while elevating your torso back until it is almost perpendicular to the floor. Note: Your head and torso needs to be slightly tilted forward to perform this exercise.$x$,$x$Now place both hands on top of your knees. This is the starting position.$x$,$x$Slowly lower your neck down until your chin touches the upper part of your chest while breathing in.$x$,$x$While exhaling, bring your neck back to the starting position.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Seated_Head_Harness_Neck_Resistance/0.jpg$x$),
($x$Seated Leg Tucks$x$,'core','{}','bodyweight','bodyweight',ARRAY[$x$Sit on a bench with the legs stretched out in front of you slightly below parallel and your arms holding on to the sides of the bench. Your torso should be leaning backwards around a 45-degree angle from the bench. This will be your starting position.$x$,$x$Bring the knees in toward you as you move your torso closer to them at the same time. Breathe out as you perform this movement.$x$,$x$After a second pause, go back to the starting position as you inhale.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Seated_Leg_Tucks/0.jpg$x$),
($x$Seated One-arm Cable Pulley Rows$x$,'back','{biceps}','cable','strength',ARRAY[$x$To get into the starting position, first sit down on the machine and place your feet on the front platform or crossbar provided making sure that your knees are slightly bent and not locked.$x$,$x$Lean over as you keep the natural alignment of your back and grab the single handle attachment with your left arm using a palms-down grip.$x$,$x$With your arm extended pull back until your torso is at a 90-degree angle from your legs. Your back should be slightly arched and your chest should be sticking out. You should be feeling a nice stretch on your lat as you hold the bar in front of you. The right arm can be kept by the waist. This is the starting position of the exercise.$x$,$x$Keeping the torso stationary, pull the handles back towards your torso while keeping the arms close to it as you rotate the wrist, so that by the time your hand is by your abdominals it is in a neutral position (palms facing the torso). Breathe out as you perform that movement. At that point you should be squeezing your back muscles hard.$x$,$x$Hold that contraction for a second and slowly go back to the original position while breathing in. Tip: Remember to rotate the wrist as you go back to the starting position so that the palms are facing down again.$x$,$x$Repeat for the recommended amount of repetitions and then perform the same movement with the right hand.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Seated_One-arm_Cable_Pulley_Rows/0.jpg$x$),
($x$Seated Side Lateral Raise$x$,'shoulders','{}','dumbbell','strength',ARRAY[$x$Pick a couple of dumbbells and sit at the end of a flat bench with your feet firmly on the floor. Hold the dumbbells with your palms facing in and your arms straight down at your sides at arms' length. This will be your starting position.$x$,$x$While maintaining the torso stationary (no swinging), lift the dumbbells to your side with a slight bend on the elbow and the hands slightly tilted forward as if pouring water in a glass. Continue to go up until you arms are parallel to the floor. Exhale as you execute this movement and pause for a second at the top.$x$,$x$Lower the dumbbells back down slowly to the starting position as you inhale.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Seated_Side_Lateral_Raise/0.jpg$x$),
($x$Shotgun Row$x$,'back','{biceps}','cable','strength',ARRAY[$x$Attach a single handle to a low cable.$x$,$x$After selecting the correct weight, stand a couple feet back with a wide-split stance. Your arm should be extended and your shoulder forward. This will be your starting position.$x$,$x$Perform the movement by retracting the shoulder and flexing the elbow. As you pull, supinate the wrist, turning the palm upward as you go.$x$,$x$After a brief pause, return to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Shotgun_Row/0.jpg$x$),
($x$Side Bridge$x$,'core','{shoulders}','bodyweight','bodyweight',ARRAY[]::text[],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Side_Bridge/0.jpg$x$),
($x$Side Hop-Sprint$x$,'quadriceps','{glutes,calves,hamstrings}','other','strength',ARRAY[$x$Stand to the side of a cone or hurdle.$x$,$x$Begin this drill by hopping sideways over the obstacle, rebounding out of your landing to hop back to where you started.$x$,$x$Hop for a prescribed number or repetitions as quickly as possible, and finish this drill by sprinting a short distance upon landing the last hop.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Side_Hop-Sprint/0.jpg$x$),
($x$Side Jackknife$x$,'core','{}','bodyweight','bodyweight',ARRAY[]::text[],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Side_Jackknife/0.jpg$x$),
($x$Side Laterals to Front Raise$x$,'shoulders','{back}','dumbbell','strength',ARRAY[$x$In a standing position, hold a pair of dumbbells at your side. This will be your starting position.$x$,$x$Keeping your elbows slightly bent, raise the weights directly in front of you to shoulder height, avoiding any swinging or cheating.$x$,$x$At the top of the exercise move the weights out in front of you, keeping your arms extended.$x$,$x$Lower the weights with a controlled motion.$x$,$x$On the next repetition, raise the weights in front of you to shoulder height before moving the weights laterally to your sides.$x$,$x$Lower the weights to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Side_Laterals_to_Front_Raise/0.jpg$x$),
($x$Side Standing Long Jump$x$,'quadriceps','{calves,glutes,hamstrings}','other','strength',ARRAY[$x$Begin standing with your feet hip width apart in an athletic stance. Your head and chest should be up, knees and hips slightly bent. This will be your starting position.$x$,$x$Leaning to your right, extend through your hips, knees, and ankles to jump into the air. Block with the arms to lead the movement, jumping as far to your right as you can.$x$,$x$Land facing the same direction with your feet hip width apart, absorbing the impact through your lower body.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Side_Standing_Long_Jump/0.jpg$x$),
($x$Side To Side Chins$x$,'back','{biceps,forearms,shoulders}','other','strength',ARRAY[$x$Grab the pull-up bar with the palms facing forward using a wide grip.$x$,$x$As you have both arms extended in front of you holding the bar at a wide grip, bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.$x$,$x$Pull your torso up while leaning to the left hand side until the bar almost touches your upper chest by drawing the shoulders and the upper arms down and back. Exhale as you perform this portion of the movement. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary as it moves through space (no swinging) and only the arms should move. The forearms should do no other work other than hold the bar.$x$,$x$After a second of contraction, inhale as you go back to the starting position.$x$,$x$Now, pull your torso up while leaning to the right hand side until the bar almost touches your upper chest by drawing the shoulders and the upper arms down and back. Exhale as you perform this portion of the movement. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.$x$,$x$After a second of contraction, inhale as you go back to the starting position.$x$,$x$Repeat steps 3-6 until you have performed the prescribed amount of repetitions for each side.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Side_To_Side_Chins/0.jpg$x$),
($x$Side to Side Box Shuffle$x$,'quadriceps','{glutes,calves,hamstrings}','other','strength',ARRAY[$x$Stand to one side of the box with your left foot resting on the middle of it.$x$,$x$To begin, jump up and over to the other side of the box, landing with your right foot on top of the box and your left foot on the floor. Swing your arms to aid your movement.$x$,$x$Continue shuffling back and forth across the box.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Side_to_Side_Box_Shuffle/0.jpg$x$),
($x$Single-Arm Linear Jammer$x$,'shoulders','{chest,triceps}','barbell','strength',ARRAY[$x$Position a bar into a landmine or securely anchor it in a corner. Load the bar to an appropriate weight.$x$,$x$Raise the bar from the floor, taking it to your shoulders with one or both hands. Adopt a wide stance. This will be your starting position.$x$,$x$Perform the movement by extending the elbow, pressing the weight up. Move explosively, extending the hips and knees fully to produce maximal force.$x$,$x$Return to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Single-Arm_Linear_Jammer/0.jpg$x$),
($x$Single-Cone Sprint Drill$x$,'quadriceps','{calves,glutes,hamstrings}','other','strength',ARRAY[$x$This drill teaches quick foot action. You need a single cone. Begin standing next to the cone with one arm back and one arm forward.$x$,$x$Chop the feet as quickly as possible, blocking with the arms. Circle the cone, keep your knees up, with violent foot action.$x$,$x$Rest after three trips around the cone.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Single-Cone_Sprint_Drill/0.jpg$x$),
($x$Single-Leg Hop Progression$x$,'quadriceps','{glutes,calves,hamstrings}','other','strength',ARRAY[$x$Arrange a line of cones in front of you. Assume a relaxed standing position, balanced on one leg. Raise the knee of your opposite leg. This will be your starting position.$x$,$x$Hop forward, jumping and landing with the same leg over the cone.$x$,$x$Use a countermovement jump to hop from cone to cone.$x$,$x$At the end, turn around and go back on the other leg.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Single-Leg_Hop_Progression/0.jpg$x$),
($x$Single-Leg Lateral Hop$x$,'quadriceps','{glutes,calves,hamstrings}','other','strength',ARRAY[$x$Stand to the side of a cone or hurdle. To get into the start position, stand on one leg with your knee slightly bent.$x$,$x$To begin, execute a counterjump to hop sideways over the cone.$x$,$x$Land on your jumping leg, and immediately rebound out of it by jumping back to the start position.$x$,$x$Continue hopping back and forth.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Single-Leg_Lateral_Hop/0.jpg$x$),
($x$Single-Leg Stride Jump$x$,'quadriceps','{glutes,calves,hamstrings}','other','strength',ARRAY[$x$Stand to the side of a box with your inside foot on top of it, close to the edge.$x$,$x$Begin by swinging the arms upward as you push through the top leg, jumping upward as high as possible. Attempt to drive the opposite knee upward.$x$,$x$Land in the same position that you started, using your inside leg to decelerate the impact.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Single-Leg_Stride_Jump/0.jpg$x$),
($x$Single Leg Butt Kick$x$,'quadriceps','{calves,hamstrings}','bodyweight','bodyweight',ARRAY[$x$Begin by standing on one leg, with the bent knee raised. This will be your start position.$x$,$x$Using a countermovement jump, take off upward by extending the hip, knee, and ankle of the grounded leg.$x$,$x$Immediately flex the knee and attempt to touch your butt with the heel of your jumping leg.$x$,$x$Return the leg to a partially bent position underneath the hips and land. Your opposite leg should stay in relatively the same position throughout the drill.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Single_Leg_Butt_Kick/0.jpg$x$),
($x$Single Leg Push-off$x$,'quadriceps','{calves,hamstrings}','other','strength',ARRAY[$x$Stand on the ground with one foot resting on the box, heel close to the edge.$x$,$x$Push off with your foot on top of the box, trying to gain as much height as possible by extending through the hip and knee.$x$,$x$Land with the same foot on top of the box, returning your other foot back to the start position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Single_Leg_Push-off/0.jpg$x$),
($x$Skating$x$,'quadriceps','{glutes,calves,hamstrings}','other','cardio',ARRAY[$x$Roller skating is a fun activity which can be effective in improving cardiorespiratory fitness and muscular endurance. It requires relatively good balance and coordination. It is necessary to learn the basics of skating including turning and stopping and to wear protective gear to avoid possible injury.$x$,$x$You can skate at a comfortable pace for 30 minutes straight. If you want a cardio challenge, do interval skating — speed skate two minutes of every five minutes, using the remaining three minutes to recover. A 150 lb person will typically burn about 175 calories in 30 minutes skating at a comfortable pace, similar to brisk walking.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Skating/0.jpg$x$),
($x$Sled Overhead Backward Walk$x$,'shoulders','{calves,back,quadriceps}','other','strength',ARRAY[$x$Attach dual handles to a sled connected by a rope or chain. Load the sled to a light weight.$x$,$x$Face the sled, backing up until there is some tension in the line. Hold your hands directly above your head with your elbows extended. This will be your starting position.$x$,$x$Walk backwards, keeping your arms raised above your head. Avoid jerky movements.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Sled_Overhead_Backward_Walk/0.jpg$x$),
($x$Sled Overhead Triceps Extension$x$,'triceps','{}','other','strength',ARRAY[$x$Attach dual handles to a sled using a chain or rope. Load the sled to an appropriate load.$x$,$x$Facing away from the sled, step away until there is tension in the line. Raise your hands above your head, keeping them together, palms facing each other. Your elbows should be pointed upward with the elbows flexed. This will be your starting position.$x$,$x$Extend through the elbow to straighten the arm. Ensure that your upper arm stays in position to isolate the triceps.$x$,$x$Upon full extension, step forward to take the slack out of the line. You may keep your feet staggered for more stability.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Sled_Overhead_Triceps_Extension/0.jpg$x$),
($x$Sled Reverse Flye$x$,'shoulders','{}','other','strength',ARRAY[$x$Attach dual handles to a sled connected by a rope or chain. Load the sled to a light weight.$x$,$x$Face the sled, backing up until there is some tension in the line. Take both handles at arms length at about waist level. Bend the knees slightly and keep your chest and head up. This will be your starting position.$x$,$x$Without flexing the elbow, pull the handles upward and apart, performing a reverse fly with some external rotation. Your palms should be facing forward as you do this.$x$,$x$Return to the starting position, taking a couple steps back to take the slack out of the line.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Sled_Reverse_Flye/0.jpg$x$),
($x$Sledgehammer Swings$x$,'core','{calves,forearms,back,shoulders}','other','strength',ARRAY[$x$You will need a tire and a sledgehammer for this exercise. Stand in front of the tire about two feet away from it with a staggered stance. Grip the sledgehammer.$x$,$x$If you are right handed, your left hand should be at the bottom of the handle, and your right hand should be choking up closer to the head.$x$,$x$As you bring the sledge up, your right hand slides toward the head; as you swing down, your right hand will slide down to join your left hand. Slam it down as hard as you can against the tire. Control the bounce of the hammer off of the tire.$x$,$x$Repeat on the other side.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Sledgehammer_Swings/0.jpg$x$),
($x$Smith Machine Bent Over Row$x$,'back','{biceps,shoulders}','machine','strength',ARRAY[$x$Set the barbell attached to the smith machine to a height that is about 2 inches below your knees.$x$,$x$Bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up.$x$,$x$Now grasp the barbell using an overhand (pronated) grip and unlock it from the smith machine rack. Then let it hang directly in front of you as your arms hang extended perpendicular to the floor and your torso. This is your starting position.$x$,$x$While keeping the torso stationary, lift the barbell as you breathe out, keeping the elbows close to the body and not doing any force with the forearm other than holding the weights. On the top contracted position, squeeze the back muscles and hold for a second.$x$,$x$Slowly lower the weight again to the starting position as you inhale.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Smith_Machine_Bent_Over_Row/0.jpg$x$),
($x$Smith Machine Hip Raise$x$,'core','{}','machine','strength',ARRAY[$x$Position a bench in the rack and load the bar to an appropriate weight. Lie down on the bench, placing the bottom of your feet against the bar. Unlock the bar and extend your legs. You may need to use your hands to assist you. For added stability grasp the sides of the Smith Machine. This will be your starting position.$x$,$x$Initiate the movement by rotating your pelvis, flexing your spine to raise your hips off of the bench. Maintain a slight bend in the knees throughout the motion.$x$,$x$After a brief pause, return the hips to the bench.$x$,$x$Repeat for the desired number of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Smith_Machine_Hip_Raise/0.jpg$x$),
($x$Smith Machine Overhead Shoulder Press$x$,'shoulders','{triceps}','machine','strength',ARRAY[$x$To begin, place a flat bench (or preferably one with back support) underneath a smith machine. Position the barbell at a height so that when seated on the flat bench, the arms must be almost fully extended to reach the barbell.$x$,$x$Once you have the correct height, sit slightly in behind the barbell so that there is an imaginary straight line from the tip of your nose to the barbell. Your feet should be stationary. Grab the barbell with the palms facing forward, unlock it and lift it up so that your arms are fully extended. This is the starting position.$x$,$x$Slowly begin to lower the barbell until it is level with your chin while inhaling.$x$,$x$Then lift the barbell back to the starting position using your shoulders while exhaling.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Smith_Machine_Overhead_Shoulder_Press/0.jpg$x$),
($x$Smith Machine Reverse Calf Raises$x$,'calves','{}','machine','strength',ARRAY[$x$Adjust the barbell on the smith machine to fit your height and align a raised platform right under the bar.$x$,$x$Stand on the platform with the heels of your feet secured on top of it with the balls of your feet extending off it. Position your toes facing forward with a shoulder width stance.$x$,$x$Now, place your shoulders under the barbell while maintaining the foot positioning described and push the barbell up by extending your hips and knees until your torso is standing erect. The knees should be kept with a slight bend; never locked. This will be your starting position. Tip: The barbell on your back is only for balance purposes.$x$,$x$Raise the balls of your feet as you breathe out by extending your toes as high as possible and flexing your calf. Ensure that the knee is kept stationary at all times. There should be no bending at any time. Hold the contracted position for a second before you start to go back down.$x$,$x$Slowly go back down to the starting position as you breathe in by lowering the balls of your feet and toes.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Smith_Machine_Reverse_Calf_Raises/0.jpg$x$),
($x$Smith Machine Stiff-Legged Deadlift$x$,'hamstrings','{glutes,back}','machine','strength',ARRAY[$x$To begin, set the bar on the smith machine to a height that is around the middle of your thighs. Once the correct height is chosen and the bar is loaded, grasp the bar using a pronated (palms forward) grip that is shoulder width apart. You may need some wrist wraps if using a significant amount of weight.$x$,$x$Lift the bar up by fully extending your arms while keeping your back straight. Stand with your torso straight and your legs spaced using a shoulder width or narrower stance. The knees should be slightly bent. This is your starting position.$x$,$x$Keeping the knees stationary, lower the barbell to over the top of your feet by bending at the waist while keeping your back straight. Keep moving forward as if you were going to pick something from the floor until you feel a stretch on the hamstrings. Exhale as you perform this movement$x$,$x$Start bringing your torso up straight again as soon as you feel the hamstrings stretch by extending your hips and waist until you are back at the starting position. Inhale as you perform this movement.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Smith_Machine_Stiff-Legged_Deadlift/0.jpg$x$),
($x$Snatch Balance$x$,'quadriceps','{calves,glutes,hamstrings,shoulders,triceps}','barbell','olympic',ARRAY[$x$Begin with the feet in the pulling position, the bar racked across the back of the shoulders, and the hands placed in a wide snatch grip.$x$,$x$Pop the bar with an abrupt dip and drive of the knees, and aggressively drive under the bar, transitioning the feet into the receiving position.$x$,$x$Receive the bar locked out overhead near the bottom of the squat. The torso should remain vertical, lowering the hips between the legs.$x$,$x$Continue to descend to full depth, and return to a standing position. Carefully lower the weight.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Snatch_Balance/0.jpg$x$),
($x$Snatch Shrug$x$,'back','{forearms,shoulders}','barbell','olympic',ARRAY[$x$Begin with a wide grip, with the bar hanging at the mid thigh position. You can use a hook or overhand grip. Your back should be straight and inclined slightly forward.$x$,$x$Shrug your shoulders towards your ears. While this exercise can usually by loaded with heavier weight than a snatch, avoid overloading to the point that the execution slows down.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Snatch_Shrug/0.jpg$x$),
($x$Snatch from Blocks$x$,'quadriceps','{calves,forearms,glutes,hamstrings,back,shoulders,triceps}','barbell','olympic',ARRAY[$x$Begin with a loaded barbell on boxes or stands of the desired height. A wide grip should be taken on the bar. The feet should be directly below the hips, with the feet turned out as needed. Lower the hips, with the chest up and the head looking forward. The shoulders should be just in front of the bar, with the elbows pointed out. This will be the starting position.$x$,$x$Begin the first pull by driving through the front of the heels, raising the bar from the boxes.$x$,$x$Transition into the second pull by extending through the hips knees and ankles, driving the bar up as quickly as possible. The bar should be close to the body. At peak extension, shrug the shoulders and allow the elbows to flex to the side.$x$,$x$As you move your feet into the receiving position, forcefully pull yourself below the bar as you elevate the bar overhead. The feet should move to just outside the hips, turned out as necessary. Receive the bar with your body as low as possible and the arms fully extended overhead.$x$,$x$Keeping the bar aligned over the front of the heels, your head and chest up, drive through heels of the feet to move to a standing position. Carefully return the weight to the boxes.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Snatch_from_Blocks/0.jpg$x$),
($x$Speed Band Overhead Triceps$x$,'triceps','{}','bands','strength',ARRAY[$x$For this exercise anchor a band to the ground. We used an incline bench and anchored the band to the base, standing over the bench. Alternatively, this could be performed standing on the band.$x$,$x$To begin, pull the band behind your head, holding it with a pronated grip and your elbows up. This will be your starting position.$x$,$x$To perform the movement, extend through the elbow to to straighten your arms, ensuring that you keep your upper arm in place.$x$,$x$Pause, and then return to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Speed_Band_Overhead_Triceps/0.jpg$x$),
($x$Speed Squats$x$,'quadriceps','{calves,glutes,hamstrings,back}','barbell','strength',ARRAY[$x$This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.$x$,$x$Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.$x$,$x$Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. This will be your starting position. (Note: For the purposes of this discussion we will use the medium stance which targets overall development; however you can choose any of the three stances discussed in the foot stances section).$x$,$x$Begin to lower the bar by bending the knees as you maintain a straight posture with the head up. Continue down until the angle between the upper leg and the calves becomes slightly less than 90-degrees (which is the point in which the upper legs are below parallel to the floor). Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.$x$,$x$Begin to raise the bar as fast as possible without involving momentum as you exhale by pushing the floor with the heel of your foot mainly as you straighten the legs again and go back to the starting position. Note: You should perform these exercises as fast as possible but without breaking perfect form and without involving momentum.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Speed_Squats/0.jpg$x$),
($x$Spell Caster$x$,'core','{glutes,shoulders}','dumbbell','strength',ARRAY[$x$Hold a dumbbell in each hand with a pronated grip. Your feet should be wide with your hips and knees extended. This will be your starting position.$x$,$x$Begin the movement by pulling both of the dumbbells to one side next to your hip, rotating your torso.$x$,$x$Keeping your arms straight and the dumbbells parallel to the ground, rotate your torso to swing the weights to your opposite side.$x$,$x$Continue alternating, rotating from one side to the other until the set is complete.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Spell_Caster/0.jpg$x$),
($x$Spider Crawl$x$,'core','{chest,shoulders,triceps}','bodyweight','bodyweight',ARRAY[$x$Begin in a prone position on the floor. Support your weight on your hands and toes, with your feet together and your body straight. Your arms should be bent to 90 degrees. This will be your starting position.$x$,$x$Initiate the movement by raising one foot off of the ground. Externally rotate the leg and bring the knee toward your elbow, as far forward as possible.$x$,$x$Return this leg to the starting position and repeat on the opposite side.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Spider_Crawl/0.jpg$x$),
($x$Split Clean$x$,'quadriceps','{calves,forearms,glutes,hamstrings,back,shoulders}','barbell','olympic',ARRAY[$x$With a barbell on the floor close to the shins, take an overhand grip just outside the legs. Lower your hips with the weight focused on the heels, back straight, head facing forward, chest up, with your shoulders just in front of the bar. This will be your starting position.$x$,$x$Begin the first pull by driving through the heels, extending your knees. Your back angle should stay the same, and your arms should remain straight. Move the weight with control as you continue to above the knees.$x$,$x$Next comes the second pull, the main source of acceleration for the clean. As the bar approaches the mid-thigh position, begin extending through the hips. In a jumping motion, accelerate by extending the hips, knees, and ankles, using speed to move the bar upward. There should be no need to actively pull through the arms to accelerate the weight; at the end of the second pull, the body should be fully extended, leaning slightly back, with the arms still extended.$x$,$x$As full extension is achieved, transition into the third pull by aggressively shrugging and flexing the arms with the elbows up and out. At peak extension, aggressively pull yourself down, rotating your elbows under the bar as you do so.$x$,$x$Receive the bar with the feet split, aggressively moving one foot forward and one foot back. The bar should be racked onto the protracted shoulders, lightly touching the throat with the hands relaxed. Continue to descend to the bottom position, which will help in the recovery.$x$,$x$Immediately recover by driving through the heels, keeping the torso upright and elbows up. Bring the feet together as you stand up.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Split_Clean/0.jpg$x$),
($x$Split Jerk$x$,'quadriceps','{glutes,hamstrings,shoulders,triceps}','barbell','olympic',ARRAY[$x$Standing with the weight racked on the front of the shoulders, begin with the dip. With your feet directly under your hips, flex the knees without moving the hips backward.$x$,$x$Go down only slightly, and reverse direction as powerfully as possible. Drive through the heels create as much speed and force as possible, and be sure to move your head out of the way as the bar leaves the shoulders. At this moment as the feet leave the floor, the feet must be placed into the receiving position as quickly as possible.$x$,$x$In the brief moment the feet are not actively driving against the platform, the athlete's effort to push the bar up will drive them down. The feet should be moved to a split stance, one foot forward, one foot back, with the knees partially bent. Receive the bar with the arms locked out overhead.$x$,$x$Return to a standing position, bringing the feet together.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Split_Jerk/0.jpg$x$),
($x$Split Jump$x$,'quadriceps','{calves,glutes,hamstrings}','bodyweight','bodyweight',ARRAY[$x$Assume a lunge stance position with one foot forward with the knee bent, and the rear knee nearly touching the ground.$x$,$x$Ensure that the front knee is over the midline of the foot.$x$,$x$Extending through both legs, jump as high as possible, swinging your arms to gain lift.$x$,$x$As you jump, bring your feet together, and move them back to their initial positions as you land.$x$,$x$Absorb the impact by reverting back to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Split_Jump/0.jpg$x$),
($x$Split Snatch$x$,'hamstrings','{calves,forearms,glutes,back,quadriceps,shoulders,triceps}','barbell','olympic',ARRAY[$x$Begin with a loaded barbell on the floor. The bar should be close to or touching the shins, and a wide grip should be taken on the bar. The feet should be directly below the hips, with the feet turned out as needed. Lower the hips, with the chest up and the head looking forward. The shoulders should be just in front of the bar. This will be the starting position.$x$,$x$Begin the first pull by driving through the front of the heels, raising the bar from the ground. The back angle should stay the same until the bar passes the knees.$x$,$x$Transition into the second pull by extending through the hips knees and ankles, driving the bar up as quickly as possible. The bar should be close to the body. At peak extension, shrug the shoulders and allow the elbows to flex to the side.$x$,$x$As you move your feet into the receiving position, forcefully pull yourself below the bar as you elevate the bar overhead. The feet should move forcefully to a split position, one foot forward one foot back. Receive the bar with your body as low as possible and the arms fully extended overhead.$x$,$x$Keeping the bar aligned over the front of the heels, your head and chest up, drive through heels of the feet to move to a standing position, bringing your feet together.$x$,$x$Carefully return the weight to floor.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Split_Snatch/0.jpg$x$),
($x$Squat Jerk$x$,'quadriceps','{calves,glutes,hamstrings,shoulders,triceps}','barbell','strength',ARRAY[$x$Standing with the weight racked on the front of the shoulders, begin with the dip. With your feet directly under your hips, flex the knees without moving the hips backward. Go down only slightly, and reverse direction as powerfully as possible. Drive through the heels create as much speed and force as possible, and be sure to move your head out of the way as the bar leaves the shoulders.$x$,$x$At this moment as the feet leave the floor, the feet must be placed into the receiving position as quickly as possible. In the brief moment the feet are not actively driving against the platform, the athlete's effort to push the bar up will drive them down. The feet should move forcefully to just outside the hips, turned out as necessary. Receive the bar with your body in a full squat and the arms fully extended overhead.$x$,$x$Keeping the bar aligned over the front of the heels, your head and chest up, drive throught heels of the feet to move to a standing position. Carefully return the weight to floor.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Squat_Jerk/0.jpg$x$),
($x$Squat with Bands$x$,'quadriceps','{calves,glutes,hamstrings,back}','barbell','strength',ARRAY[$x$Set up the bands on the sleeves, secured to either band pegs, the rack, or dumbbells so that there is appropriate tension.$x$,$x$Begin by stepping under the bar and placing it across the back of the shoulders. Squeeze your shoulder blades together and rotate your elbows forward, attempting to bend the bar across your shoulders. Remove the bar from the rack, creating a tight arch in your lower back, and step back into position. Place your feet wide for more emphasis on the back, glutes, adductors, and hamstrings. Keep your head facing forward.$x$,$x$With your back, shoulders, and core tight, push your knees and butt out and you begin your descent. Sit back with your hips as much as possible. Ideally, your shins should be perpendicular to the ground. Lower bar position necessitates a greater torso lean to keep the bar over the heels. Continue until you break parallel, which is defined as the crease of the hip being in line with the top of the knee.$x$,$x$Keeping the weight on your heels and pushing your feet and knees out, drive upward as you lead the movement with your head. Continue upward, maintaining tightness head to toe, until you have returned to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Squat_with_Bands/0.jpg$x$),
($x$Squat with Chains$x$,'quadriceps','{calves,glutes,hamstrings,back}','barbell','strength',ARRAY[$x$To set up the chains, begin by looping the leader chain over the sleeves of the bar. The heavy chain should be attached using a snap hook. Adjust the length of the lead chain so that a few links are still on the floor at the top of the movement.$x$,$x$Begin by stepping under the bar and placing it across the back of the shoulders. Squeeze your shoulder blades together and rotate your elbows forward, attempting to bend the bar across your shoulders. Remove the bar from the rack, creating a tight arch in your lower back, and step back into position. Place your feet wide for more emphasis on the back, glutes, adductors, and hamstrings. Keep your head facing forward.$x$,$x$With your back, shoulders, and core tight, push your knees and butt out and you begin your descent. Sit back with your hips as much as possible. Ideally, your shins should be perpendicular to the ground. Lower bar position necessitates a greater torso lean to keep the bar over the heels. Continue until you break parallel, which is defined as the crease of the hip being in line with the top of the knee.$x$,$x$Keeping the weight on your heels and pushing your feet and knees out, drive upward as you lead the movement with your head. Continue upward, maintaining tightness head to toe, until you have returned to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Squat_with_Chains/0.jpg$x$),
($x$Squat with Plate Movers$x$,'quadriceps','{glutes,calves,hamstrings}','barbell','strength',ARRAY[$x$To begin, first set the bar on a rack to just below shoulder level. Position a weight plate on the ground a couple feet back from the rack. Once the bar is loaded, step under it and place the back of your shoulders across it.$x$,$x$Hold on to the bar with both hands and lift it off the rack by first pushing with your legs and at the same time straighten your torso.$x$,$x$Step away from the rack and adopt a wide stance with the toes slightly pointed out, with one foot on the weight plate. Keep your head up at all times. This will be your starting position.$x$,$x$Begin to slowly lower the bar by bending the knees and hips. Continue down until the angle between the upper leg and the calves becomes slightly less than 90-degrees.$x$,$x$Raise the bar as you exhale by pushing the floor with the heels of your feet as you extend the hips and knees.$x$,$x$At the top of the movement, side step, bringing your feet together on the opposite side of the plate.$x$,$x$Using your inside foot, push the weight plate, sliding it across the floor to where you were just standing.$x$,$x$Place your inside foot on the weight plate, adopting a wide stance for the next repetition.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Squat_with_Plate_Movers/0.jpg$x$),
($x$Stairmaster$x$,'quadriceps','{calves,glutes,hamstrings}','machine','cardio',ARRAY[$x$To begin, step onto the stairmaster and select the desired option from the menu. You can choose a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise.$x$,$x$Pump your legs up and down in an established rhythm, driving the pedals down but not all the way to the floor. It is recommended that you maintain your grip on the handles so that you don't fall. The handles can be used to monitor your heart rate to help you stay at an appropriate intensity.$x$,$x$Stairmasters offer convenience, cardiovascular benefits, and usually have less impact than running outside. They are typically much harder than other cardio equipment. A 150 lb person will typically burn over 300 calories in 30 minutes, compared to about 175 calories walking.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Stairmaster/0.jpg$x$),
($x$Standing Dumbbell Straight-Arm Front Delt Raise Above Head$x$,'shoulders','{}','dumbbell','strength',ARRAY[$x$Hold the dumbbells in front of your thighs, palms facing your thighs.$x$,$x$Keep your arms straight with a slight bend at the elbows but keep them locked. This will be your starting position.$x$,$x$Raise the dumbbells in a semicircular motion to arm's length overhead as you exhale.$x$,$x$Slowly return to the starting position using the same path as you inhale.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Standing_Dumbbell_Straight-Arm_Front_Delt_Raise_Above_Head/0.jpg$x$),
($x$Standing Front Barbell Raise Over Head$x$,'shoulders','{}','barbell','strength',ARRAY[$x$To begin, stand straight with a barbell in your hands. You should grip the bar with palms facing down and a closer than shoulder width grip apart from each other.$x$,$x$Your feet should be shoulder width apart from each other. Your elbows should be slightly bent. This is the starting position.$x$,$x$Lift the barbell up until it is directly over your head while exhaling. Make sure to keep your elbows slightly bent when performing each repetition.$x$,$x$Once you feel the contraction, begin to lower the barbell back down to the starting position as you inhale.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Standing_Front_Barbell_Raise_Over_Head/0.jpg$x$),
($x$Standing Long Jump$x$,'quadriceps','{calves,glutes,hamstrings}','bodyweight','bodyweight',ARRAY[$x$This drill is best done in sand or other soft landing surface. Ensure that you are able to measure distance. Stand in a partial squat stance with feet shoulder width apart.$x$,$x$Utilizing a big arm swing and a countermovement of the legs, jump forward as far as you can.$x$,$x$Attempt to land with your feet out in front you, reaching as far as possible with your legs.$x$,$x$Measure the distance from your landing point to the starting point and track results.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Standing_Long_Jump/0.jpg$x$),
($x$Standing Low-Pulley Deltoid Raise$x$,'shoulders','{forearms}','cable','strength',ARRAY[$x$Start by standing to the right side of a low pulley row. Use your left hand to come across the body and grab a single handle attached to the low pulley with a pronated grip (palms facing down). Rest your arm in front of you. Your right hand should grab the machine for better support and balance.$x$,$x$Make sure that your back is erect and your feet are shoulder width apart from each other. This is the starting position.$x$,$x$Begin to use the left hand and come across your body out until it is elevated to shoulder height while exhaling.$x$,$x$Feel the contraction at the top for a second and begin to slowly lower the handle back down to the original starting position while inhaling.$x$,$x$Repeat for the recommended amount of repetitions.$x$,$x$Switch arms and repeat the exercise.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Standing_Low-Pulley_Deltoid_Raise/0.jpg$x$),
($x$Standing Low-Pulley One-Arm Triceps Extension$x$,'triceps','{chest,shoulders}','cable','strength',ARRAY[$x$Grab a single handle with your left arm next to the low pulley machine. Turn away from the machine keeping the handle to the side of your body with your arm fully extended. Now use both hands to elevate the single handle directly above the head with the palm facing forward. Keep your upper arm completely vertical (perpendicular to the floor) and put your right hand on your left elbow to help keep it steady. This is the starting position.$x$,$x$Keeping your upper arms close to your head (elbows in) and perpendicular to the floor, lower the resistance in a semicircular motion behind your head until your forearms touch your biceps. Tip: The upper arms should remain stationary and only the forearms should move. Breathe in as you perform this step.$x$,$x$Go back to the starting position by using the triceps to raise the single handle. Breathe out as you perform this step.$x$,$x$Repeat for the recommended amount of repetitions.$x$,$x$Switch arms and repeat the exercise.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Standing_Low-Pulley_One-Arm_Triceps_Extension/0.jpg$x$),
($x$Standing Olympic Plate Hand Squeeze$x$,'forearms','{biceps}','other','strength',ARRAY[$x$To begin, stand straight while holding a weight plate by the ridge at arm's length in each hand using a neutral grip (palms facing in). You feet should be shoulder width apart from each other. This will be your starting position.$x$,$x$Lower the plates until the fingers are nearly extended but can still hold weights. Inhale as you lower the plates.$x$,$x$Now raise the plates back to the starting position as you exhale by closing your hands.$x$,$x$Repeat for the recommended amount of repetitions prescribed in your program.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Standing_Olympic_Plate_Hand_Squeeze/0.jpg$x$),
($x$Standing Palm-In One-Arm Dumbbell Press$x$,'shoulders','{triceps}','dumbbell','strength',ARRAY[$x$Start by having a dumbbell in one hand with your arm fully extended to the side using a neutral grip. Use your other arm to hold on to an incline bench to keep your balance.$x$,$x$Your feet should be shoulder width apart from each other. Now slowly lift the dumbbell up until you create a 90 degree angle with your arm. Note: Your forearm should be perpendicular to the floor. Continue to maintain a neutral grip throughout the entire exercise.$x$,$x$Slowly lift the dumbbell up until your arm is fully extended. This the starting position.$x$,$x$While inhaling lower the weight down until your arm is at a 90 degree angle again.$x$,$x$Feel the contraction for a second and then lift the weight back up towards the starting position while exhaling. Remember to hold on to the incline bench and keep your feet positioned to keep balance during the exercise.$x$,$x$Repeat for the recommended amount of repetitions.$x$,$x$Switch arms and repeat the exercise.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Standing_Palm-In_One-Arm_Dumbbell_Press/0.jpg$x$),
($x$Standing Palms-In Dumbbell Press$x$,'shoulders','{triceps}','dumbbell','strength',ARRAY[$x$Start by having a dumbbell in each hand with your arm fully extended to the side using a neutral grip. Your feet should be shoulder width apart from each other. Now slowly lift the dumbbells up until you create a 90 degree angle with your arms. Note: Your forearms should be perpendicular to the floor. This the starting position.$x$,$x$Continue to maintain a neutral grip throughout the entire exercise. Slowly lift the dumbbells up until your arms are fully extended.$x$,$x$While inhaling lower the weights down until your arm is at a 90 degree angle again.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Standing_Palms-In_Dumbbell_Press/0.jpg$x$),
($x$Standing Towel Triceps Extension$x$,'triceps','{}','bodyweight','bodyweight',ARRAY[$x$To begin, stand up with both arms fully extended above the head holding one end of a towel with both hands. Your elbows should be in and the arms perpendicular to the floor with the palms facing each other while your feet should be shoulder width apart from each other. This is the starting position.$x$,$x$Now communicate with your partner so that he/she can grip the other side of the towel to apply resistance. Keeping your upper arms close to your head (elbows in) and perpendicular to the floor, lower the resistance in a semicircular motion behind your head until your forearms touch your biceps. Tip: The upper arms should remain stationary and only the forearms should move. Breathe in as you perform this step.$x$,$x$Go back to the starting position by using the triceps to raise the towel. Breathe out as you perform this step.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Standing_Towel_Triceps_Extension/0.jpg$x$),
($x$Standing Two-Arm Overhead Throw$x$,'shoulders','{chest,back}','other','strength',ARRAY[$x$Stand with your feet shoulder width apart holding a medicine ball in both hands. To begin, reach the medicine ball deep behind your head as you bend the knees slightly and lean back.$x$,$x$Violently throw the ball forward, flexing at the hip and using your whole body to complete the movement.$x$,$x$The medicine ball can be thrown to a partner or to a wall, receiving it as it bounces back.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Standing_Two-Arm_Overhead_Throw/0.jpg$x$),
($x$Star Jump$x$,'quadriceps','{calves,glutes,hamstrings,shoulders}','bodyweight','bodyweight',ARRAY[$x$Begin in a relaxed stance with your feet shoulder width apart and hold your arms close to the body.$x$,$x$To initiate the move, squat down halfway and explode back up as high as possible. Fully extend your entire body, spreading your legs and arms away from the body.$x$,$x$As you land, bring your limbs back in and absorb your impact through the legs.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Star_Jump/0.jpg$x$)
) as v(name,mg,sm,eq,et,ins,img)
where not exists (select 1 from exercises e where lower(e.name)=lower(v.name));

insert into exercises (name,muscle_group,secondary_muscles,equipment,exercise_type,instructions,image_url,is_custom,user_id)
select v.name,v.mg::muscle_group,v.sm::muscle_group[],v.eq::equipment_type,v.et::exercise_type,v.ins::text[],v.img,false,null
from (values
($x$Step-up with Knee Raise$x$,'glutes','{hamstrings,quadriceps}','bodyweight','bodyweight',ARRAY[$x$Stand facing a box or bench of an appropriate height with your feet together. This will be your starting position.$x$,$x$Begin the movement by stepping up, putting your left foot on the top of the bench. Extend through the hip and knee of your front leg to stand up on the box. As you stand on the box with your left leg, flex your right knee and hip, bringing your knee as high as you can.$x$,$x$Reverse this motion to step down off the box, and then repeat the sequence on the opposite leg.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Step-up_with_Knee_Raise/0.jpg$x$),
($x$Step Mill$x$,'quadriceps','{calves,glutes,hamstrings}','machine','cardio',ARRAY[$x$To begin, step onto the stepmill and select the desired option from the menu. You can choose a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. Use caution so that you don't trip as you climb the stairs. It is recommended that you maintain your grip on the handles so that you don't fall.$x$,$x$Stepmills offer convenience, cardiovascular benefits, and usually have less impact than running outside while offering a similar rate of calories burned. They are typically much harder than other cardio equipment. A 150 lb person will typically burn over 300 calories in 30 minutes, compared to about 175 calories walking.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Step_Mill/0.jpg$x$),
($x$Stiff Leg Barbell Good Morning$x$,'back','{glutes,hamstrings}','barbell','strength',ARRAY[$x$This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.$x$,$x$Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.$x$,$x$Step away from the rack and position your legs using a shoulder width medium stance. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. This will be your starting position.$x$,$x$Keeping your legs stationary, move your torso forward by bending at the hips while inhaling. Lower your torso until it is parallel with the floor.$x$,$x$Begin to raise the bar as you exhale by elevating your torso back to the starting position.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Stiff_Leg_Barbell_Good_Morning/0.jpg$x$),
($x$Straight-Arm Dumbbell Pullover$x$,'chest','{back,shoulders,triceps}','dumbbell','strength',ARRAY[$x$Place a dumbbell standing up on a flat bench.$x$,$x$Ensuring that the dumbbell stays securely placed at the top of the bench, lie perpendicular to the bench (torso across it as in forming a cross) with only your shoulders lying on the surface. Hips should be below the bench and legs bent with feet firmly on the floor. The head will be off the bench as well.$x$,$x$Grasp the dumbbell with both hands and hold it straight over your chest at arms length. Both palms should be pressing against the underside one of the sides of the dumbbell. This will be your starting position.
Caution: Always ensure that the dumbbell used for this exercise is secure. Using a dumbbell with loose plates can result in the dumbbell falling apart and falling on your face.$x$,$x$While keeping your arms straight, lower the weight slowly in an arc behind your head while breathing in until you feel a stretch on the chest.$x$,$x$At that point, bring the dumbbell back to the starting position using the arc through which the weight was lowered and exhale as you perform this movement.$x$,$x$Hold the weight on the initial position for a second and repeat the motion for the prescribed number of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Straight-Arm_Dumbbell_Pullover/0.jpg$x$),
($x$Straight Bar Bench Mid Rows$x$,'back','{biceps}','barbell','strength',ARRAY[$x$Place a loaded barbell on the end of a bench. Standing on the bench behind the bar, take a medium, pronated grip. Stand with your hips back and chest up, maintaining a neutral spine. This will be your starting position.$x$,$x$Row the bar to your torso by retracting the shoulder blades and flexing the elbows. Use a controlled movement with no jerking.$x$,$x$After a brief pause, slowly return the bar to the starting position, ensuring to go all the way down.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Straight_Bar_Bench_Mid_Rows/0.jpg$x$),
($x$Straight Raises on Incline Bench$x$,'shoulders','{back}','barbell','strength',ARRAY[$x$Place a bar on the ground behind the head of an incline bench.$x$,$x$Lay on the bench face down. With a pronated grip, pick the barbell up from the floor, keeping your arms straight. Allow the bar to hang straight down. This will be your starting position.$x$,$x$To begin, raise the barbell out in front of your head while keeping your arms extended.$x$,$x$Return to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Straight_Raises_on_Incline_Bench/0.jpg$x$),
($x$Stride Jump Crossover$x$,'quadriceps','{glutes,calves,hamstrings}','other','strength',ARRAY[$x$Stand to the side of a box with your inside foot on top of it, close to the edge.$x$,$x$Begin by swinging the arms upward as you push through the top leg, jumping upward as high as possible. Attempt to drive the opposite knee upward.$x$,$x$Land in the opposite position that you started, on the opposite side of the box. The foot that was initially on the box will now be on the ground, with the opposite foot now on the box.$x$,$x$Repeat the movement, crossing back over to the other side.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Stride_Jump_Crossover/0.jpg$x$),
($x$Sumo Deadlift with Bands$x$,'hamstrings','{quadriceps,forearms,glutes,back}','barbell','strength',ARRAY[$x$To deadlift with short bands, simply loop them over the bar before you start, and step into them to set up. Ensure that they under the back half of your foot, directly where you are driving into the floor.$x$,$x$Begin with a bar loaded on the ground. Approach the bar so that the bar intersects the middle of the feet. The feet should be set very wide, near the collars. Bend at the hips to grip the bar. The arms should be directly below the shoulders, inside the legs, and you can use a pronated grip, a mixed grip, or hook grip.$x$,$x$Take a breath, and then lower your hips, looking forward with your head with your chest up. Drive through the floor, spreading your feet apart, with your weight on the back half of your feet. Extend through the hips and knees.$x$,$x$As the bar passes through the knees, lean back and drive the hips into the bar, pulling your shoulder blades together.$x$,$x$Return the weight to the ground by bending at the hips and controlling the weight on the way down.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Sumo_Deadlift_with_Bands/0.jpg$x$),
($x$Sumo Deadlift with Chains$x$,'hamstrings','{glutes,quadriceps,forearms,back}','barbell','strength',ARRAY[$x$You can attach the chains to the sleeves of the bar, or just drape the middle over the bar so there is a greater weight increase as you lift. Attempt to keep the ends of the chains away from the plates so you don't hit them when you lower the weight.$x$,$x$Begin with a bar loaded on the ground. Approach the bar so that the bar intersects the middle of the feet. The feet should be set very wide, near the collars. Bend at the hips to grip the bar. The arms should be directly below the shoulders, inside the legs, and you can use a pronated grip, a mixed grip, or hook grip. Relax the shoulders, which in effect lengthens your arms.$x$,$x$Take a breath, and then lower your hips, looking forward with your head with your chest up. Drive through the floor, spreading your feet apart, with your weight on the back half of your feet. Extend through the hips and knees.$x$,$x$As the bar passes through the knees, lean back and drive the hips into the bar, pulling your shoulder blades together.$x$,$x$Return the weight to the ground by bending at the hips and controlling the weight on the way down.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Sumo_Deadlift_with_Chains/0.jpg$x$),
($x$Supine Chest Throw$x$,'triceps','{chest,shoulders}','other','strength',ARRAY[$x$This drill is great for chest passes when you lack a partner or a wall of sufficient strength. Lay on the ground on your back with your knees bent.$x$,$x$Begin with the ball on your chest, held with both hands on the bottom.$x$,$x$Explode up, extending through the elbow to throw the ball directly above you as high as possible.$x$,$x$Catch the ball with both hands as it comes down.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Supine_Chest_Throw/0.jpg$x$),
($x$Supine One-Arm Overhead Throw$x$,'core','{chest,back,shoulders}','other','strength',ARRAY[$x$Lay on the ground on your back with your knees bent. Hold the ball with one hand, extending the arm fully behind your head. This will be your starting position.$x$,$x$Initiate the movement at the shoulder, throwing the ball directly forward of you as you sit up, attempting to go for maximum distance.$x$,$x$The ball can be thrown to a partner or bounced off of a wall.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Supine_One-Arm_Overhead_Throw/0.jpg$x$),
($x$Supine Two-Arm Overhead Throw$x$,'core','{chest,back,shoulders}','other','strength',ARRAY[$x$Lay on the ground on your back with your knees bent.$x$,$x$Hold the ball with both hands, extending the arms fully behind your head. This will be your starting position.$x$,$x$Initiate the movement at the shoulder, throwing the ball directly forward of you as you sit up, attempting to go for maximum distance.$x$,$x$The ball can be thrown to a partner or bounced off of a wall.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Supine_Two-Arm_Overhead_Throw/0.jpg$x$),
($x$Suspended Fallout$x$,'core','{chest,back,shoulders}','other','strength',ARRAY[$x$Adjust the straps so the handles are at an appropriate height, below waist level.$x$,$x$Begin standing and grasping the handles. Lean into the straps, moving to an incline push-up position. This will be your starting position.$x$,$x$Keeping your arms straight, lean further into the suspension straps, bringing your body closer to the ground, allowing your shoulders to extend, raising your arms up and over your head.$x$,$x$Maintain a neutral spine and keep the rest of your body straight, your shoulders being the only joints allowed to move.$x$,$x$Pause during the peak contraction, and then return to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Suspended_Fallout/0.jpg$x$),
($x$Suspended Push-Up$x$,'chest','{shoulders,triceps}','other','strength',ARRAY[$x$Anchor your suspension straps securely to the top of a rack or other object.$x$,$x$Leaning into the straps, take a handle in each hand and move into a push-up plank position. You should be as close to parallel to the ground as you can manage with your arms fully extended, maintaining good posture.$x$,$x$Maintaining a straight, rigid torso, descend slowly by allowing the elbows to flex.$x$,$x$Continue until your elbows break 90 degrees, pausing before you extend to return to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Suspended_Push-Up/0.jpg$x$),
($x$Suspended Row$x$,'back','{biceps}','other','strength',ARRAY[$x$Suspend your straps at around chest height. Take a handle in each hand and lean back. Keep your body erect and your head and chest up. Your arms should be fully extended. This will be your starting position.$x$,$x$Begin by flexing the elbow to initiate the movement. Protract your shoulder blades as you do so.$x$,$x$At the completion of the motion pause, and then return to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Suspended_Row/0.jpg$x$),
($x$Svend Press$x$,'chest','{forearms,shoulders,triceps}','other','strength',ARRAY[$x$Begin in a standing position.$x$,$x$Press two lightweight plates together with your hands. Hold the plates together close to your chest to create an isometric contraction in your chest muscles. Your fingers should be pointed forward. This is your starting position.$x$,$x$Squeeze the plates between your palms and extend your arms directly out in front of you in a controlled motion.$x$,$x$Pause at the top of the motion, and then slowly return to the starting position.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Svend_Press/0.jpg$x$),
($x$Thigh Abductor$x$,'glutes','{}','machine','strength',ARRAY[$x$To begin, sit down on the abductor machine and select a weight you are comfortable with. When your legs are positioned properly, grip the handles on each side. Your entire upper body (from the waist up) should be stationary. This is the starting position.$x$,$x$Slowly press against the machine with your legs to move them away from each other while exhaling.$x$,$x$Feel the contraction for a second and begin to move your legs back to the starting position while breathing in. Note: Remember to keep your upper body stationary to prevent any injuries from occurring.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Thigh_Abductor/0.jpg$x$),
($x$Thigh Adductor$x$,'quadriceps','{glutes,hamstrings}','machine','strength',ARRAY[$x$To begin, sit down on the adductor machine and select a weight you are comfortable with. When your legs are positioned properly on the leg pads of the machine, grip the handles on each side. Your entire upper body (from the waist up) should be stationary. This is the starting position.$x$,$x$Slowly press against the machine with your legs to move them towards each other while exhaling.$x$,$x$Feel the contraction for a second and begin to move your legs back to the starting position while breathing in. Note: Remember to keep your upper body stationary and avoid fast jerking motions in order to prevent any injuries from occurring.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Thigh_Adductor/0.jpg$x$),
($x$Trail Running/Walking$x$,'quadriceps','{calves,glutes,hamstrings}','other','cardio',ARRAY[$x$Running or hiking on trails will get the blood pumping and heart beating almost immediately. Make sure you have good shoes. While you use the muscles in your calves and buttocks to pull yourself up a hill, the knees, joints and ankles absorb the bulk of the pounding coming back down. Take smaller steps as you walk downhill, keep your knees bent to reduce the impact and slow down to avoid falling.$x$,$x$A 150 lb person can burn over 200 calories for 30 minutes walking uphill, compared to 175 on a flat surface. If running the trail, a 150 lb person can burn well over 500 calories in 30 minutes.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Trail_Running_Walking/0.jpg$x$),
($x$Tuck Crunch$x$,'core','{}','bodyweight','bodyweight',ARRAY[$x$To begin, lie down on the floor or an exercise mat with your back pressed against the floor. Your arms should be lying across your sides with the palms facing down.$x$,$x$Your legs should be crossed by wrapping one ankle around the other. Slowly elevate your legs up in the air until your thighs are perpendicular to the floor with a slight bend at the knees. Note: Your knees and toes should be parallel to the floor as opposed to the thighs.$x$,$x$Move your arms from the floor and cross them so they are resting on your chest. This is the starting position.$x$,$x$While keeping your lower back pressed against the floor, slowly lift your torso. Remember to exhale while perform this part of the exercise.$x$,$x$Slowly begin to lower your torso back down to the starting position while inhaling.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Tuck_Crunch/0.jpg$x$),
($x$Two-Arm Kettlebell Clean$x$,'shoulders','{calves,glutes,hamstrings,back}','kettlebell','strength',ARRAY[$x$Place two kettlebells between your feet. To get in the starting position, push your butt back and look straight ahead.$x$,$x$Clean the kettlebells to your shoulders by extending through the legs and hips as you raise the kettlebells towards your shoulders. Rotate your wrists as you do so.$x$,$x$Lower the kettlebells back to the starting position and repeat.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Two-Arm_Kettlebell_Clean/0.jpg$x$),
($x$Two-Arm Kettlebell Jerk$x$,'shoulders','{calves,quadriceps,triceps}','kettlebell','strength',ARRAY[$x$Clean two kettlebells to your shoulders. Clean the kettlebells to your shoulders by extending through the legs and hips as you swing the kettlebells towards your shoulders. Rotate your wrists as you do so, so that the palms face forward. Squat down a few inches and reverse the motion rapidly driving both kettlebells overhead. Immediately after the initial push, squat down again and get under the kettlebells. Once the kettlebells are locked out, stand upright to complete the exercise.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Two-Arm_Kettlebell_Jerk/0.jpg$x$),
($x$Two-Arm Kettlebell Row$x$,'back','{biceps}','kettlebell','strength',ARRAY[$x$Place two kettlebells in front of your feet. Bend your knees slightly and then push your butt out as much as possible as you bend over to get in the starting position.$x$,$x$Grab both kettlebells and pull them to your stomach, retracting your shoulder blades and flexing the elbows. Keep your back straight. Lower and repeat.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Two-Arm_Kettlebell_Row/0.jpg$x$),
($x$Underhand Cable Pulldowns$x$,'back','{biceps,shoulders}','cable','strength',ARRAY[$x$Sit down on a pull-down machine with a wide bar attached to the top pulley. Adjust the knee pad of the machine to fit your height. These pads will prevent your body from being raised by the resistance attached to the bar.$x$,$x$Grab the pull-down bar with the palms facing your torso (a supinated grip). Make sure that the hands are placed closer than the shoulder width.$x$,$x$As you have both arms extended in front of you holding the bar at the chosen grip width, bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.$x$,$x$As you breathe out, pull the bar down until it touches your upper chest by drawing the shoulders and the upper arms down and back. Tip: Concentrate on squeezing the back muscles once you reach the fully contracted position and keep the elbows close to your body. The upper torso should remain stationary as your bring the bar to you and only the arms should move. The forearms should do no other work other than hold the bar.$x$,$x$After a second on the contracted position, while breathing in, slowly bring the bar back to the starting position when your arms are fully extended and the lats are fully stretched.$x$,$x$Repeat this motion for the prescribed amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Underhand_Cable_Pulldowns/0.jpg$x$),
($x$V-Bar Pulldown$x$,'back','{biceps,shoulders}','cable','strength',ARRAY[$x$Sit down on a pull-down machine with a V-Bar attached to the top pulley.$x$,$x$Adjust the knee pad of the machine to fit your height. These pads will prevent your body from being raised by the resistance attached to the bar.$x$,$x$Grab the V-bar with the palms facing each other (a neutral grip). Stick your chest out and lean yourself back slightly (around 30-degrees) in order to better engage the lats. This will be your starting position.$x$,$x$Using your lats, pull the bar down as you squeeze your shoulder blades. Continue until your chest nearly touches the V-bar. Exhale as you execute this motion. Tip: Keep the torso stationary throughout the movement.$x$,$x$After a second hold on the contracted position, slowly bring the bar back to the starting position as you breathe in.$x$,$x$Repeat for the prescribed number of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/V-Bar_Pulldown/0.jpg$x$),
($x$V-Bar Pullup$x$,'back','{biceps,shoulders}','bodyweight','bodyweight',ARRAY[$x$Start by placing the middle of the V-bar in the middle of the pull-up bar (assuming that the pull-up station you are using does not have neutral grip handles). The V-Bar handles will be facing down so that you can hang from the pull-up bar through the use of the handles.$x$,$x$Once you securely place the V-bar, take a hold of the bar from each side and hang from it. Stick your chest out and lean yourself back slightly in order to better engage the lats. This will be your starting position.$x$,$x$Using your lats, pull your torso up while leaning your head back slightly so that you do not hit yourself with the chin-up bar. Continue until your chest nearly touches the V-bar. Exhale as you execute this motion.$x$,$x$After a second hold on the contracted position, slowly lower your body back to the starting position as you breathe in.$x$,$x$Repeat for the prescribed number of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/V-Bar_Pullup/0.jpg$x$),
($x$Vertical Swing$x$,'hamstrings','{glutes,quadriceps,shoulders}','dumbbell','strength',ARRAY[$x$Allow the dumbbell to hang at arms length between your legs, holding it with both hands. Keep your back straight and your head up.$x$,$x$Swing the dumbbell between your legs, flexing at the hips and bending the knees slightly.$x$,$x$Powerfully reverse the motion by extending at the hips, knees, and ankles to propel yourself upward, swinging the dumbell over your head.$x$,$x$As you land, absorb the impact through your legs and draw the dumbbell to your torso before the next repetition.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Vertical_Swing/0.jpg$x$),
($x$Walking, Treadmill$x$,'quadriceps','{calves,glutes,hamstrings}','machine','cardio',ARRAY[$x$To begin, step onto the treadmill and select the desired option from the menu. Most treadmills have a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. Elevation can be adjusted to change the intensity of the workout.$x$,$x$Treadmills offer convenience, cardiovascular benefits, and usually have less impact than walking outside. When walking, you should move at a moderate to fast pace, not a leisurely one. Being an activity of lower intensity, walking doesn't burn as many calories as some other activities, but still provides great benefit. A 150 lb person will burn about 175 calories walking 4 miles per hour for 30 minutes, compared to 450 calories running twice as fast. Maintain proper posture as you walk, and only hold onto the handles when necessary, such as when dismounting or checking your heart rate.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Walking_Treadmill/0.jpg$x$),
($x$Weighted Ball Side Bend$x$,'core','{}','other','strength',ARRAY[$x$To begin, lie down on an exercise ball with your left side of the torso (waist, hips and shoulder) pressed against the ball.$x$,$x$Your feet should be on the floor while your legs are crossed and hanging from the ball. Hold a weighted plate with your right hand directly to the right side of your head. Tip: Make sure the smooth side of the plate is resting against your head.$x$,$x$Place your left arm across your torso so that your palm is on your obliques. There should be a right angle between your left forearm and upper arm. This is the starting position.$x$,$x$Raise the side of your torso up by laterally flexing at the waist while exhaling.$x$,$x$Hold the contraction for a second and slowly lower yourself back down to the starting position while inhaling.$x$,$x$Repeat for the recommended amount of repetitions.$x$,$x$Switch sides and repeat the exercise.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Weighted_Ball_Side_Bend/0.jpg$x$),
($x$Weighted Jump Squat$x$,'quadriceps','{calves,glutes,hamstrings,back}','barbell','strength',ARRAY[$x$Position a lightly loaded barbell across the back of your shoulders. You could also use a weighted vest, sandbag, or other type of resistance for this exercise.$x$,$x$The weight should be light enough that it doesn't slow you down significantly. Your feet should be just outside of shoulder width with your head and chest up. This will be your starting position.$x$,$x$Using a countermovement, squat partially down and immediately reverse your direction to explode off of the ground, extending through your hips, knees, and ankles. Maintain good posture throughout the jump.$x$,$x$As you return to the ground, absorb the impact through your legs.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Weighted_Jump_Squat/0.jpg$x$),
($x$Wide-Grip Decline Barbell Pullover$x$,'chest','{shoulders,triceps}','barbell','strength',ARRAY[$x$Lie down on a decline bench with both legs securely locked in position. Reach for the barbell behind the head using a pronated grip (palms facing out). Make sure to grab the barbell wider than shoulder width apart for this exercise. Slowly lift the barbell up from the floor by using your arms.$x$,$x$When positioned properly, your arms should be fully extended and perpendicular to the floor. This is the starting position.$x$,$x$Begin by moving the barbell back down in a semicircular motion as if you were going to place it on the floor, but instead, stop when the arms are parallel to the floor. Tip: Keep the arms fully extended at all times. The movement should only happen at the shoulder joint. Inhale as you perform this portion of the movement.$x$,$x$Now bring the barbell up while exhaling until you are back at the starting position. Remember to keep full control of the barbell at all times.$x$,$x$Repeat the movement for the prescribed amount of repetitions of your training program.$x$,$x$When finished with your set, slowly lower the barbell back down until it is level with your head and release it.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Wide-Grip_Decline_Barbell_Pullover/0.jpg$x$),
($x$Wide-Grip Pulldown Behind The Neck$x$,'back','{biceps,shoulders}','cable','strength',ARRAY[$x$Sit down on a pull-down machine with a wide bar attached to the top pulley. Make sure that you adjust the knee pad of the machine to fit your height. These pads will prevent your body from being raised by the resistance attached to the bar.$x$,$x$Grab the bar with the palms facing forward using the prescribed grip. Note on grips: For a wide grip, your hands need to be spaced out at a distance wider than your shoulder width. For a medium grip, your hands need to be spaced out at a distance equal to your shoulder width and for a close grip at a distance smaller than your shoulder width.$x$,$x$As you have both arms extended in front of you holding the bar at the chosen grip width, bring your torso and head forward. Think of an imaginary line from the center of the bar down to the back of your neck. This is your starting position.$x$,$x$As you breathe out, bring the bar down until it touches the back of your neck by drawing the shoulders and the upper arms down and back. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary and only the arms should move. The forearms should do no other work except for holding the bar; therefore do not try to pull down the bar using the forearms.$x$,$x$After a second on the contracted position squeezing your shoulder blades together, slowly raise the bar back to the starting position when your arms are fully extended and the lats are fully stretched. Inhale during this portion of the movement.$x$,$x$Repeat this motion for the prescribed amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Wide-Grip_Pulldown_Behind_The_Neck/0.jpg$x$),
($x$Wide-Grip Rear Pull-Up$x$,'back','{biceps,shoulders}','bodyweight','bodyweight',ARRAY[$x$Grab the pull-up bar with the palms facing forward using a wide grip.$x$,$x$As you have both arms extended in front of you holding the bar, bring your torso forward and head so that there is an imaginary line from the pull-up bar to the back of your neck. This is your starting position.$x$,$x$Pull your torso up until the bar is near the back of your neck. To do this, draw the shoulders and upper arms down and back while slightly leaning your head forward. Exhale as you perform this portion of the movement. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.$x$,$x$After a second on the contracted position, start to inhale and slowly lower your torso back to the starting position when your arms are fully extended and the lats are fully stretched.$x$,$x$Repeat this motion for the prescribed amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Wide-Grip_Rear_Pull-Up/0.jpg$x$),
($x$Wide Stance Stiff Legs$x$,'hamstrings','{quadriceps,glutes,back}','barbell','olympic',ARRAY[$x$Begin with a barbell loaded on the floor. Adopt a wide stance, and then bend at the hips to grab the bar. Your hips should be as far back as possible, and your legs nearly straight. Keep your back straight, and your head and chest up. This will be your starting position.$x$,$x$Begin the movement be engaging the hips, driving them forward as you allow the arms to hang straight. Continue until you are standing straight up, and then slowly return the weight to the starting position. For successive reps, the weight need not touch the floor.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Wide_Stance_Stiff_Legs/0.jpg$x$),
($x$Wind Sprints$x$,'core','{}','bodyweight','bodyweight',ARRAY[$x$Hang from a pull-up bar using a pronated grip. Your arms and legs should be extended. This will be your starting position.$x$,$x$Begin by quickly raising one knee as high as you can. Do not swing your body or your legs. 3$x$,$x$Immediately reverse the motion, returning that leg to the starting position. Simultaneously raise the opposite knee as high as possible.$x$,$x$Continue alternating between legs until the set is complete.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Wind_Sprints/0.jpg$x$),
($x$Wrist Rotations with Straight Bar$x$,'forearms','{}','barbell','strength',ARRAY[$x$Hold a barbell with both hands and your palms facing down; hands spaced about shoulder width. This will be your starting position.$x$,$x$Alternating between each of your hands, perform the movement by extending the wrist as though you were rolling up a newspaper. Continue alternating back and forth until failure.$x$,$x$Reverse the motion by flexing the wrist, rolling the opposite direction. Continue the alternating motion until failure.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Wrist_Rotations_with_Straight_Bar/0.jpg$x$),
($x$Yoke Walk$x$,'quadriceps','{core,glutes,calves,hamstrings,back}','other','strength',ARRAY[$x$The yoke is usually done with a yoke apparatus, but is sometimes seen with refrigerators or other heavy objects.$x$,$x$Begin by racking the apparatus across the back of the shoulders. With your head looking forward and back arched, lift the yoke by driving through the heels.$x$,$x$Begin walking as quickly as possible using short, quick steps. You may hold the side posts of the yoke to help steady it and hold it in position. Continue for the given distance as fast as possible, usually 75-100 feet.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Yoke_Walk/0.jpg$x$),
($x$Zercher Squats$x$,'quadriceps','{calves,glutes,hamstrings}','barbell','strength',ARRAY[$x$This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. The correct height should be anywhere above the waist but below the chest. Once the correct height is chosen and the bar is loaded, lock your hands together and place the bar on top of your arms in between the forearm and upper arm.$x$,$x$Lift the bar up so that it is resting on top of your forearms. If you are holding the bar properly, it should look as if you have your arms crossed but with a bar running across them.$x$,$x$Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. This will be your starting position. (Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances discussed in the foot stances section).$x$,$x$Begin to lower the bar by bending the knees as you maintain a straight posture with the head up. Continue down until the angle between the upper leg and the calves becomes slightly less than 90-degrees (which is the point in which the upper legs are below parallel to the floor). Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.$x$,$x$Begin to raise the bar as you exhale by pushing the floor with the ball of your foot mainly as you straighten the legs again and go back to the starting position.$x$,$x$Repeat for the recommended amount of repetitions.$x$],$x$https://cdn.jsdelivr.net/gh/yuhonas/free-exercise-db@main/exercises/Zercher_Squats/0.jpg$x$)
) as v(name,mg,sm,eq,et,ins,img)
where not exists (select 1 from exercises e where lower(e.name)=lower(v.name));
